CREATE TABLE `truyen` (
  `Id_truyen` int(11) NOT NULL,
  `Ten` varchar(255) DEFAULT NULL,
  `TacGia` varchar(255) DEFAULT NULL,
  `TheLoai` varchar(255) DEFAULT NULL,
  `TongSoChuong` int(11) DEFAULT NULL,
  `TrangThai` varchar(50) DEFAULT NULL,
  `GioiThieu` text DEFAULT NULL,
  `NgayTao` datetime DEFAULT current_timestamp(),
  `AnhBia` varchar(255) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `truyen`
--

INSERT INTO `truyen` (`Id_truyen`, `Ten`, `TacGia`, `TheLoai`, `TongSoChuong`, `TrangThai`, `GioiThieu`, `NgayTao`, `AnhBia`) VALUES
(1, 'Kiếm Lai', 'Phong Hỏa Hí Chư Hầu', 'Huyền Huyễn, Tiên Hiệp, Kiếm Hiệp', NULL, 'Đang ra', 'Thiên địa mênh mông, vạn vật tồn tại. Ta - Trần Bình An - chỉ với một kiếm, phá thành, chắn sông, hái sao, lấp biển, hàng yêu, diệt ma, phong thần, khai thiên, làm nên tất cả! ', '2026-03-11 00:00:00', 'kiemlai.jpg'),
(2, 'Mao Sơn Tróc Quỷ Nhân', 'Thanh Tử', 'Linh Dị, Đô Thị, Huyền Huyễn', 3665, 'Hoàn thành', 'Diệp Thiếu Dương vốn là một Mao Sơn tróc quỷ nhân, dũng cảm tiến vào đô thị, gặp người đấu người, gặp quỷ đấu quỷ, gặp yêu đấu yêu, gặp hồ đấu hồ...<br><br>Tương tây Thi vương, Tà Thần bất tử, điệp tiên hung linh, tứ phương quỷ khấu.<br><br>Nữ minh tinh nuôi tiểu quỷ, công chúa hoàng thất hút máu, nữ giám đốc là hồ yêu,...<br><br>Thi triển Mao Sơn thần thuật, đánh lui tất cả!', '2026-03-11 00:00:00', 'maosontrocquynhan.jpg'),
(3, 'Lạn Kha Kỳ Duyên', 'Chân Phí Sự', 'Tiên Hiệp, Dị Giới, Huyền Huyễn, Cổ Đại', 1070, 'Hoàn thành', 'Lạn Kha ngồi bên ván cờ lá rụng, tại giữa trúc lâm không người đánh cờ.<br>Hưng sở trí Thiên Nguyên một cờ, lại xoay người sông núi thênh thang.<br><br>...<br><br>Thức giấc sau cơn mơ, Kế Duyên trở thành một tên hành khất gần như mù mắt trong một cái miếu sơn thần cũ nát.<br><br>Thực lực không đủ thì dùng miệng lưỡi để kiếm ăn, chân nhân dùng kiếm, lừa đảo dùng mồm, Kế Duyên nhờ vào bản thân kiếm sống tại cái thế giới đáng sợ này.<br><br>...<br><br><b>Du Lạn Kha Sơn</b><br>Giản lai huề trượng thượng toàn ngoan,<br>Tứ nhập vân tiêu nhãn giới khoan.<br>Phong động viễn lâm thu sắt sắt,<br>Giản thông u cốc thuỷ sàn sàn.<br>Bình không tử lạc tiên kì tĩnh,<br>Vật hoán tinh di Phật cốt hàn.<br>Duyệt thế du du kim kỷ hử,<br>Không tồn di tích hậu nhân khan.<br><br><b>Review Truyện:</b><br><br>Tiên hiệp cổ điển rất khó viết. Một bộ tiên hiệp hay là một bộ truyện phải được viết sao cho thật dễ hiểu, thật thú vị, thật tiêu sái cũng như phải có cái hồn của tiên hiệp. Chỉ một điều kiện thôi đã khó, chứ đừng nói phải có đầy đủ các điều kiện trên. Có lẽ vì vậy mà tiên hiệp bắt đầu suy tàn.<br><br>Kể từ sau <a target=\"_blank\" rel=\"nofollow\" href=\"https://truyenfull.vn/hoang-dinh/\">Hoàng Đình</a>, cũng thật lâu rồi mình mới thấy lại một bộ tiên hiệp cổ điển thuần túy như Lạn Kha Kỳ Duyên. Có yếu tố lãng mạn, thoải mái tiêu sái của tiên hiệp cổ điển trường phái phi thăng, chi tiết truyện vừa xuất sắc lại dân dã. Có yếu tố truyền thuyết phàm tục mang lại cảm giác của những câu chuyện thần thoại cổ xưa. Nam chính ở trong trò chơi hồng trần này, tuy rằng pháp lực tu vi không cao, nhưng cách xử sự làm người lại có trước có sau, thần bí khó lường, có ý cảnh, có tâm cảnh, thực sự đã mang lại cảm giác thần bí của tiên nhân. Đoạn mở đầu, khi nam chính nghèo túng cũng sợ chết như người thường, lời ăn tiếng nói cũng hơi tùy tiện. Trong truyện mỗi người đều rất lý tưởng, không dây dưa lợi ích quá nhiều, cũng không có quá nhiều cơ quan tính toán, nhiều khi đọc mà không nhịn được cười.<br><br>Trước mắt thì thấy đây là một thể loại truyền kỳ du ký cổ đại, có giang hồ, có tu sĩ, có tiên thần, có võ lâm cao thủ, có người phàm. Bàn tay vàng rất có ý tứ, tựa như thay đổi vận mệnh nhân vật. Mỗi khi nam chính thúc đẩy vận mệnh một người, hoặc là dạy người hướng thiện, trên ván cờ sẽ ngưng tụ ra một quân cờ mới. Người đọc bị cuốn hút dần bởi những câu chuyện xung quanh Kế Duyên, muốn biết rốt cuộc quân cờ mà nam chính đã gieo sẽ trở thành những gì.', '2026-03-11 00:00:00', 'lankhakyduyen.jpg'),
(4, 'Ta Thân Ái Pháp Y Tiểu Thư', 'Tửu Noãn Xuân Thâm', 'Trinh Thám, Nữ Cường, Bách Hợp', NULL, 'Đang ra', 'Trong \"Nỗi bi thảm của thế giới\", Victor Hugo viết rằng<br><br>\"Nhân tâm, vừa có thể tỏa ra muôn vàn quang minh, đồng thời cũng dựng lên vô tận hắc ám.<br><br>Ánh sáng cùng bóng tối, đan xen nhau, tranh đấu, tàn sát nhau.<br><br>Cũng là nguyên do mà ta lưu luyến nhân gian, đồng thời dâng lên niềm tiếc hận\".<br><br>Tra án, đoán tâm, thăm dò.<br><br>\"Ngươi biết nhân sinh khó khăn nhất là gì không?\"<br><br>\"Không phải tương ngộ, là cửu biệt trùng phùng.', '2026-03-11 00:00:00', 'tathanaiphapytieuthu.jpg'),
(5, 'Ván Cờ Ẩn Danh', 'Nguyên Thanh Đại', 'Trinh Thám, Ngôn Tình', 148, 'Hoàn thành', '1. Cô là Chu Uẩn, cũng là Thẩm Uẩn.</p><p dir=\"ltr\" data-rm-block-id=\"block-7\">Năm tám tuổi, vì một tai nạn bất ngờ, nhà họ Chu đã nhận nuôi cô. Người người đều nói cô một bước bước chân vào chốn hào môn, từ nay cuộc đời sang trang, một bước lên mây.</p><p dir=\"ltr\" data-rm-block-id=\"block-8\">Nhưng chẳng ai hay biết, đằng sau sự nhận nuôi ấy là những lời dối trá chất chồng, cho cô một thân phận hiển hách chỉ để tô vẽ thêm cho danh tiếng và sự kính trọng của người đời dành cho nhà họ Chu.</p><p dir=\"ltr\" data-rm-block-id=\"block-9\">Cô từng tưởng rằng, bản thân mình đối với Chu Vực là khác biệt.</p><p dir=\"ltr\" data-rm-block-id=\"block-10\">Anh ta đối xử tốt với cô hơn tất thảy mọi người, tốt đến mức không gì sánh bằng, tốt đến nỗi khiến cô mụ mị đầu óc, nảy sinh thứ tình cảm không nên có với anh ta.</p><p dir=\"ltr\" data-rm-block-id=\"block-11\">Ngay khoảnh khắc cô trao đi chân tình, cô lại nghe thấy anh ta giải thích với người khác, cũng là định vị rõ ràng cho mối quan hệ này:</p><p dir=\"ltr\" data-rm-block-id=\"block-12\">“Đã nhận nuôi thì phải có trách nhiệm, không thể để người đời đàm tiếu được.”</p><p dir=\"ltr\" data-rm-block-id=\"block-13\">Lúc ấy cô mới biết, bên cạnh Chu Vực chưa bao giờ thiếu phụ nữ, chỉ là anh ta quá giỏi ngụy trang mà thôi. Cô dùng cách thức quyết tuyệt nhất để vạch rõ giới hạn, rời khỏi nhà họ Chu.</p><p dir=\"ltr\" data-rm-block-id=\"block-14\">2. Khi tất cả mọi người đều dè bỉu, dùng những lời lẽ châm biếm mỉa mai cô, cô đã gặp được một người có danh tiếng không kém gì mình.</p><p dir=\"ltr\" data-rm-block-id=\"block-15\">Anh là sự tồn tại bí ẩn nhất ở Túc Nguyên, là nhân vật thần bí mà giới truyền thông tranh nhau phỏng vấn nhưng không thể tiếp cận, là Văn tổng của Thịnh Hoằng – người được đồn đại là nửa chính nửa tà, khen chê lẫn lộn.</p><p dir=\"ltr\" data-rm-block-id=\"block-16\">Anh không có tin đồn tình ái, không tham gia bất kỳ tiệc rượu nào, báo chí bên ngoài đưa tin về anh chỉ gói gọn trong thân phận Tổng giám đốc Thịnh Hoằng.</p><p dir=\"ltr\" data-rm-block-id=\"block-17\">Ngày hôm đó, anh đã giúp cô. Sau này cô mới hiểu, đó là sự tiếp cận đã được toan tính từ trước.</p><p dir=\"ltr\" data-rm-block-id=\"block-18\">3. Anh thừa nhận email ẩn danh kia là do anh gửi, dụ cô quay lại Túc Nguyên, mục đích lợi dụng cô quá đỗi rõ ràng.</p><p dir=\"ltr\" data-rm-block-id=\"block-19\">Điều kiện hợp tác anh đưa ra là: Giúp cô thoát khỏi sự kiểm soát của nhà họ Chu, trở lại cuộc sống bình yên, và công bố sự thật ra ánh sáng. Cái giá phải trả là cô phải nghe theo mệnh lệnh của anh như một con rối gỗ.</p><p dir=\"ltr\" data-rm-block-id=\"block-20\">Cô chưa bao giờ là người cam chịu, nhưng lại hiểu đạo lý “hư tình giả ý” để sinh tồn.</p><p dir=\"ltr\" data-rm-block-id=\"block-21\">Anh hiểu cô, cô liền trước mặt anh giả vờ bộc lộ chân tính; Anh tính kế cô, cô liền giả vờ không biết mà ngoan ngoãn chui vào rọ.</p><p dir=\"ltr\" data-rm-block-id=\"block-22\">Đêm đó, người hiếm khi tham dự tiệc tối như anh lại đích thân đến hiện trường. Giữa chốn phồn hoa nâng ly cạn chén, anh kéo cô vào một góc khuất, trầm giọng chất vấn:</p><p dir=\"ltr\" data-rm-block-id=\"block-23\">“Ở trước mặt anh trai em mà vội vã phủ nhận quan hệ như thế, coi tôi là lốp dự phòng sao?”</p><p dir=\"ltr\" data-rm-block-id=\"block-24\">Về sau, ánh mắt anh nhìn cô ngày càng khác lạ. Cô biết, cuộc phản công của con mồi đã chính thức bắt đầu.</p><p dir=\"ltr\" data-rm-block-id=\"block-25\">4. Cô hoàn toàn biến mất, không ai tìm thấy. Nửa năm sau, màn kịch “chết đi sống lại” khiến tất cả mọi người phải trố mắt, bao gồm cả anh.</p><p dir=\"ltr\" data-rm-block-id=\"block-26\">Anh mất đi vẻ bình tĩnh, liệu việc như thần của ngày xưa, đi trong đêm để đến nơi, phong trần mệt mỏi chỉ để tận mắt thấy cô còn sống.</p><p dir=\"ltr\" data-rm-block-id=\"block-27\">Anh nghiêng đầu quan sát kỹ người trong lòng “Nếu tôi đưa ra giá cao để mua chuộc em, em có đồng ý không?”</p><p dir=\"ltr\" data-rm-block-id=\"block-28\">Chu Uẩn rũ mi mắt, nghe lời anh nói thì bật cười từ tận đáy lòng: “Mua chuộc tôi cái gì? Cơ thể hay tình cảm?”</p><p dir=\"ltr\" data-rm-block-id=\"block-29\">Đôi mắt hẹp dài của Văn Chú phủ lên một tầng nghiêm túc sau khi suy tính kỹ càng: “Nếu tôi muốn cả hai thì sao?”</p><p dir=\"ltr\" data-rm-block-id=\"block-30\">“Chỉ để nhìn thấy tôi cúi đầu cầu xin anh? Hay là thỏa mãn dục vọng chinh phục của anh?”</p><p dir=\"ltr\" data-rm-block-id=\"block-31\">“Tôi biết em cố ý dụ tôi đến Vụ Sơn cũng biết em có toan tính riêng của mình, nhưng vậy thì đã sao, em thích chơi tôi sẽ chơi cùng em, nhưng em cũng biết thời gian của người như tôi rất quý giá, thời gian lâu rồi cũng phải thu chút thù lao chứ.”</p><p dir=\"ltr\" data-rm-block-id=\"block-32\"> ***Xin lưu ý</p><ul><li dir=\"ltr\"><p dir=\"ltr\" data-rm-block-id=\"block-33\">Nữ chính thuộc kiểu thông minh (giai đoạn đầu chưa bộc lộ rõ, về sau sẽ cực kỳ bản lĩnh, đại sát tứ phương).</p></li><li dir=\"ltr\"><p dir=\"ltr\" data-rm-block-id=\"block-34\">Nam chính tâm cơ thâm sâu, từng bước toan tính.</p></li><li dir=\"ltr\"><p dir=\"ltr\" data-rm-block-id=\"block-35\">Lợi dụng qua lại, đừng vội đánh giá thiết lập nhân vật chỉ qua một chương truyện (tác giả không chịu trách nhiệm nếu độc giả tự suy diễn quá đà).</p></li><li dir=\"ltr\"><p dir=\"ltr\" data-rm-block-id=\"block-36\">Thương trường quyền mưu / Hướng báo thù / Có tình tiết h.ă.c*k não (nếu đọc lướt hoặc bỏ chương có thể sẽ không hiểu mạch truyện).', '2026-03-11 00:00:00', 'vancoandanh.jpg'),
(6, 'Khó Dỗ Dành', 'Trúc Dĩ', 'Ngôn Tình', 89, 'Hoàn thành', 'Bạn đang đọc truyện <b>Khó Dỗ Dành</b> của tác giả <b>Trúc Dĩ</b>. Tình cờ, Ôn Dĩ Phàm cùng người bạn học cấp ba từng bị cô cự tuyệt là Tang Diên thuê chung một nhà.<br><br>Hai người nước giếng không phạm nước sông, như hai người xa lạ sống dưới cùng một mái hiên.<br><br>Cuộc sống bình yên dừng lại ở một buổi sáng.<br><br>Tối trước đó Ôn Dĩ Phàm ngủ ở phòng mình, vậy mà sáng hôm sau lại tỉnh dậy ở trên giường Tang Diên.<br><br>Biết mình bị mộng du, Ôn Dĩ Phàm chỉ có thể giải thích và xin lỗi anh. Nhưng rồi chuyện này lại liên tiếp xuất hiện, cô đành thương lượng cùng anh, đề nghị anh trước khi ngủ khóa cửa phòng lại.<br><br>Tang Diên lơ đễnh: “Em sẽ cạy khóa.”<br><br>Ôn Dĩ Phàm nhún nhường nói: “Tôi nào có bản lĩnh đó?”<br><br>“Để cùng chung chăn gối với tôi” Tang Duyên chậm rãi giương mắt, không tập trung, “em có cái gì không làm được?”<br><br>Ôn Dĩ Phàm yên lặng hai giây, thành khẩn nói: “Nếu đúng thật như vậy, anh nguyện ý khóa cửa sao?”<br><br>“...”.....<br><br>Ôn Dĩ Phàm: “Vậy tới luôn đi.”<br><br>Tang Diên: “?”<br><br>• Tóm tắt một câu: Bạn cùng phòng luôn cho là tôi muốn tán tỉnh anh ta.', '2026-03-24 15:58:42', 'kho-do-danh.jpg'),
(7, 'Cưới Trước Yêu Sau', 'Mộng Tiêu Nhị', 'Ngôn Tình, Sủng', 96, 'Hoàn thành', '<b>Giới thiệu:</b><br><br>Ba tháng sau khi kết hôn, Giản Hàng và Tần Mặc Lãnh vẫn phân chia phòng ngủ. Mối hôn nhân này là do ông cụ nhà họ Tần quyết định, Tần Mặc Lãnh không có tình cảm với cô. Trong mắt người ngoài, người có gia cảnh bình thường như cô gả đến nhà họ Tần là bay lên cành cây cao biến thành phượng hoàng.<br><br>Không ít người trông chờ cô trở thành chuyện cười vì bị người chồng giàu có ruồng bỏ.<br><br>Mối hôn nhân này cô cũng không thiệt thòi, Giản Hàng quyết định cùng Tần Mặc Lãnh sống chung với nhau.<br><br>Đêm đó, cô chủ động tìm anh nói chuyện, nói về một chủ đề nào đó trên hotsearch.<br><br>Tần Mặc Lãnh trả lời qua loa mấy câu với cô. Giản Hàng trông bộ dạng thờ ơ đó, ngay tức khắc đứng dậy trở về phòng ngủ.<br><br>Không lâu sau đó, tiếng gõ cửa phòng vang lên.<br><br>Giản Hàng không mở cửa, ngữ khí lạnh nhạt: “Có chuyện thì nói!”<br><br>Tần Mặc Lãnh: “Hotsearch mà em quan tâm ban nãy mới đứng thứ 22, trạng thái là “mới”, bây giờ lên tới vị trí thứ 2 rồi, phía sau còn có “bạo” màu tím”.<br><br>Giản Hàng: “...”<br><br>PS: Nội dung như tên truyện, cưới trước yêu sau. Nam chính từ không yêu, tới rung động, đến quyết tâm một lòng.', '2026-03-24 16:01:50', 'cuoi-truoc-yeu-sau-mong-tieu-nhi-221970.jpg'),
(8, 'Giả Vờ Mất Trí Nhớ', 'Tiêu Thủy Huyền Khả', 'Bách Hợp, Khác', 174, 'Hoàn thành', '<p>Cô 6 tuổi, Mục Thanh Nhiễm 12 tuổi.<br />Lần đầu gặp mặt, chị ấy cho cô một viên kẹo sữa, ngọt ngào, tan chảy trong lòng. Cùng sống bên nhau nhiều năm, cô luôn cố gắng chạy theo bước chân của Mục Thanh Nhiễm.<br />Từ một cô bé hay khóc đến khi cô lớn lên xinh đẹp như ngọc. Hòa Mộc vẫn luôn ngước nhìn, thành kính Mục Thanh Nhiễm như một vị thần.<br />Nhưng có một ngày, chị ấy đưa cho cô một con dao, đâm sâu vào tim, máu thịt bầm dập.<br />Khi cô 24 tuổi, Mục Thanh Nhiễm 30 tuổi.<br />Gặp lại nhau......<br />Cô không muốn thừa nhận, cái tên Mục Thanh Nhiễm gần như chiếm giữ toàn bộ cuộc đời cô.<br />Nếu như, Mục Thanh Nhiễm lại tặng cho cô một viên kẹo sữa, Cô, vẫn muốn làm đứa trẻ của chị ấy.<br />Nhưng khi gặp lại nhau, Mục Thanh Nhiễm thậm chí còn xóa sạch quá khứ của họ, và con dao cắm trong tim càng xoáy sâu hơn.<br />Vào khoảng khắc Hòa Mộc quyết tâm quay lưng, Mục Thanh Nhiễm nhận ra, lần này hình như cô đã thật sự đánh mất đứa trẻ của mình.<br />Cô chưa bao giờ hoảng loạn như vậy, khao khát muốn nắm lấy bàn tay ấm áp đó một lần nữa. <br />Cuối cùng, cô cũng hiểu, trong suốt những năm tháng qua, đứa trẻ của cô đã đau khổ biết bao.<br />Hòa Mộc: Suỵt, đừng nói chuyện tình cảm với tôi, tôi chỉ muốn lo cho sự nghiệp.<br />Nội dung: tình cảm, chênh lệch tuổi tác, tái hợp, thương trường<br />Số chương: 161 + 13 PN', '2026-03-24 16:04:30', '384779149-256-k446659.jpg'),
(9, 'Giáo Sư Gián Điệp', 'Sayren', 'Khác, Light Novel', 734, 'Hoàn thành', '<p>Hắn trở thành giáo sư tại học viện ma thuật tốt nhất đế quốc.<br />....Vì bị nhầm với người khác.</p><p>Đây là light novel được viết bởi tác giả Sayren.<br />Thông tin về light novel hầu hết đều ở trên Reddit, nếu ai có nhu cầu hãy lên Reddit để tìm hiểu thêm, đây chỉ là bản trans để tiện đọc lại.</p><p>Giới thiệu</p><p>Hầu hết các bậc cha mẹ đều đã có dự định sẵn về công việc tương lai của con cái. Họ thường đề xuất những nghề nghiệp cấp cao như bác sĩ hoặc thẩm phán, nếu không, chí ít cũng phải là một công chức có công việc ổn định. Chẳng ai lại muốn con mình phải chịu khổ.<br />Tuy nhiên, trong trường hợp của tôi thì hơi khác một chút.<br />\"Con trai, con sẽ trở thành một pháp sư.\"<br />\"Dạ?\"<br />Đó là lời mẹ nói với tôi khi cha tôi mất sớm và tôi phải lớn lên cùng với một đứa em gái hung dữ.<br />Mặc dù gia đình không túng thiếu hay nghèo khó gì nhưng tôi vẫn muốn kiếm tiền bằng con đường học hành, từ đó nhắm đến việc trở thành bác sĩ, nhà khoa học hay một lập trình viên. Tuy nhiên, tôi chẳng thể ngờ được con đường tương lai mà mẹ khuyên mình lại hoàn toàn không nằm trong dự tính thông thường như vậy.<br />Tôi nên nói gì về thứ nghề nghiệp mang đầy tính Thần học này đây?<br />\"Mẹ vừa nói gì vậy?\"<br />\"Con không nghe rõ à? Vậy mẹ sẽ nói lại lần nữa. Con phải trở thành một pháp sư.\"<br />Tôi trả lời rất kiên quyết.<br />\"Con không thích pháp sư.\" <br />Tôi sẽ không trở thành một pháp sư.<br />Trước câu trả lời táo bạo của tôi, mẹ hơi nhướng mày, bà chậm rãi tuyên bố chắc nịch.<br />\"Con có phẩm chất của một pháp sư. Tất cả các linh hồn đều đang dõi theo con. Không có nghề nào khác phù hợp với con hơn một pháp sư đâu.\"<br />Con có tài năng như vậy sao con không biết?<br />Tôi choáng váng. Ngoài từ vô lý ra, tôi chẳng nghĩ ra từ nào khác.<br />Kể từ đó, mẹ tôi dành phần lớn thời gian nói những điều không nên nói với con trai của bà, chẳng hạn như tôi có những phẩm chất độc đáo, rằng tôi sẽ bị thương nếu tôi không trở thành một pháp sư và sẽ không nhận được chỉ dẫn của các vị thần.<br />Tôi đã trả lời gì sau đó?<br />\"Con sẽ không làm pháp sư đâu.\"<br />\"Sau này con sẽ bị thương. Bọn họ đều đang lo lắng cho con.\"<br />\"Nếu là vì con, họ nên ủng hộ con mới đúng!\" <br />Tôi nhớ mình đã nói câu đó một cách cương quyết và nhốt mình trong phòng.<br />Thành thật mà nói, hành động của mẹ chỉ làm cho tôi thêm buồn bực và tức giận. Mẹ không thể bắt một đứa trẻ từ bỏ mọi thứ mà nó đã dày công thiết kế từ khi học trung học chỉ để trở thành một pháp sư được. Cái nghề nghiệp mới chỉ nghe tên thôi đã thấy có mùi lừa đảo rồi.<br />Vào thời điểm đó, tôi thậm chí còn ra sức học hành chăm chỉ hơn để chống đối. Mẹ thường xuyên làm phiền, nhồi nhét vào đầu tôi hàng tá thứ mang đậm tính tôn giáo. Bà dạy tôi đủ thứ kiến thức kỳ quái như thơ ca, ma thuật hay thậm chí là phù thủy. <br />Mười năm qua đi, khi tôi cuối cùng cũng đã thực sự trở thành một phần tử tinh anh của xã hội, bất hạnh thay, tôi lại qua đời trong một vụ tai nạn xe hơi.<br />Thật vô lý!<br />...<br />Mình vẫn còn sống?<br />Chính xác hơn thì tôi đã chết và lại được sinh ra một lần nữa.<br />Khái niệm Kiếp sau thực sự tồn tại ư? Chẳng lẽ những gì mẹ nói đều là sự thật?<br />Tôi nên làm gì bây giờ?<br />...<br />\"Mở tài liệu ra. Tiếp tục tiết học trước, hôm nay ta sẽ dạy các trò cách vẽ một vòng tròn ma thuật.\"<br />Tôi bất đắc dĩ trở thành giáo sư tại Học viện Phép thuật.<br />......Làm sao chuyện này lại xảy ra được cơ chứ?</p', '2026-03-24 16:08:30', '332898347-256-k688758.jpg'),
(10, 'Anh Trai Nhân Vật Chính', 'Tiên Sắc Xám', 'Dị Giới, Xuyên Không, Khác, Light Novel', 96, 'Hoàn thành', 'Tên truyện: Anh Trai Nhân Vật Chính<br>Người Viết: Tiên Sắc Xám<br><br>===<br><br>Ở kiếp này, Khan là anh trai nhân vật chính nhưng số mệnh của hắn lại không may mắn hưởng ké được miếng hào quang nào của cậu ta.<br><br>Khan lấy lại được ký ức tiền kiếp mình trong hoàn cảnh hoàn toàn bất lợi. Hắn nhận ra mình chỉ là một nhân vật phụ, một nhân vật phản diện bé nhỏ trong bộ tiểu thuyết dài kỳ được viết bởi nhỏ em gái của mình ở kiếp trước viết ra.<br><br>Hắn là nhân vật được định sẵn kết cục làm đá lót đường cho nhân vật chính.<br><br>Nếu chỉ cần an phận làm cục đá lót đường cho nhân vật chính thì cũng được thôi, hắn sẽ vô cùng biết điều mà trở thành cục đá. Nhưng ngặt nỗi, hắn lại là anh trai nhân vật chính, là người anh trai mà nhân vật chính căm ghét.<br><br>Nếu hắn nhớ không nhầm thì nhân vật chính của thế giới này cũng muốn hắn chết thì phải...<br><br>Không ổn chút nào! Hắn chỉ là một nhân vật phụ vô dụng, bẩm sinh đã không có ma lực, không có sức mạnh được thần thánh ban phước hay là đàn em lợi hại sát cánh.<br><br>Hắn không có gì cả, ngoại trừ...<br><br>Nội dung cốt truyện.<br><br>Không còn cách nào khác, hắn phải giải quyết nhân vật chính thôi.', '2026-03-24 16:10:48', 'anh-trai-nhan-vat-chinh.jpg'),
(11, 'Nhất Niệm Vĩnh Hằng', 'Nhĩ Căn', 'Tiên Hiệp, Huyền Huyễn', 1981, 'Hoàn thành', '<b>一念永恒<br></b><br>Nhất niệm thành biển cả, nhất niệm hóa nương dâu.<br>Nhất niệm trảm nghìn Ma, nhất niệm giết vạn Tiên.<br><br>Chỉ có niệm của ta... là Vĩnh hằng.', '2026-03-24 17:47:03', 'nhat-niem-vinh-hang.jpg'),
(12, 'Mệnh Tiên', 'Mã Hộ Tử Quân', 'Huyền Huyễn, Linh Dị, Đam Mỹ, Hài Hước, Khác', 109, 'Hoàn thành', '<p>Tên gốc: 命仙</p><p>Tác giả: Mã Hộ Tử Quân</p><p>Giới thiệu</p><p>Trong thời đại công nghệ hiện đại phát triển vượt bậc, những câu chuyện về phong thủy và mệnh cách* vẫn được lưu truyền khắp phố lớn ngõ nhỏ.</p><p>Vẫn có người đang thuận buồm xuôi gió bỗng gặp biến cố bất ngờ, hoặc chịu tai ương khó hiểu.</p><p>Ting! Lâm Túc mở điện thoại lên: \"Bạn có một đơn hàng mới.\"</p><p>Cậu tắt điện thoại, nhét cuốn sổ vào túi rồi ung dung bước ra ngoài. Trong mắt cậu, sinh thần bát tự của mọi người hiện lên rõ ràng ngay ngắn trên đầu họ.</p><p>Giữa ba nghìn thế giới, có một chức vị gọi là \"Mệnh Tiên\".</p><p>Một ánh mắt nhìn thấu thiện ác, một nét bút sửa lại mệnh bàn.</p><p>Học sinh giả thần giả quỷ để giành suất tuyển thẳng, thiếu gia thay đổi vận mệnh để bước chân vào hào môn, nghệ sĩ đánh cắp cơ may để mưu cầu hào quang chói lọi.</p><p>Bọn họ dốc hết thủ đoạn tà đạo hòng chiếm đoạt những thứ vốn không thuộc về mình.</p><p>Nhưng chẳng ai ngờ rằng, chỉ cần Mệnh Tiên vung một nét bút, vận mệnh sẽ lại trở về quỹ đạo vốn có.</p><p>Lâm Túc lật cuốn sổ mệnh cách: \"Để tôi xem hôm nay ai đang giở trò nào.\"</p><p>.<br />Hai vị thần quan thần tiên yêu đương!</p><p>(Bí mật) × Lâm Túc</p><p> </p><p>-</p><p>Tags: Linh dị thần quái, vả mặt, sảng văn, huyền học, hài hước.</p><p>Tóm tắt: Một ánh mắt nhìn thấu thiện ác, một nét bút sửa lại mệnh bàn.</p><p>Thông điệp: Ánh sáng chính đạo chiếu rọi khắp đất trời.</p><p>-</p><p>Chú thích:</p><p>*Mệnh cách là cấu trúc các sao, hành, cung trong lá số Tử Vi, cho thấy bản chất, tiềm năng, tính cách và các đặc điểm cố định trong cuộc đời một người. (chú ý mệnh cách khác với vận mệnh, vận mệnh tốt hay xấu thường dựa trên sự tương tác giữa mệnh cách và vận hạn. Nếu mệnh cách mạnh và vững, người đó dễ vượt qua nghịch cảnh.)</p><p>*Mệnh bàn là một khái niệm quan trọng trong Tử Vi và các môn thuật số phương Đông, là toàn bộ bản đồ số mệnh của một người, được lập dựa trên ngày, tháng, năm, và giờ sinh.</p><p>Vận mệnh < Mệnh cách < Mệnh bàn.</p><p>-</p><p>Lưu ý của tác giả:</p><p>1. Truyện hài ngọt sảng, tiết tấu nhanh, độ dài không quá dài.</p><p>2. Công thụ đều là \"sếp\" lớn, chủ nghĩa cường cường cường! Không ngược, toàn bộ là quá trình vả mặt.</p><p>3. Truyện này chỉ thuần sảng. Nhân vật chính là thần, sức mạnh áp đảo mọi cấp độ. Không có phản diện bất tử hay ai có thể đánh lại ngang tài ngang sức. Nếu bạn thích kiểu đấu cân sức, cân nhắc trước khi đọc.</p><p>4. Tuyến tình cảm và nội dung có nhiều phục bút và chi tiết ẩn, không viết quá rõ nhưng cũng không mơ hồ. Đọc với tốc độ bình thường sẽ hiểu rõ, tất cả sẽ được làm rõ ở cuối truyện.</p><p>5. Viết truyện để vui, mọi thứ theo sở thích và phong cách của tác giả. Nếu không hợp gu, vui lòng rời đi, không cần báo cáo.</p><p>-</p><p>Lưu ý của editor:</p><p>1. Bộ này có khá nhiều ngôn ngữ mạng và tiếng lóng, trình edit của mình còn non so với những bạn khác vậy nên có gì sai sót mong được mọi người góp ý.</p><p>2. Bộ này cũng chủ yếu là về tử vi, tụi mình chỉ có thể tìm hiểu trên mạng và giải thích sao cho mọi người dễ hiểu, có sai sót gì thì giúp một tay mình nhen.</p><p>3. Đầu truyện chưa nắm rõ mạch truyện và nhân vật (+ cả 2 đứa làm) nên chắc xưng hô sẽ hơi rối, các chương sau đã thống nhất, đang beta. </p><p>4. Truyện thời hiện đại nên mình để các nhân vật đều xưng hô kiểu hiện đại.</p><p>5. Mọi người bình luận nhiều vô nha, tụi mình thích đọc bình luận lắm (*ゝω・)ﾉ</p><p>Vậy thoai, chúc mọi người đọc truyện vui vẻ nho ♥️', '2026-03-24 18:08:16', '1774320437_6_1_menh-tien-ma-ho-tu-quan.jpg'),
(13, 'Núi Của Nàng , Biển Của Nàng', 'Phù Hoa', 'Bách Hợp', 82, 'Hoàn thành', 'Tác giả: Phù Hoa.<br>Editor: Fukahi.<br><br><b>Văn án:</b><br><br>\"Hồ nước là hồ nước lặng, cá bơi nguyện ý vào ở cái hồ này chăng?\"<br>\"Nguyện ý.\"<br><br>(Du Dư x Trì Đường, vườn trường văn)<br><br>Tags: Hoa quý vũ quý (tuổi thanh xuân), ưa thích không rời, chỉ yêu một người, tình yêu bị trần đời không cho phép, là vườn trường văn.', '2026-03-24 18:12:57', 'nui-cua-nang-bien-cua-nang.jpg'),
(14, 'Năm Thứ Tư Sau Khi Nàng Chết', 'Quân Tuế Hi', 'Ngôn Tình, Cung Đấu, Cổ Đại, Ngược, Khác', 124, 'Hoàn thành', '- Thể loại: Nguyên sang, Ngôn tình, Cổ đại , HE , Tình cảm , Hào môn thế gia , Cẩu huyết , Cung đình hầu tước , Cường thủ hào đoạt , 1v1 , Thị giác nữ chủ , Phúc hắc , Hỏa táng tràng</p><p>- Văn án: nói trước nam9 rất ác, ác đến cuối cùng, nữ chính rất cứng, cứng đến cuối cùng. Hết chính truyện nữ 9 vẫn không iu nam 9, hết chính truyện, nam 9 vẫn cầm tù nữ 9.</p><p>【 Cường thủ hào đoạt · Cẩu huyết cổ đại · Toàn viên hỏa táng tràng 】</p><p>Thế nhân đều biết, Vân Hi thích Hoài Lăng vương.</p><p>Hoài Lăng vương hắt hơi một cái, nàng liền nửa đêm trèo tường đưa áo lông chồn.</p><p>Hoài Lăng vương yêu bút mực, nàng không ngại ngàn dặm xa xôi, toàn thân thương tích cũng phải cầu cho được một phương nghiên mực truyền đời.</p><p>Nhưng Hoài Lăng vương không thích Vân Hi.</p><p>Đến cả liếc mắt một cái, hắn cũng không muốn.</p><p>Ngày ấy, khi bọn thích khách đặt đao lên cổ Vân Hi và Sầm Ngữ Vi, buộc Hoài Lăng vương phải chọn một trong hai, hắn không hề do dự, chọn Sầm Ngữ Vi.</p><p>Hắn nói:</p><p>“Vân Hi, Ngữ Vi từ nhỏ đã mảnh mai, chịu không nổi kinh hách. Còn ngươi thì không phải. Ngươi hiểu chứ?”</p><p>Vân Hi hiểu rất rõ.</p><p>Sầm Ngữ Vi dù sao cũng là thanh mai trúc mã, tiểu tâm can trong tim hắn, còn nàng thì da dày thịt béo, đến chém đầu cũng chẳng thấy đau.</p><p>Quả nhiên, thích khách thả Sầm Ngữ Vi, quay sang vung đao chém thẳng vào cổ Vân Hi.</p><p>Thế nhân đều cho rằng Vân Hi đã chết.</p><p>Ngay cả Hoài Lăng vương cũng tin là như vậy.</p><p>Nhưng Vân Hi không chết.</p><p>Nàng rời xa kinh đô, sống tiêu dao tự tại, còn cùng người mình yêu bái đường thành thân.</p><p>Chỉ là ngày thành hôn ấy, lại gặp tân đế cải trang vi hành.</p><p>Khoảnh khắc gió cuốn tung khăn voan, tân đế thần sắc đại biến, ánh mắt điên loạn, đánh mất cả uy nghi của bậc cửu ngũ.</p><p>Hắn loạng choạng lao tới, giật Vân Hi ra khỏi kiệu hoa.</p><p>“Vân Hi, ngươi dám gạt ta! Ngươi sao dám… ngươi sao dám……”</p><p>Hoài Lăng vương vẫn luôn cho rằng mình không thích Vân Hi.</p><p>Cho đến một ngày, hắn nhìn thấy nàng cười trong lòng nam nhân khác, tim hắn đột nhiên quặn thắt.</p><p>Đôi mắt chứa đầy xuân sắc ấy, từng chỉ nhìn hắn—chỉ thuộc về một mình hắn!</p><p>Hắn đoạt nàng trở về, bẻ gãy đôi cánh, nhốt nàng trong hậu cung.<br />Hắn cho rằng chỉ cần ban cho nàng vài phần ân sủng, nàng sẽ lại như trước, khăng khăng một mực yêu hắn.</p><p>Nhưng hắn chưa từng nghĩ tới, nàng thật sự không còn yêu hắn nữa.</p><p>Thậm chí nàng còn dùng trường kiếm đặt lên cổ hắn, uy hiếp hắn thả phu quân cũ của nàng. Nếu không—nàng sẽ giết hắn.</p><p>Cường thủ hào đoạt, cường thủ hào đoạt, cường thủ hào đoạt. Chuyện quan trọng nói ba lần.</p><p>Nam chính thật sự điên, cũng thật sự cẩu.</p><p>Không tiếp nhận bất kỳ kiểu “gỡ mìn” văn án nào.</p><p>Không hiểu toàn cảnh thì xin đừng phát biểu.</p><p>Tự ý não bổ—xóa bình trực tiếp.</p><p>Bình luận công kích tác giả—xóa không thương lượng.</p><p>Không ăn được thể loại này thì tự rút lui kịp thời, đừng đến trút cảm xúc, không ai là thùng rác cảm xúc của ngươi.</p><p>Tag: Cung đình hầu tước · Yêu sâu sắc · Cổ đại · Phúc hắc · Truy ái hỏa táng tràng</p><p>Góc nhìn nhân vật chính: Vân Hi, Tiêu Thận Kính.</p><p>Một câu tóm tắt: Bệ hạ, bầu trời và mây—vĩnh viễn không giam cầm được nhau được.</p><p>Lập ý: Dù cuộc đời có khổ cực đến đâu, cũng phải dũng cảm đối mặt.', '2026-03-24 18:15:58', '119.jpg'),
(15, 'Tổ Thần Chí Tôn', 'KK Cố Hương', 'Huyền Huyễn, Khác', 1628, 'Hoàn thành', 'Hắn từng là thiên tài tu luyện, là anh tài trong anh tài, nhưng ba năm trước vì một sự cố mà từ trên đỉnh cao rơi xuống vực thẳm, bị người người cười chê.<br><br>Suốt ba năm hắn không ngừng nổ lực bất kể ngày đêm, cuối cùng cũng có cơ hội trở lại con đường của người tu hành, từ đây thiên địa rộng mở, người người khuất phục...', '2026-03-24 18:19:54', 'Tổ-thần-chí-tôn.jpg'),
(16, 'Linh Vũ Thiên Hạ', 'Vũ Phong', 'Tiên Hiệp, Dị Giới, Huyền Huyễn, Xuyên Không', 5024, 'Hoàn thành', '<b><i>Nhóm dịch:</i></b><i> Sói Già<br><b>Đả tự:</b> Bựa Thập Ngũ BLH<br><br></i><b>Lục Thiếu Du</b>, linh hồn bị xuyên qua đến thế giới khác, nhập vào thân thể của một thiếu gia không có địa vị phải trải qua cuộc sống không khác gì nô bộc.<br>Thế giới này lấy Vũ vi cường, lấy Linh vi tôn, nghe đồn khi võ đạo đỉnh phong, linh đạo đạt đến cực hạn có thể phá toái hư không. <br>Lục Thiếu Du mang theo ký ức từ kiếp trước tái sinh, không cam lòng làm một thiếu gia chẳng khác gì củi mục.<br><br>Trong thế giới xa lạ, <br>Say - nằm trên gối mỹ nhân, <br>Tỉnh - nắm quyền thiên hạ.<br>Đây mới là cuộc sống đáng mơ ước. <br>Linh - Vũ song tu<br>Bá chủ kiêu hùng<br>Đã đến, ta sẽ lưu lại một huyền thoại......<br><br><strong><b>Hệ Thống Tu Luyện:</b></strong><br><br><b>- Vũ giả: </b>Vũ khí, Vũ đồ, Vũ sĩ, Vũ sư, Vũ phách, Vũ tướng, Vũ suất, Vũ vương, Vũ tôn, Vũ đế.<br><b>- Linh giả: </b>Linh khí, Linh đồ, Linh sĩ, Linh sư, Linh phách, Linh tướng, Linh suất, Linh vương, Linh tôn, Linh đế.<br><br>Mỗi cấp được chia làm cửu trọng (chín tầng). Ngoài ra còn có Yêu thú, Linh thú các thể loại, chia làm nhất giai, nhị giai,... mỗi giai chia làm sơ kỳ, trung kỳ, hậu kỳ.<br><br>- <b>Công pháp:</b> chia làm sáu loại, từ cao đến thấp: Thiên, Địa, Huyền, Hoàng, Tinh, Thần<br><br>Tất nhiên là vẫn tồn tại một số công pháp đặc biệt bí ẩn khác.<br><br>- <b>Ngũ hệ: </b>Vũ giả, Vũ kỹ (công pháp cho vũ giả) được chia thành năm loại Mộc, Thủy, Hỏa, Thổ, Phong.', '2026-03-24 18:28:17', 'linh-vu-thien-ha.jpg'),
(17, 'Nụ Hôn Hải Đường', 'Thất Dư Vụ', 'Ngôn Tình, Đô Thị, Khác, Sủng', 107, 'Hoàn thành', '<p>Tác giả: Thất Dư Vụ </p><p>Tran / Editor: Lê Phạm Thanh Thảo</p><p>Beta: Lê Phạm Thanh Thảo</p><p>Thể loại: Cưới trước yêu sau, Hào môn thế gia, Hiện đại, HE, Sủng Ngọt</p><p>Độ dài: 107</p><p>Giới thiệu</p><p>Chàng trai nho nhã hệ Daddy X Tiểu thư kiêu sa, lộng lẫy</p><p>Nghe tin Thẩm gia ở Kinh Triệu và Từ gia ở Nam Lâm sắp làm thông gia, Từ Tử Diễn lập tức bỏ trốn ra nước ngoài ngay trong đêm, chỉ vì muốn từ hôn.</p><p>Trước khi máy bay cất cánh, anh ta gọi điện thoại cầu cứu người thân duy nhất mà anh ta tin tưởng trong nhà. Anh ta nhờ người đó đến gặp tiểu thư Thẩm gia để từ hôn. Đầu dây bên kia, giọng người đàn ông trầm ấm, trong trẻo, cười bảo: “Chắc chắn em sẽ bị ông nội phạt quỳ từ đường”</p><p>Anh ta không để tâm, bức xúc nói: “Kệ đi! Miễn là đừng bắt em cưới một cô gái xấu xí là được!”</p><p>Trong giới thượng lưu có lời đồn, tiểu thư Thẩm gia chưa bao giờ lộ diện trên bất kỳ phương tiện truyền thông nào vì cô là một người phụ nữ xấu xí, dung mạo bị hủy hoại.</p><p>…</p><p>Từ gia ở Nam Lâm là một gia tộc giàu có quyền quý</p><p>Từ Kỳ Thanh — người đứng đầu Từ gia là một quý ông nhã nhặn, thanh lịch, phong thái nhẹ nhàng. Anh là hình mẫu \"con rể hoàn hảo\" trong mắt các gia tộc quyền quý. Điều khác người duy nhất trong cuộc đời anh, có lẽ là việc anh phải thay em trai dọn dẹp đống tàn cục, anh gặp một cô gái nhỏ bàn chuyện từ hôn</p><p>Lần đầu tiên hai người gặp nhau là tại buổi hòa nhạc bế mạc của ngôi sao nổi tiếng— Trần Thụ Thanh.</p><p>Đại sư Trần Thụ Thanh lần đầu tiên xuất hiện cùng học trò bí mật của mình, cô gái Hà Tư Nguyệt Vận. Cô mặc một chiếc váy lụa đen, đẹp không tì vết. Dưới ánh đèn sân khấu, cô đã biểu diễn hoàn hảo tác phẩm nổi tiếng của Trần lão sư, khiến cả khán phòng kinh ngạc.</p><p>Kết thúc buổi hòa nhạc, tiếng vỗ tay vang dội. Sư tỷ cùng các bạn học thì thầm báo cho Thẩm Sơ Đường rằng người ngồi cạnh thầy chính là người của Từ gia</p><p>Trong khán phòng tối, người đàn ông mặc vest đen, dáng vẻ khiêm tốn, nghiêng đầu lắng nghe Trần Thụ Thanh nói chuyện. Anh không quên vỗ tay phụ họa, nhịp độ nhẹ nhàng, tao nhã. Gương mặt anh ẩn hiện trong ánh sáng, toát lên vẻ thanh lịch tuyệt trần.</p><p>Cô đoán, anh đến để từ hôn.</p><p>Sau buổi hòa nhạc, ở hậu trường, một bó hoa hải đường độc đáo được đưa đến tay cô.</p><p>Trong quán cà phê sắp đóng cửa, cô nhìn người đối diện: “Em biết Từ tiên sinh đến để từ hôn.”</p><p>Thực ra, cô còn chưa kịp nói ra ý mình cũng không muốn kết hôn sớm.</p><p>Người đàn ông từ tốn ngồi thẳng người, ngắt lời cô: “Thẩm tiểu thư, anh có một yêu cầu hơi quá đáng.”</p><p>Cô tỏ vẻ khó hiểu: “Cái gì?”</p><p>Anh bình thản nói: “Cùng anh kết hôn”</p><p>…</p><p>Sau khi kết hôn, người đàn ông vốn nho nhã, lịch thiệp lại thay đổi hoàn toàn. Chuyện ấy giúp tình cảm vợ chồng thăng hoa nhưng tần suất khá cao.</p><p>Một ngày nọ, sau khi xong việc, Thẩm Sơ Đường dùng ngón chân mềm mại cọ vào bắp chân săn chắc của người đàn ông. Nhớ lại cảnh tượng vừa rồi, má cô ửng hồng, mồ hôi nhễ nhại nói: “Em nghĩ chúng ta nên giảm bớt tần suất một chút.”</p><p>Người bên cạnh lười biếng vuốt ve mái tóc cô rồi móc lấy chiếc áo ngực gợi cảm trên mép giường, anh hỏi: “Vừa nãy người đòi anh mạnh hơn không phải là em sao?”</p><p>Thẩm Sơ Đường: “...”</p><p>Nam chính hơn nữ chính 5 tuổi / Cưới trước yêu sau</p><p>Tag: Đô thị, hào môn thế gia, tình cờ gặp gỡ, tình yêu và hôn nhân, ngọt văn, cưới trước yêu sau.</p><p>Nhân vật chính: Thẩm Sơ Đường, Từ Kỳ Thanh.</p><p>Tóm tắt: Cưới trước yêu sau | Chàng trai nho nhã X Tiểu thư kiêu sa.</p><p>Lập ý: Tình yêu bình đẳng.', '2026-03-24 18:31:59', '1752069991537.jpg'),
(18, 'Trên Sông Tĩnh Lặng', 'Đinh Mặc', 'Ngôn Tình, Đô Thị, Trinh Thám, Khác', 69, 'Hoàn thành', 'Tôi có một người mà mình thích, tôi chỉ gặp anh ấy một lần.</p><p>Tôi có một người mà mình yêu nhưng cô ấy không hề hay biết.</p><p>Tôi biết ở thời đại này, những kẻ cố chấp thường không có kết cục tốt đẹp.</p><p>Nhưng một khi đã bắt đầu chờ đợi, tôi muốn tiếp tục chờ đợi mãi mãi.</p><p>— Tình yêu, ly kỳ —</p><p>Một mối tình ngây thơ vọng tưởng, một khúc ca lý tưởng tội phạm điên cuồng.', '2026-03-24 18:40:57', '126.jpg'),
(19, 'Tù Điểu ', 'Bạch Lộ Vi Yến', 'Đô Thị, Bách Hợp, Trinh Thám, Khác', 165, 'Hoàn thành', 'Tác phẩm: Tù Điểu (Chim trong lồng)<br />Tác giả: Bạch Lộ Vi Yến<br />Thể loại: Bách hợp, hiện đại, tình hữu độc chung, nhân duyên gặp gỡ, cường cường liên hợp, trinh thám phá án, HE,....<br />Nhân vật chính: Kiều Ỷ Hạ x Lộ Tây Trán<br />Nhân vật phụ: Hạ Lan Thu Bạch, Lam Tuyết Ngô, Mạnh Lưu Sâm, Bạch Anh, Thạch Vi, Thương Lục,....<br />Editor: Phong Lạc</p><p>Văn Án</p><p>Cô, Kiều Ỷ Hạ, nữ thám tử tuyệt mỹ, có chỉ số thông minh cao. Nàng là mỹ nữ giáo sư tâm lý học tội phạm Lộ Tây Trán, cao ngạo lạnh lùng.</p><p>Khi hai người phụ nữ thông minh xinh đẹp, phúc hắc giống nhau bước vào nhân sinh của nhau, là nhất kiến chung tình soạn nên khúc ca tình yêu đẹp đẽ hay là oan gia ngõ hẹp không chịu thua kém gây nên những câu chuyện thú vị?<br />\"Công chúng khó chiều nhưng khoan dung, bọn họ có thể tha thứ tất cả, ngoại trừ thiên tài. Chỉ số thông minh của tôi đã định trước sẽ là thứ mà mọi người không có cách nào tha thứ cho sai lầm của tôi\". Lộ giáo sư nói.<br />\"Lộ giáo sư, thừa nhận cô thua tôi kì thực cũng không có gì mất mặt!\". Thám tử Kiều nói.<br />Đây là một hồi đấu đá của Ngự tỷ và Nữ vương, hãy xem thám tử Kiều cùng Lộ giáo sư làm thế nào cẩn thận từng bước, cười nhìn phong vân.<br />Đây là một câu chuyện cũ, về tình yêu.<br />*****</p><p>Người thân gần gũi nhất rời khỏi thế gian khiến cho Kiều Ỷ Hạ bỗng nhiên trầm tính, đem bản thân mình nhốt trong nhà tù vô hình, khó có thể thoát ra.</p><p>Lộ giáo sư lòng cất giấu bí mật dùng ba năm để tạo nên một nhà lao cho chính mình, giam cầm trái tim của mình, giam cầm tình yêu của mình.<br />Với người ngoài, hai người họ là tuyệt mỹ ngự tỷ lạnh lùng khuynh thành. Trong nội tâm, họ tràn đầy tâm sự, giống như một con chim bị nhốt trong lồng. Họ sẽ phá ngục giương cánh bay cao, hay vẫn bảo thủ tình cảm đã qua suốt cả cuộc đời?<br />\"Lộ Tây Trán, cô chính là S. Chính là ác ma đùa giỡn tất cả mọi người trong lòng bàn tay mình, là người thần bí kia, S\".<br />Lộ Tây Trán khẽ nhắm hai mắt, khóe miệng cong lên: \"Hạ, nếu như em muốn biết đáp án, như vậy chị có thể nói cho em biết, chị....\".', '2026-03-24 18:43:10', '93853012-256-k387543.jpg'),
(20, 'Bắt Được Rồi ', 'Hồ Linh', 'Ngôn Tình, Đô Thị, Trinh Thám, Khác', 104, 'Hoàn thành', 'Tác giả: Hồ Linh</p><p>Tran / Editor: AI_Quả Hồng</p><p>Beta: AI_Xuyến Chi</p><p>Thể loại: Chữa lành, Hiện đại, HE, Sạch, Phá án, Tâm lý, Góc nhìn nữ chính, Lâu ngày sinh tình</p><p>Độ dài: 104</p><p>Giới thiệu</p><p>Triệu Huyền, một nữ sinh cấp 3 đã bỏ học, tình cờ phát hiện một thi thể nam giới không rõ danh tính trên núi.</p><p>Chú chó đi cùng cô ngậm về hung khí giết người.</p><p>Triệu Huyền phân tích được thời gian tử vong và đặc điểm của nạn nhân.</p><p>Cảnh sát hình sự Từ Chí: “Điên rồ thật, khả năng nhìn một lần là nhớ được mọi thứ thực sự tồn tại hả?”</p><p>Cảnh sát hình sự Văn Văn: “Cô ấy thật thông minh, tôi rất thích.”</p><p>Phó đội trưởng đội cảnh sát hình sự: “Tôi sẽ lập tức gửi thư mời, nhận cô ấy vào đội.”</p><p>Triệu Huyền: “Tiền thưởng cho những vụ án quan trọng phải gấp đôi.”</p><p>Từ Chí: “Không phải chứ, cậu thật sự thích robot hả?”</p><p>Văn Văn: “Cậu thì hiểu cái gì.”</p><p>Vụ án xác chết không rõ danh tính trên núi, vụ án giết người hiếp dâm liên hoàn, vụ án buôn bán trẻ em, ...</p><p>Càng đến gần với sự thật, Triệu Huyền mới nhận ra rằng tất cả các manh mối đều hướng về phía mình.</p><p>“Vụ án giết người của thiếu nữ thiên tài!”</p><p>“Không phải chứ, cô ấy thật sự là hung thủ hả?”</p><p>“Bắt cô ấy, mang về đây. Đây mới là việc cậu nên làm.”</p><p>Văn Văn nhìn Triệu Huyền, trên gương mặt cô đã không còn nét rạng rỡ như trước nữa. Dường như cô đang nghi ngờ bản thân, không biết liệu mình có thật sự là hung thủ như họ nói hay không.</p><p>“Tiên Nhi, hãy tìm ra hung thủ đi. Giống như trước đây.”</p><p>“Triệu Huyền không thể nào là kẻ giết người được. Triệu Huyền là thiên tài. Thiên tài sẽ không làm những chuyện ngu xuẩn như vậy.”</p><p>Thiếu nữ thiên tài X Cảnh sát con nhà giàu.', '2026-03-24 18:44:22', '1751213924952.jpg'),
(21, 'Ngỗ Tác Kinh Hoa', 'Bạc Nguyệt Tê Yên', 'Ngôn Tình, Trinh Thám, Nữ Cường, Cổ Đại', 206, 'Hoàn thành', 'Nữ chủ Thích Tầm là một vị ngỗ tác tài nghệ cao cường, vì oan án của gia tộc mà phải ẩn danh đổi tính, nương nhờ nghề nghiệm thi để sinh sống. Nàng dựa vào bản lĩnh tinh tế cùng nhãn lực sắc bén, nhiều lần trợ giúp quan phủ phá giải những vụ án kỳ dị, uẩn khúc.</p><p>Trong quá trình ấy, nàng gặp được nam chủ Phó Quyết, một người xuất thân tôn quý, tâm cơ kín đáo. Từ hoài nghi lẫn nhau ban đầu, hai người dần sinh tín nhiệm, cùng vai kề vai tra ra chân tướng những âm mưu ẩn sâu phía sau các vụ án.', '2026-03-24 18:47:31', 'ngỗ tác kinh hoa.png'),
(22, 'Ẩn Tình Trong Án', 'Đưa Tôi Đến Hà Lan', 'Đô Thị, Bách Hợp, Trinh Thám, Khác', 101, 'Hoàn thành', 'Tác phẩm: Ẩn Tình Trong Án (Nói Tình Nói Án)</p><p>Tác giả: Đưa Tôi Đến Hà Lan (Đái Ngã Khứ Hà Lan)</p><p>Số chương: 101 Chương</p><p>Thể loại: Trinh thám, Hiện đại, 1x1, HE</p><p>Nhân vật chính: Lãnh Du  x Lâm Hinh</p><p>Văn án</p><p>Những vụ án hóc búa nối tiếp nhau kéo đến.</p><p>Hai sếp của hai tổ trọng án bị cuốn vào các vụ án ly kỳ, hãy chờ xem các nàng sẽ dẫn dắt đội viên phá án thế nào.</p><p>Cảnh sát A: \"Sếp Lãnh, cảnh sát Lâm ở tổ kế bên vừa hài hước vừa can đảm. Cô ấy đã phá rất nhiều vụ án, có lẽ chúng ta có thể nhờ cô ấy giúp đỡ. Quan trọng nhất cô còn xinh đẹp. Sếp chắc sẽ có hứng thú.\"</p><p>Lãnh Du nhướng mày: \"Vậy sao? Cô ấy phá được án là nhờ ăn may thôi. Hơn nữa, có đẹp thì liên quan gì đến vụ án hay đến tôi.\"</p><p>Cảnh sát B: \"Sếp Lâm, vụ án này cần người có IQ cao. Sếp Lãnh tổ bên là người bình tĩnh, cơ trí. Cô ấy chuyên giải quyết những vụ như vậy. Nếu không tổ mình thương lượng với cô ấy nha sếp?\"</p><p>Lâm Hinh nhìn móng tay mình: \"Cô nàng đó thì có gì hay? Suốt ngày lạnh lùng, thông minh hơn chút thôi. Lẽ nào tôi thua ai đó?\"</p><p>--------------------------------------------------------------</p><p>Vụ án 1: Cánh Cửa Lấp Kín (Chương 1 - 14)</p><p>Vụ án 2: Vết Khắc Cuối Cùng (C.15 - 32)</p><p>Vụ án 3: Câu Đố Chưa Bao Giờ Kết Thúc (C.33 - 51)</p><p>Vụ án 4: Bài Thơ Kỳ Quái (C.52-72)</p><p>Vụ án 5: Kỳ Án Cú Đêm (C.73-96)', '2026-03-24 18:50:25', '361382733-256-k267960.jpg'),
(23, 'Sát Thủ Tâm Lýn', 'Thanh Mang', 'Đô Thị, Trinh Thám', 40, 'Hoàn thành', 'Tôi chạy trong bóng tối, đuổi theo bóng dáng của người đó, nhưng khi chạy đến điểm cuối, tôi mới phát hiện ra trên con đường ấy chỉ có mỗi mình tôi.”<br /> Khi chỉ có một mình, bạn ngồi sâu trong ghế, nhìn chiếc quạt trần trên trần nhà, có bao giờ bạn tưởng tượng nó quay mãi, quay mãi, rồi đột nhiên rơi xuống, khiến bạn bị chặt lìa đầu, máu me be bét không?<br /> Giống như trong “Lưỡi hái tử thần”, con người có hàng vạn cách để đối mặt với cái chết. Chỉ là bạn chưa nghĩ đến, còn tử thần thì không gì là không thể.<br /> ***<br /> Nhà tâm lý học Cầm Mạch và đội trưởng đội điều tra hình sự Ninh Tề Thương cùng các thành viên của đội trọng án sẽ dẫn chúng ta bước vào một góc tối tăm và mục nát, nơi dơ bẩn và đen tối như thể bạn rơi xuống một hồ nước đầy rong rêu đen dày đặc, cảm giác nghẹt thở trào lên mũi. Bạn có bật khóc không?<br /> Khi bạn soi gương mỗi ngày, nhìn gương mặt trong gương, bạn có chắc đó là chính mình không? Một cô gái tóc dài rơi xuống bồn tắm, mắt cô ta nổ tung và lồi ra ngoài, làn da khô héo, nhăn nheo như người già cỗi. Cô ta hét lên. Bạn có nghe thấy không? Nào, nắm tay tôi, tôi sẽ đưa bạn bước vào vực sâu dưới lòng đất.', '2026-03-24 18:51:43', 'cats.jpg'),
(24, 'Kết Thúc Của Một Tội Buônn', 'Hàn Đàm Hạt Ảnh', 'Đô Thị, Trinh Thám', 9, 'Hoàn thành', 'Tôi là một kẻ buôn người, tôi thường đặt con mèo của mình ở cửa nhà người dân.</p><p>Tiếng mèo kêu sẽ thu hút chủ nhà mở cửa ra xem.</p><p>Chỉ cần họ mở cửa thì mục đích của tôi đã đạt được.</p><p>Phương pháp này chưa bao giờ thất bại, cho đến chiều nay, tôi phát hiện người mở cửa cho tôi...là một t.h.i t.h.ể!', '2026-03-24 18:55:18', 'horror.jpg'),
(25, 'Tứ Trùng Miên', 'Ân Tầm', 'Ngôn Tình, Đô Thị, Linh Dị, Trinh Thám, Sủng', 407, 'Hoàn thành', 'Hai năm sau, khúc nhạc “Ode to soul” chết chóc tái hiện…</p><p>Thế nên, anh là Lục Nam Thâm ư? Vị nhạc trưởng chính thức đầy thần bí?</p><p>Không, tôi là Trần Lẫm, tôi không biết gì về âm nhạc.</p><p>Anh là Trần Lẫm ư? Bên ngoài gọi anh là “Nham thạch”, sở trường bắt tóm bằng tay không.</p><p>Không, tôi là Thẩm Phục, một người già tuổi đã ngoài năm chục như tôi làm sao chơi được mấy môn thể thao đối kháng.</p><p>Anh là Thẩm Phục ư? Bên ngoài là một giáo sư, thực chất là một hacker cao thủ.</p><p>Không, tôi là Kiều Uyên, tôi ghét kẻ nào lừa gạt tôi.</p><p>Anh là Kiều Uyên, kỳ tài kinh doanh, cố chấp, lấy việc thao túng người khác làm niềm vui.</p><p>Không, tôi là Tư Niệm, nhưng tôi đã chết từ lâu lắm rồi.</p><p>Còn ai nữa?</p><p>Còn một người nữa.</p><p>Suỵt, cậu ta đang ngủ say, tuyệt đối đừng đánh thức cậu ta, cậu ta và người đứng sau lưng cậu ta rất nguy hiểm.</p><p>Có muốn phá giải bí mật khúc nhạc chết chóc không?</p><p>Hãy tìm Lục Nam Thâm, anh sẽ dùng âm thanh nói cho bạn biết chân tướng.</p><p>Sau đó, giết chết chúng ta.</p><p>…</p><p>Nhân vật:</p><ol class=\"wp-block-list\"><li>Lục Nam Thâm – Một nhạc trưởng bên ngoài hiền lành ngoan ngoãn thực chất là một con chó sói vs Hàng Tư – Một cô gái đi ngược lại triết lý õng ẹo, một nhân tài phát hiện “trà xanh”, một người có câu chuyện.</li><li>Lục Nam Thâm – Một người hướng nội vs Niên Bách Tiêu – Một người hướng ngoại.</li></ol><p>…</p><p>Đại ý:</p><p>Dùng “âm thanh” giải đáp bí ẩn, giải đáp một cách mới mẻ và chuẩn xác khái niệm người đa nhân cách. Nam nữ chính chữa lành cho nhau, yêu cuộc sống, yêu xã hội.', '2026-03-24 19:05:06', 'tháng 3 (6).jpg'),
(26, 'Cẩm Y Hành', 'Dã Anh Tây Qua', 'Ngôn Tình, Trinh Thám, Cổ Đại', 13, 'Hoàn thành', 'Thể loại: Nguyên sang, Ngôn tình, Cổ đại, HE, Tình cảm, Trinh thám, Nhẹ nhàng, Cải trang giả dạng, Duyên trời tác hợp, Thị giác nữ chủ.<br>- -<br><br>Ngày trước Trâu Lan Thanh là phó chỉ huy của Cẩm Y Vệ, vì bị thuộc hạ phát hiện ra thân phận mà vội vã rời khỏi kinh thành. Sau một giấc ngủ, nàng bàng hoàng nhận ra nàng đã trở thành thê tử của kẻ thù không đội trời chung???<br><br>Trong Cẩm Y Vệ, người mà Tề Vệ khinh thường nhất là Trâu Lan Thanh.<br><br>Người này trong ngoài không đồng nhất, giỏi luồn lách. Đặc biệt là vừa mới gia nhập Vệ Sở đã ngồi lên vị trí ngang hàng với hắn càng khiến hắn \"Phẫn uất bất bình\"<br><br>Nhưng dù tính toán thế nào, hắn cũng không ngờ được, hóa ra Trâu Lan Thanh là nữ nhân?<br><br>Tag: Duyên trời tác hợp, Huyền nghi trinh thám, Nữ giả nam trang<br><br>Tóm tắt một câu: Cuộc sống hôn nhân của nàng và kẻ thù truyền kiếp<br><br>Lập ý: Duyên phận trời định sẵn.', '2026-03-24 19:06:56', 'Full.io tháng 12 (73).jpg'),
(27, 'Thi Tỷ', 'Dạ Vô Thanh', 'Đô Thị, Huyền Huyễn, Linh Dị, Thám Hiểm, Khác', 42, 'Đang ra', 'Tôi tên là Tần Việt, làm việc trong ngành tang lễ, ngoài việc bán hương nến, giấy tiền, thỉnh thoảng tôi cũng giúp người ta thu liệm thi thể, cuộc sống trôi qua êm đềm, yên ả.<br><br>Thế nhưng, công trường trong thị trấn đột nhiên có người nhảy lầu, tôi và ông lão họ Khương ở nhà tang lễ phụ trách đến đó thu liệm thi thể.<br><br>Ban đầu, tôi cứ tưởng chỉ là một vụ nhảy lầu bình thường, nhưng không ngờ, lại đẩy tôi đến bờ vực cái chết.<br><br>Để bảo toàn tính mạng, ông nội tôi đành phải lập đàn làm phép, \"thỉnh sơn chiêu linh\"...<br><br>Trong núi ẩn hiện lăng mộ cổ, linh đường nửa đêm \"tử thi bật dậy\", đồng hoang \"bốn quỷ khiêng quan\", âm lộ \"trăm quỷ dạ hành\", tất cả mọi chuyện, đều liên quan đến sự xuất hiện của \"Thi Tỷ\"...', '2026-03-24 19:09:02', 'thitykWQAwqi.jpg'),
(28, 'Mắt Bồ Đề', 'Mạc Hề', 'Đô Thị, Thám Hiểm', 80, 'Hoàn thành', 'Hai mươi lăm năm trước, một bức bích họa mang tên “Rừng Đắc Nhãn” tại Đôn Hoàng mất tích đầy ly kỳ. Hai mươi lăm năm sau, một người mối lái đồ cổ tên Tiêu Khản bước vào miền biển cát vô biên này.<br><br>Khắc ra một con mắt lên cây bồ đề, Đức Phật có thể nhìn thấy hết thảy thế gian. Chiếm được những thứ không nên chiếm được sẽ mất đi thứ vốn không cần mất đi.<br><br>Mối lái đồ cổ x hướng dẫn viên du lịch miệng cười giấu lấy ruột đen.<br><br>Thám hiểm Tây Bắc + một ít huyền bí.', '2026-03-24 19:10:40', '403647249_708571581372959_8518505130930546519_n.png'),
(29, 'Phàm Tâm', 'Khuyết Danh', 'Ngôn Tình, Cổ Đại, Khác', 17, 'Hoàn thành', 'Ta là tiểu yêu mê luyến hồng trần, lại không biết sống ch ết trêu chọc một hòa thượng.</p><p>Kết quả… chơi quá trớn rồi.</p><p>Hắn mặt lạnh phá giới, bị ta kéo xuống khỏi đài mây.</p><p>Hủy thiên diệt địa, lửa giận cuộn trào. Nhốt ta vào Lôi Phong tháp, dồn ta vào góc tường.</p><p>Ta cứ nghĩ lần này hắn hẳn muốn gi ế t mình rồi.', '2026-03-24 19:13:38', '_Phàm Tâm.jpg'),
(30, 'Thẻ Bài Mật Thất', 'Điệp Chi Linh', 'Khoa Huyễn, Đam Mỹ, Trọng Sinh, Trinh Thám', 613, 'Hoàn thành', '<strong>Giới thiệu</strong><br /><br />Tiêu Lâu bất ngờ chết đi, sau khi sống lại thì bị đưa tới một thế giới hình thành từ những lá bài.<br /><br />Ở nơi đây mỗi lá bài đều đại diện cho một mật thất – <em>Giải mã bí ẩn; Mê cung cơ quan; Mạo hiểm sinh tồn; Quyết đấu khiêu chiến</em>. Độ khó của mật thất sẽ tăng dần, chỉ khi vượt qua mật thất cấp SS thì mới có thể trở về thế giới thực.<br /><br />Để trở về, Tiêu Lâu và bạn bè của mình đã bắt đầu hành trình sinh tồn trong mật thất đầy mạo hiểm và kích thích.', '2026-03-24 19:16:25', 'the-bai-mat-that.jpg'),
(31, 'Không Người Giám Thị', 'Tô Thành Ách Nhân', 'Action, Fantasy', 605, 'Hoàn thành', '<strong>Thể loại: </strong>CHỦ CÔNG<strong>,</strong> hiện đại, vô hạn lưu, hỗ sủng, huyền nghi, tương ái tương sát, đã từng là lão đại táo bạo lão ca ngang tàng công Lê Tiệm Xuyên X IQ cao tâm cơ dụ thụ Ninh Chuẩn, HE.</p><p><strong>Tác giả</strong>: Tô Thành Ách Nhân</p><p><strong>Biên tập:</strong> Lam Thương</p><p>Giới thiệu</p><p>Giữa hè năm 2050.</p><p>Một mạng lưới tinh thần bao trùm nửa lãnh thổ thế giới rền vang mở ra, kéo theo các thiên tài nổi tiếng ở mọi lĩnh vực vào một trò chơi có tên là Hộp ma Pandora.</p><p>Vào mùa đông cùng năm, Lê Tiệm Xuyên nhận nhiệm vụ đập vỡ Pandora và lấy con chip X.</p><p>Lê Tiệm Xuyên: Lúc tôi nhận được nhiệm vụ này, nội tâm của tôi rất kháng cự, nhưng cho đến khi nghe cấp trên nói làm nhiệm vụ này có thể tìm được bạn gái…</p><p>Cấp trên: Cậu thấy chưa, tôi có xạo cậu đâu. Chẳng phải cậu tìm được một cậu bạn trai có thể giả gái đấy ư? Gọi tắt là bạn gái còn gì.</p><p>Lê Tiệm Xuyên: …</p><p>…</p><p><strong>Ps:</strong> Thụ không phải nam giả nữ, đây chỉ là một phần thiết lập của trò chơi.</p><p><strong>Pps:</strong> Thụ đã biết công từ trước.</p><p>☆ <strong>Chú</strong><strong> ý</strong> (lời nhắn từ tác giả): công thụ là người, tính cách không hoàn mỹ, có khuyết điểm. Truyện có BUG, công khống thụ khống mời quay xe.', '2026-03-24 19:43:20', '202304sss06.jpg'),
(32, 'Cận Chiến Pháp Sư', 'Hồ Điệp Lam', 'Võng Du, Hài Hước', 565, 'Đang ra', '<b><i>Dịch giả:</i></b><i>WindDK, Akiko Chono (70 trở đi)<br></i><br>Một võ sư siêu cấp chơi game online nhưng bị người ta chọn lầm làm pháp sư. Với thói quen lấy cứng đối cứng, chơi xáp lá cà, hắn chỉ có thể đâm lao phải theo lao. Thế là hắn quyết định trở thành một pháp sư cận chiến, đem sức mạnh cùng pháp thuật kết hợp lại, mở ra một con đường hoàn toàn mới trong trò chơi.<br><br>Một tác phẩm của Hồ Điệp Lam, dẫn dắt người xem vào một thế giới của game online đầy thú vị cùng những trận cười sảng khoái.<br><br>***<br><br><b>Một số thuật ngữ Game trong truyện</b><br>Đối với những bạn không có chơi game online nhiều thì một số khái niệm trong game còn khá xa lạ.Mình xin giới thiệu với các bạn một số từ mà mình giữ nguyên, không dịch ra tiếng việt (vì nghe khá chuối):D<br><br>VR: Vitual Reality, là trò chơi thực tế ảo, mang mắt kính hoặc vào hộp đăng nhập, trực tiếp hóa thân thành nhân vật trong trò chơi, trải nghiệm mọi cảm giác thực tế nhất.<br><br>PK: Player Kill, đây là hành động người chơi cùng với người chơi khác đánh nhau, thường thì sẽ diễn ra ở khu vực luyện cấp. Nếu giết chết người chơi khác thì sẽ lên điểm PK, bị đỏ nick, bị bắt vào tù, bị phạt gì gì đó,...<br><br>BUG: lỗi game, ảnh hưởng trực tiếp đến trò chơi<br><br>GM: Game master, người quản lý trong trò chơi, thường sẽ vào xử lý một ít lỗi của game được người chơi báo cáo, cũng có thể xử phạt người chơi vi phạm quy định.<br><br>Report: Người chơi sẽ báo cáo cho GM về lỗi hoặc là có người chơi khác vi phạm quy định.<br><br>NPC: None-player character, chỉ những nhân vật không phải người chơi, thường sẽ do máy chủ điều khiển.', '2026-03-24 19:45:24', 'can-chien-phap-su.jpg');
INSERT INTO `truyen` (`Id_truyen`, `Ten`, `TacGia`, `TheLoai`, `TongSoChuong`, `TrangThai`, `GioiThieu`, `NgayTao`, `AnhBia`) VALUES
(33, 'Hỗn Nguyên Tu Chân Lục', 'Y Lạc Thành Hỏa', 'Tiên Hiệp, Đam Mỹ, Trọng Sinh, Khác', 972, 'Đang ra', '<p>[Văn Án]</p><p>Vì một viên Hỗn Nguyên Châu (混元珠) mà toàn bộ gia tộc Diệp gia đã bị diệt môn. Diệp Khiên (叶搴), thiếu tộc trưởng của Diệp gia, đã liều mạng chống lại nhưng cuối cùng vẫn không thể cứu vãn tình thế. Khi tỉnh lại, hắn nhận ra hồn phách đã quay trở về một ngàn năm trước, và viên Hỗn Nguyên Châu lại đang lơ lửng trong đan điền của hắn.</p><p>Người ta thường nói: \"Hỗn nguyên sinh hỗn độn, càn khôn hóa phù trần. Hào quang xuyên thấu hư vọng, phong lôi định cốt thân.\"</p><p>Diệp Khiên sẽ mượn sức mạnh từ thần vật này, nghịch thiên tu chân.</p><p>Về phần CP... Nếu tính kiếp trước: thiếu tộc trưởng Diệp gia và khôi lỗi khổng lồ của hắn. Nếu tính kiếp này: Diệp Thù (叶殊), phiên bản tái sinh của thiếu tộc trưởng, và Yến Trưởng Lan (晏长澜), người còn sống mà chưa bị luyện thành khôi lỗi.</p><p>Về các cảnh giới tu chân: Cảnh giới đại thể như sau: Luyện Khí, Trúc Cơ, Kết Đan, Nguyên Anh, Thần Du, Tụ Hợp, Huyền Quang, Thông Huyền, Đại Thừa.</p><p>Lưu ý: Đây là một bộ truyện tu chân dài, thể loại nâng cấp từ phàm nhân; Cả truyện là 1 vs 1, không có ngược, kết thúc viên mãn HE; phong cách của mình luôn là cưng chiều nhau, gần như có hai nhân vật chính nhé; (<em>chi3yamaha: đừng tin bả, trong Xuyên Việt Chi Tu Tiên bả ngược chết tiểu công luôn á =))</em>)Thiết lập thế giới là cường giả vi tôn, kẻ yếu sẽ bị chà đạp; Mọi người thảo luận hòa nhã nhé, đừng tranh cãi nha, chúng ta đều là những người hiểu lý lẽ mà, yêu thương mọi người!</p><p>【Lời thổ lộ】( của bà Y Lạc Thành Hỏa)</p><p>Nói với các vị một lời, tốc độ cập nhật của bộ truyện này sẽ tùy duyên, nhưng ta quyết không bỏ hố! Không bỏ hố! Không bỏ hố! Bản thân ta đã từng viết một bộ truyện dài đến hai triệu chữ, trừ khi gặp chuyện gì bất đắc dĩ lớn lao, bằng không ta tuyệt đối không bỏ hố. Những độc giả lão luyện theo dõi truyện của ta hẳn đều biết rằng, mỗi khi ta mở một trường thiên dài, nhất định sẽ đồng thời viết thêm truyện ngắn để điều tiết, rất thường thấy cảnh một trường thiên chưa xong đã kết thúc mấy truyện ngắn. Bởi vì thời gian viết trường thiên kéo dài, chỉ viết một bộ thì tư tưởng sẽ dễ trở nên cứng nhắc, mà nếu vấp phải cản trở trong quá trình viết thì cũng sẽ không có chút hứng thú nào, tâm tình chẳng vui vẻ chút nào.</p><p>Hiện tại bộ <em>Hỗn Nguyên Châu</em> cập nhật chậm, nguyên do chủ yếu là, thứ nhất, viết đã quá dài, có phần mệt mỏi; thứ hai, văn tu chân truyền thống khi viết cũng khá theo lối mòn, nếu muốn sáng tạo thì lại chẳng còn là thứ mà ta muốn viết nữa. Ta mở loại văn tu chân này là vì bản thân thích nó, vậy nên sẽ không cài cắm quá nhiều yếu tố mới vào, ít nhiều thiếu đi sự kích thích. Đừng tưởng chỉ có độc giả mới cần kích thích, tác giả cũng cần đó chứ... Hồi trước, khi ta viết trường thiên còn trẻ trung, dồi dào sức lực, có thể giữ vững song song cả hai bên ngày nào cũng viết mà chẳng áp lực gì. Nhưng giờ đã lớn tuổi rồi, viết thêm truyện ngắn để điều tiết mà còn phải giữ nhịp với các hố cũ thì cũng vất vả lắm, nếu không viết điều tiết văn thì mỗi ngày đều thấy bức bối, viết ra không biết thành cái thứ gì, vậy nên cũng đành tùy duyên mà cập nhật thôi.</p><p><strong>[Chú ý]</strong></p><p><em>Trong truyện có những lộn xộn với cảnh giới <strong>Kết Đan (结丹)</strong>. Thỉnh thoảng sẽ có tên gọi là <strong>Kim Đan (金丹)</strong>, chính tác giả cũng xài lẫn lộn giữa hai chữ này trong bản gốc tiếng Trung. Nhưng mà khi đọc nội dung của truyện sẽ thấy Kết Đan mới đúng. Tui cũng lười sửa, kệ đi hé.</em></p><p><em>Mấy ní thấy chỗ nào có chữ <strong>Cang Lam</strong> thì comment để chi3 sửa thành <strong>Thương Lam</strong> cho nó đúng nha.', '2026-03-24 19:48:00', '395256080-256-k555029.jpg'),
(34, 'Thanh Âm Mưa Rào', 'Tây Khê', 'Ngôn Tình, Light Novel, Đô Thị, Huyền Huyễn, Truyện Teen, Ngược, Khác, Nữ Phụ', 26, 'Hoàn thành', 'Tác giả: Tây Khê<br><br>Thể loại: Ngôn Tình, Truyện Ngược, Bách Hợp, Truyện Sủng, Đô Thị, Truyện Teen, Nữ Phụ, Light Novel, Truyện Khác, Huyền Huyễn...<br><br>Giới thiệu:<br><br>Lúc cô vừa tròn 1 tuổi, anh đã là chàng thiếu niên bước vào ngôi trường trung học.<br><br>Từ thuở bé, Dương Thính Vũ không những được bố mẹ yêu thương, mà còn được hết mực cưng chiều.<br><br>cô vẫn hay lẽo đẽo phía sau anh, tình yêu giữa họ như dòng nước dần vào đất, rốt cuộc nhận ra đã không thể vãn hồi.<br><br>Vì khúc mắc, sai lầm, bồng bột của tuổi trẻ đã vô tình khiến tình yêu của hai người đổ vỡ rạn nứt.<br><br>Anh đẩy cô rời xa, đi kết hôn với người con gái khác, nhưng lại tức giận giam giữ cô bên mình.<br><br>Bảy năm yêu hận, không ngừng tổn thương đối phương, dây dưa không dứt, liệu có lối thoát cho tình yêu của bọn họ?', '2026-03-24 19:50:10', 'thanh-am-mua-rao.jpg'),
(35, 'Tiểu Thư', 'Hữu Mao Nhi', 'Đô Thị, Bách Hợp, Khác', 85, 'Hoàn thành', '<p>Tiểu Thư<br />Tác Giả : Hữu Mao Nhi<br />Bản QT: khht07<br />Thể loại: Hiện đại, đô thị tình duyên, nhẹ nhàng, chữa lành<br />Nhân vật: Đinh Nghệ, Hải Linh, Chung Kỳ, Chu Mân, Mạc Hâm,...</p><p>Đinh Nghệ: Cô gái 22 tuổi, vừa chân ướt chân ráo rời quê lên Nam Châu lập nghiệp sau khi tốt nghiệp đại học. Tính cách nàng hiền lành, ngoan ngoãn nhưng cũng rất bướng bỉnh, cố chấp. Để tiết kiệm tiền thuê nhà, Đinh Nghệ cùng cô bạn thân Chung Kỳ thuê một căn phòng ở khu dân cư phức tạp. Vô tình, nàng gặp gỡ Hải Linh – người mà mọi người vẫn hay gọi là \"tiểu thư\" làm ở tiệm mát xa. Sau vài lần chạm mặt, Đinh Nghệ nhận ra mình cứ vô thức bị cô gái ấy cuốn hút.</p><p>Hải Linh: Nàng 25 tuổi, là \"tiểu thư\" của một tiệm mát xa. Lớn lên trong gia đình trọng nam khinh nữ, vì muốn em trai được ăn học tử tế và cha mẹ có cuộc sống tốt hơn, nàng đành chọn con đường này. Người nhà cầm tiền của nàng thì vui vẻ ra mặt, nhưng ánh mắt khinh thường của họ đã không ít lần cứa vào tim nàng. Rồi một ngày, nàng gặp Đinh Nghệ. Giữa cơn mưa tầm tã, Đinh Nghệ vội vã đưa ô che cho nàng. Rồi nhiều lần sau đó, Hải Linh lại thấy Đinh Nghệ dù rất sợ hãi nhưng vẫn hết lòng phóng sinh thằn lằn ở bồn hoa. Những điều ấy khiến Hải Linh bắt đầu có hứng thú với cô gái ngây thơ kia.</p><p>Một bên là Hải Linh dịu dàng, thấu hiểu, một bên là Đinh Nghệ thanh thuần nhưng bướng bỉnh. Hai người dường như thuộc về hai thế giới khác biệt, chẳng biết từ khi nào lại vô tình thu hút lẫn nhau.</p><p>Có lẽ ban đầu, Hải Linh chỉ đơn thuần bị cuốn hút bởi Đinh Nghệ – người con gái hội tụ tất cả những điều mà nàng khao khát. Nhưng rồi nàng chẳng hề nhận ra, dần dà, mỗi nụ cười nàng trao cho Đinh Nghệ, dù trong lòng buồn hay vui, hy vọng hay thất vọng, thì sự dịu dàng của nàng dành cho đối phương vẫn chưa từng vơi cạn.</p><p>Đó có phải là tình yêu không, Hải Linh không biết. Có lẽ, nàng chỉ muốn được một lần ngang bướng, sống theo ý mình mà thôi!', '2026-03-24 19:54:01', '399109390-256-k935575.jpg'),
(36, 'Sính Ác', 'Kim Yêu Đới', 'Đam Mỹ, Khác, Sủng', 103, 'Hoàn thành', '<p>Tên truyện: Sính Ác</p><p>Tác giả: Kim Yêu Đới</p><p>Nhân vật chính: Quý Ngưỡng Chân - Nhậm Đàn Chu</p><p>Lập ý: đoá hoa cao lãnh trở nên lạnh lùng điên rồ, ép yêu một Beta mỏng manh</p><p>Thể loại: đam mỹ nam x nam - ngọt sủng - ép yêu - HE - gương vỡ lại lành</p><p>Khác: Alpha x Beta</p><p>Giới thiệu vắn tắt: đoá hoa cao lãnh điên rồ nhưng luôn bình tĩnh đến đáng sợ x tiểu thiếu gia xinh xắn kiêu ngạo có thể nổi điên ở bất cứ đâu</p><p>__</p><p>Văn án</p><p>Dịch: CP88</p><p>-</p><p>Sau hai tháng bị nhốt, Quý Ngưỡng Chân học được ngoan rồi.</p><p>Cậu chủ động làm lành với Nhậm Đàn Chu, nhận sai, xin lỗi, làm nũng, lấy lòng, thậm chí hứa hẹn sẽ giúp đối phương trải qua kỳ phát tình.</p><p>Cậu dùng lời lẽ khéo léo, dỗ dành đến mức Nhậm Đàn Chu buông lỏng cảnh giác đưa cậu ra ngoài, cùng cậu xem buổi biểu diễn âm nhạc cực kỳ nhàm chán, nhưng ở thời điểm Nhậm Đàn Chu cần mình nhất, cậu không hề lưu luyến mà chạy.</p><p>Cậu trốn đi rất xa, xa đến mức tự cho rằng bản thân có thể yên tâm kê cao gối mà ngủ.</p><p>Thế nhưng khi cuộc sống dần đi vào quỹ đạo, sắp tự phục hồi xong, lại ở một tối muộn nào đó, bất ngờ không kịp phòng bị gặp lại ôn thần.</p><p>Nhậm Đàn Chu mặc một thân vest đắt tiền đứng trước cửa căn nhà đổ nát, như là đoá hoa thuỷ sinh bị đưa nhầm vào vũng bùn, vô cùng không ăn nhập với nơi này.</p><p>Lốc bia Quý Ngưỡng Chân xách trên tay bịch một tiếng rơi xuống.</p><p>Nhậm Đàn Chu nghiêng người chặn đường đi của cậu, sắc mặt thản nhiên, lên tiếng chào hỏi: \"Trùng hợp thế?\"</p><p>***</p><p>Bát Bát: Hihi lại được đào hố mới rồi (✿╹◡╹)</p><p>Tuy đã tự nhủ với bản thân đào rồi lấp từng hố một đi, cơ mà cuối cùng vẫn cứ là kìm lòng không đặng... (ಥ ͜ʖಥ)</p><p>Bộ này Bát đọc 10 chương ùi, ban đầu thụ là Beta, sau đó thì có tiêm thuốc các thứ (là ẻm tự muốn từ trước chứ không phải công ép nhen, tuy là có dụ một tí này kia :>>), rồi ẻm muốn phân hoá thành Alpha nhưng Bát đoán nếu thành công thì chắc là không được rồi :)))). Có xuất hiện omega, ờm, không biết có được tính là omega phụ không vì công từ đầu đến cuối trung trinh một mình thụ thôi, tính ra thì chính thụ mới là người quan tâm đến bé ấy, mà tui thấy bé nó đáng yêu lắm, tui nghĩ bé nó mà thích khéo lại thích thụ không chừng :>> Tóm lại tui đọc truyện tranh vấp nhiều công thúi nên thấy kiểu ép yêu này kia cũng hơi rén, ngồi đọc hết sạch 10 chương đã ra (chứ bình thường chắc đọc 3, 4 chương là chốt à), thấy có vẻ ok hợp gu hê hê</p>', '2026-03-24 19:56:15', '358241430-256-k616563.jpg'),
(37, 'Thanh Xuân Ngọt Ngào Và Cay Đắng', 'Thỏ Tử Hữu Điểm Đoàn', 'Ngôn Tình, Khác', 90, 'Hoàn thành', 'Một buổi chiều mùa thu, ánh nắng tựa như mật ong đã được pha loãng, dịu dàng và nồng đượm, xuyên qua những tán lá dày đặc của cây ngô đồng, đổ xuống mặt đất những đốm sáng loang lổ. Giữa sự giao thoa của ánh sáng và bóng tối, dường như thời gian cũng chậm bước tại nơi đây.<br /><br />  Chính vào lúc này, một cô gái tựa như tiên t.ử — U Lạc Thi, lặng lẽ bước vào vùng sáng tối mộng ảo này. Mái tóc dài đen bóng như gỗ mun mềm mại như lụa xõa trên đôi vai gầy manh khảnh, gió nhẹ thổi qua, lọn tóc nhẹ nhàng nhảy múa, như những nốt nhạc linh động đang bay bổng trong không trung.<br /><br />  Làn da trắng ngần hơn tuyết của cô dưới nụ hôn của ánh nắng ửng lên một lớp hào quang dịu nhẹ như trân châu, khiến người ta không kìm được muốn chạm khẽ vào, nhưng lại sợ làm vấy bẩn vẻ đẹp ấy. Đôi mắt trong vắt như nước kia tựa như hồ nước sâu không thấy đáy, lúc thì lóe lên tia sáng kiên cường, lúc lại để lộ nỗi u sầu phảng phất, dường như đang ẩn chứa vô số tâm tư không ai thấu hiểu.<br /><br />  Cô có vóc dáng mảnh mai, dáng người uyển chuyển, mặc một chiếc váy liền màu trắng giản dị, thắt một dải lụa xanh nhạt ngang eo, vạt váy lay động theo gió, tựa như cành liễu trong gió, nhẹ nhàng mà mong manh.', '2026-03-24 19:58:17', 'Thanh Xuân Ngọt Ngào Và Cay Đắng.jpg'),
(38, 'Đá Ngầm', 'Bất Nhượng Trần', 'Đô Thị, Đam Mỹ, Khác, Sủng', 67, 'Hoàn thành', 'Ngày hôm ấy, Lâm Dụ Chi đã bước lên tầng thượng, nơi mẹ Chu Thời Dã từng đứng. Chu Thời Dã đứng trong đám đông vây quanh phía dưới, im lặng đối diện với cậu ở khoảng cách sáu mươi bảy mét theo đường thẳng.</p><p>Lâm Dụ Chi từng ngỡ rằng Chu Thời Dã là cơn gió căng buồm, là ngọn sóng dập dềnh, là mặt trời chói chang trên hành trình của cậu.</p><p>Giờ đây, cuối cùng cậu mới hiểu, Chu Thời Dã chỉ là một rặng đá ngầm chết người ẩn sâu dưới mặt biển tĩnh lặng.</p><p>***</p><p><strong>Chu Thời Dã x Lâm Dụ Chi</strong></p><p>Câu chuyện éo le về một cậu ấm nhà giàu sa cơ lỡ vận.</p><p>HE, hiện thực, hàn gắn. Địa điểm có nguyên mẫu, địa danh hư cấu.', '2026-03-24 20:01:07', '97.jpg'),
(39, 'Không Còn Đường Quay Lại Nữa', 'Hy Hồng', 'Đô Thị, Linh Dị, Trọng Sinh, Trinh Thám', 146, 'Hoàn thành', 'Câu chuyện diễn ra tại một làng chài nhỏ ở tỉnh Sơn Đông – nơi đổi đời chóng mặt sau thời kỳ cải cách và mở cửa, được gọi là “Tiểu Thâm Quyến của miền Bắc”.</p><p>Giữa lúc kinh tế phồn thịnh, một giám đốc cấp cao của công ty địa phương nổi tiếng bất ngờ tử vong. Cùng lúc đó, trong làng lan truyền tin đồn rùng rợn: một cô gái từng bị bắt nạt đến chết đã quay trở lại dưới hình dạng “bóng ma áo trắng” để báo thù.</p><p>Nỗi sợ nhanh chóng bao trùm, đặc biệt là năm người có liên quan đến vụ bắt nạt năm xưa. Không lâu sau, nạn nhân thứ hai – một nữ chủ cửa hàng quần áo trẻ tuổi – chết vì đau tim sau khi bị “bóng ma áo trắng” xuất hiện dọa nạt trong đêm.</p><p>Cảnh sát lập đội đặc nhiệm điều tra chuỗi án mạng kỳ lạ này. Nhưng càng đi sâu, họ càng phát hiện một mối thù bị chôn giấu suốt nhiều năm đang dần trỗi dậy…</p><p>Cô gái năm xưa vì sao phải tự tử?<br />“Bóng ma áo trắng” là oan hồn trở về, hay chỉ là con người mang gương mặt quỷ dữ?<br />Sự thật rốt cuộc sẽ được phơi bày như thế nào?', '2026-03-24 20:04:24', '94.jpg'),
(40, 'Chiều Tà', 'Sơn Dã Niêm Hoa', 'Đô Thị, Đam Mỹ, Trọng Sinh, Sủng', 59, 'Hoàn thành', 'strong>Nhân vật chính</strong>: Giang Dã công x Tống Úc thụ <em>(Giang Dã mười năm sau)</em></p><p><strong>Tag</strong>: Yêu sâu sắc, truyện ngọt, học đường, chữa lành</p><p><strong>✿ GIỚI THIỆU ✿</strong></p><p>Năm thứ ba sau khi kết hôn, Giang Dã phát hiện Cố Hải ngoại tình.</p><p>Người đàn ông kia buông lời cay nghiệt, nếu muốn ly hôn thì phải tay trắng rời nhà.</p><p>Ba năm này, y từ cậu chủ nhỏ kiêu xa kiệt ngạo từng bước một biến thành dáng vẻ tối tăm hiện tại.</p><p>Giang Dã nhìn mặt mình trong gương, quầng thâm mắt dày đặc, ánh mắt tử khí nặng nề, có hơi không nhận ra mình.</p><p>Dẫu như thế, y vẫn kiên định kết thúc tình cảm bảy năm này.</p><p>Chỉ là chẳng ngờ rằng, sau khi ly hôn Giang Dã thế mà trùng sinh về mười năm trước.</p><p>Tỉnh lại trong thân xác một người khác.</p><p>Lúc ngẩng đầu, vừa vặn thấy bản thân lúc trước đang đưa món quà chuẩn bị đã lâu cho Cố Hải.</p><p>Y như phát điên, giật phắt đồ lại.</p><p>\"Không được đưa cho hắn ta!\"</p><p>Thiếu niên Giang Dã mặc đồng phục, nhíu mày rất khó chịu: \"Cậu là ai vậy?\"</p><p>[Tôi suy sút, chết lặng, tuyệt vọng, là ánh tà dương sắp biến mất, cho đến khi nhìn thấy cậu nơi cuối bóng tối.<br />Hóa ra –<br />Sự cứu rỗi của tôi, là bản thân tôi.]</p><p><strong>Một câu tóm tắt</strong>: Tôi yêu bản thân tôi</p><p><strong>Lập ý</strong>: Nắm lấy tự do. Trở thành ánh sáng.', '2026-03-24 20:17:19', 'tháng 2.26 (30).jpg'),
(41, 'Xuyên Thành A Cặn Bã Bị Năm Nhân Cách Của Ảnh Hậu Dây Dưa', 'Tửu Túy Đích Phúc Điệp/Phúc Điệp say rượu', 'Đô Thị, Bách Hợp, Khác', 95, 'Hoàn thành', '<p>Tác phẩm: Xuyên thành A cặn bã bị năm nhân cách của ảnh hậu dây dưa</p><p>Tác giả: Phúc Điệp say rượu (Tửu Túy Đích Phúc Điệp)</p><p>Chuyển ngữ: Gemini</p><p>Biên tập: Hoa Bạch Quang</p><p>Thể loại: bách hợp, hiện đại, xuyên sách, giới giải trí, ABO, đa nhân cách, đô thị tình duyên</p><p>Góc nhìn tác phẩm: chủ công</p><p>Giới thiệu</p><p>Mỹ nhân O tuyệt thế khuynh thành điên cuồng xấu xa và A lãnh đạm sạch sẽ phản nghịch.</p><p>Tư Cảnh Ngọc xuyên thành A cặn bã trong một quyển tiểu thuyết A cặn bã, nguyên thân cưỡng ép nữ chính - nữ thần cấp bảo vật của giới giải trí, Liễu Phạm.</p><p>Cưỡng ép đánh dấu, thậm chí còn play thai kỳ làm Liễu Phạm sảy thai, khiến Liễu Phạm không thể mang thai được nữa.</p><p>Lúc Tư Cảnh Ngọc xuyên đến, vừa đúng lúc một khắc trước khi nguyên thân lần đầu cưỡng ép đánh dấu Liễu Phạm.</p><p>Đối với tất cả những điều này, Tư Cảnh Ngọc bày tỏ: Không liên quan đến tôi, tôi chỉ muốn nằm yên thôi.</p><p>Sau đó, mọi chuyện lại càng ngày càng sai lệch…</p><p>Rõ ràng Liễu Phạm thanh thuần lạnh lùng, minh diễm kiêu sa, hệt như tiên nhân hạ phàm.</p><p>Thế nhưng, Liễu Phạm trong phòng học đại học lại lạnh như băng, cầm roi dạy học, hệt như một giảng viên cấm dục.</p><p>Omega tiến lên ép sát, cười lạnh nói: Nghe nói em muốn cưỡng ép đánh dấu cô?</p><p>Tư Cảnh Ngọc: ???</p><p>Đây có phải là lời mà người nói không?</p><p>Từ đó về sau, Tư Cảnh Ngọc đều sống trong cảnh nước sôi lửa bỏng mỗi ngày.</p><p>Liễu Phạm có tổng cộng năm nhân cách: ảnh hậu ghen tuông (chính), tổng tài thẳng tính, giảng viên điên cuồng, bác sĩ bệnh kiều, đại tỷ giang hồ dịu dàng. Mỗi nhân cách đều ôm mục đích khác nhau tiếp cận Tư Cảnh Ngọc.</p><p>Trong phòng bệnh tối tăm, nhân cách A của Liễu Phạm mặc áo blouse trắng, ngón tay lướt qua tuyến thể của Tư Cảnh Ngọc: Hay là cắt bỏ đi, chôn cùng đứa con đã mất của chúng ta?</p><p>Trong văn phòng, nhân cách B cười âm u, lộ ra chiếc răng nanh nhọn hoắt: Để tôi nuôi em, không tốt sao?</p><p>May mắn thay, Tư Cảnh Ngọc quen được một người bạn tri kỷ trên mạng.</p><p>Cho đến ngày hai người gặp mặt trực tiếp, trong căn bếp sáng sủa ấm áp của biệt thự, nhân cách C đè Tư Cảnh Ngọc lên bàn bếp: Cơm trong nồi, người trong lòng, dù là trên mạng hay ở đây, cưng muốn làm gì cũng được.</p><p>Sau đó, Tư Cảnh Ngọc nắm lấy cơ hội chuẩn bị bỏ trốn, lên máy bay chuẩn bị bay cao bay xa, lại gặp Liễu Phạm cong môi cười nói:</p><p>“Hóa ra chị chỉ là thế thân, đúng không?”</p><p>Vì Tư Cảnh Ngọc nhiều lần bỏ trốn, Liễu Phạm triệt để hắc hóa, đưa Tư Cảnh Ngọc cho người khác đùa bỡn.</p><p>Thế nhưng, vào lúc Tư Cảnh Ngọc sắp kết hôn với người khác, Liễu Phạm thấy hối hận rồi.</p><p>#Hỏa táng tràng không điển hình#</p><p>Tu la tràng tuy muộn nhưng sẽ đến.</p><p>#Chuyện này có chừng mực là được, nhưng có những Omega lại không hiểu thế nào là chừng mực#</p><p>Lưu ý:</p><p>* Song khiết, A không có cái ấy, thiết lập riêng khá nhiều.</p><p>* Nhân cách sẽ thống nhất, là kỳ tích y học Tấn Giang.</p>', '2026-03-24 20:19:19', '397960250-256-k457609.jpg'),
(42, 'Trái Đắng', 'Tuế Kiến', 'Ngôn Tình, Đô Thị, Ngược, Sủng', 55, 'Hoàn thành', '<p>Giới thiệu tóm tắt: Cô ấy chỉ là em gái tôi (Không hẳn thế)</p><p>–</p><p>Chuyện thầm yêu Lâm Tây Tân, Lương Tư Ý đã giấu được tất cả mọi người, nhưng chẳng thể ngờ cuối cùng lại bị Diêm Thận phát hiện.</p><p>Anh là anh trai trên danh nghĩa của cô, cũng là người mà Lương Tư Ý không muốn để biết chuyện này nhất.</p><p>Những lời đe dọa, trêu chọc và giễu cợt của Diêm Thận khi lấy bí mật đó làm cái cớ, trong mắt Lương Tư Ý thuở ấy, chẳng khác nào một sự khiêu khích vì mẹ cô đã chen chân vào gia đình anh.</p><p>Mãi cho đến cái đêm sau khi kỳ thi đại học kết thúc, một nụ hôn bất ngờ từ Diêm Thận mới khiến Lương Tư Ý bàng hoàng nhận ra.</p><p>Hóa ra, trên cái cây thanh xuân tuổi mười bảy của cô, lại kết đến hai trái quả đắng cay.</p><p>[Hai trái đắng, một trái héo tàn, một trái rụng rơi.]</p><p>Hình tượng: Bướng bỉnh x Kiêu ngạo / Luật sư x Diễn viên (Không hoàn toàn)<br />Phong cách: Đời thường bình dị / Phần đầu là vườn trường cấp ba / Phần sau có một chút nội dung giới giải trí.<br />⚠️ Lưu ý: Nam nữ chính không có quan hệ h.uyết thốn.g, không có các tình tiết thân mật quá mức trong giai đoạn nhân vật chưa trưởng thành.</p>', '2026-03-24 20:21:43', 'tháng 2.26 (29).jpg'),
(43, 'Thành Phố Sương Mù', 'Na Thù', 'Ngôn Tình, Đô Thị, Huyền Huyễn, Dị Năng, Phương Tây', 170, 'Hoàn thành', '<p><em>Thể loại:</em> Nguyên sang, Ngôn tình, Cận đại, Tình hữu độc chung, Trời sinh một cặp, Dị năng, Tây huyễn, Chính kịch, HE</p><p class=\"wp-block-paragraph\"><em>Văn Án</em></p><p class=\"wp-block-paragraph\">Đa Luân, năm 1772, mùa đông.<br /><br />Sau khi bảy người đàn ông lần lượt bỏ mạng dưới tay kẻ mổ bụng, nạn nhân thứ tám xuất hiện.<br /><br />Người chết thứ tám là một cô gái.<br /><br />Câu chuyện bắt đầu từ đây.</p><p class=\"wp-block-paragraph\">“Hắn từng yêu cô, như một thiếu niên rực cháy.” — Mê cung Nhân Sư</p><p class=\"wp-block-paragraph\">Tinh quái phương Đông VS. Thực thể siêu nhiên phương Tây</p>', '2026-03-24 20:23:49', 'tháng 2.26 (25).jpg'),
(44, 'Hạ Đến Mang Theo Thơ Tình', 'Thanh Chúc Kỉ Hứa', 'Ngôn Tình, Đô Thị, Khác', 16, 'Hoàn thành', '<p>🥂 TRUYỆN: Hạ Đến Mang Theo Thơ Tình</p><p>🥂 TÊN HÁN VIỆT: Hạ Nhật Tình Thi</p><p>🥂 TÁC GIẢ: Thanh Chúc Kỉ Hứa</p><p>🥂 CONVERT: Bụt</p><p>🥂 SỐ CHƯƠNG: 16 chương</p><p>🥂 EDIT + BETA: LenguyenngocThanh 🦋</p><p>🥂 THỂ LOẠI: Hiện đại, Tình chị em, Duyên trời tác hợp, Chức nghiệp tinh anh, Phi song khiết (Nam xử – Nữ phi), 1v1, HE</p><p>Giới thiệu<br />#Tình Chị Em #Mùa Xuân Thứ Hai</p><p>Tần Thi 26 tuổi, tháo chạy khỏi cuộc hôn nhân đầy bạo lực lạnh.</p><p>Ngày thứ hai sau khi ly hôn, Tần Thi ném đơn xin nghỉ việc vào mặt sếp, mua vé máy bay đi du lịch.</p><p>Cô tìm lại những chiếc váy từ vài năm trước, ghé tiệm cắt tóc cắt một mái tóc ngắn.</p><p>Chẳng phải chỉ là người tình mới thôi sao? Ngày trước cô chỉ cần ra ngoài dạo một vòng là có thể gặp cả tá.</p><p>Trên đường ra sân bay, cô bắt một chuyến xe đi chung, ghế phụ có một người đàn ông trẻ tuổi mặc sơ mi trắng đang ngồi.</p><p>Cô đứng bên cửa sổ phía anh nói chuyện với tài xế, mùi nước hoa hoa lan trong đêm khuya cứ thế xộc vào mũi anh…</p><p>“Vì chị, địa ngục tôi cũng đến.”</p><p>Lưu ý trước khi đọc:</p><p>Nữ chính không còn nguyên vẹn (không dành cho độc giả cực đoan về sự thuần khiết).<br />Tình chị em, chênh lệch 6 tuổi.</p>', '2026-03-24 20:25:38', '634911024_1330750992429534_8422083620050466069_n.jpg'),
(45, 'Dễ Vỡ', 'Nhược Thi An Hiên', 'Ngôn Tình, Đô Thị, Khácy', 15, 'Hoàn thành', '<p>🐚Tên truyện: Dễ vỡ</p><p>Tác giả: Nhược Thi An Hiên.</p><p>Độ dài: 15 chương</p><p>Thể loại: Nguyên sang, ngôn tình, đô thị, hào môn thế gia, gương vỡ lại lành, truy thê.</p><p>Dịch: Khoai Tây</p><p>Beta: The Atlamtis</p><p>Bìa: Bliebe – Nhà Nàng Mơ</p><p>🐚Giới thiệu:</p><p>Từ đồng phục đến váy cưới, Châu Miểu thích Trình Dương chín năm, hôm sinh nhật cô nhận được tin nhắn từ một người lạ.</p><p>Người đó gửi cho cô một bức ảnh, là ảnh ôm ấp thân mật, dưới ánh sáng mờ ảo, người đàn ông và người phụ nữ âu yếm lấy nhau.</p><p>“…” Bầu trời của Châu Miểu sụp đổ.</p><p>Tối đó, nhân việc uống rượu, Châu Miểu hỏi Trình Dương: “Người anh yêu nhất là ai?”</p><p>Người đàn ông mặc bộ đồ vest màu đen cao cấp được đặt may, cả người toả ra vẻ lạnh lùng và cấm dục, trên gương mặt với những đường nét như được điêu khắc tỉ mỉ là vẻ mặt rất ung dung, mắt phượng khẽ ngước lên: “Em.”</p><p>Đợi tới khi cô ra khỏi phòng bao, cô nghe thấy bạn thơ ấu của Trình Dương hỏi anh: “Không phải chỉ chơi qua đường thôi à, mày thích Châu Miểu thật à?”</p><p>Ngón tay với những khớp xương rõ ràng của Trình Dương cầm ly rượu lên, dáng vẻ ung dung tự tại: “Không thích.”</p><p>Châu Miểu đứng ở cửa: “…” Hoá ra, tất cả là giả.</p><p>—</p><p>Hôm ly hôn, ở Kinh Tây tuyết rơi nhiều, Châu Miểu mặc một chiếc váy mỏng manh đứng trong gió, Trình Dương đắm mình trong bóng tối, giọng nói anh trầm thấp: “Nếu giờ em hối hận thì anh sẽ coi như chưa có chuyện gì xảy ra.”</p><p>Ánh mắt Châu Miểu sáng rực, lạnh lùng nói: “Tôi không hối hận.”</p><p>“Em muốn ly hôn thật sao?”</p><p>“Phải.”</p><p>—</p><p>Mọi người đều tưởng Châu Miểu sẽ là người lụy nhất, vì dù sao trong cuộc tình này cô là người bỏ ra nhiều hơn, cô yêu Trình Dương hơn.</p><p>Không ngờ người lụy nhất lại là Trình Dương, trong đêm tuyết, anh quỳ trước mặt Châu Miểu, nức nở nói: “Miểu Miểu, xin em, hãy quay về bên anh.”</p><p>Tổng tài bá đạo lạnh lùng cấm dục vs Diễn viên múa xinh đẹp dịu dàng.</p>', '2026-03-24 20:26:57', '629990462_1327469139424386_8907957687578768655_n.jpg'),
(46, 'Âm Thầm Cháy Bỏng', 'Mộ Nghĩa', 'Ngôn Tình, Đô Thị, Ngược, Sủng', 75, 'Hoàn thành', '<p>Tags: Hào môn thế gia, gương vỡ lại lành, thiên chi kiêu tử, tinh anh giới nghiệp, truyện ngọt. </p><p>Gương vỡ lại lành | cưới trước yêu sau | ngọt ngào xen lẫn giằng co | chênh lệch thể hình bùng nổ.</p><p>VĂN ÁN</p><p>1.</p><p>Phó Lận Chinh, Thái tử gia của giới hào môn ở Kinh thành, cao mét chín, có cơ bụng săn chắc, có hình xăm Thủy Triều, là tay đua giải đua F1 nổi tiếng toàn cầu. Anh mang vẻ ngoài ngông nghênh, bất cần và luôn là tâm điểm ở bất cứ đâu.</p><p>Dung Vi Nguyệt, thiên kim tiểu thư xuất thân từ gia đình thư hương ở Kinh thành. Cô hiện điều hành một phòng studio về kỹ thuật \"Hoa ti khảm nạm\" (Hoa Ti Silicat - Pháp Lam - kỹ nghệ thủ công truyền thống). Với đôi mắt long lanh, vòng eo mảnh mai và chiếc sườn xám màu xanh thanh thiên, cô mang vẻ đẹp dịu dàng, thanh lãnh, nổi tiếng là người khó tiếp cận.</p><p>Phó Lận Chinh và Dung Vi Nguyệt, hai người tưởng chừng như đến từ hai thế giới hoàn toàn khác biệt, lại bất ngờ tái ngộ. Trong một lần gặp mặt, khi giáo sư còn trêu đùa: “Nguyệt Nguyệt từ nhỏ đã ngoãn, cậu đừng có mà trêu chọc con bé nhé”.</p><p>Ánh mắt Dung Vi Nguyệt khẽ động, người đàn ông đối diện lười biếng ngước lên nhìn: \"Thật sao?\"</p><p>Nhưng khi chỉ còn hai người, sự ngạo mạn và vẻ điềm tĩnh của anh lập tức tan biến.</p><p>Anh áp sát cô vào tường, phả hơi thở khàn khàn bên tai:</p><p>\"Dung tiểu thư đúng là ngoan ngoãn thật đấy. Nhưng hình như cô quên mất hồi đó ngồi trong lòng tôi vặn vẹo như thế nào rồi à?\"</p><p>\"...\"</p><p>Ký ức lập tức quay về những năm tháng tốt nghiệp cấp ba:</p><p>Dưới cái nóng oi ả, trong căn phòng đóng kín rèm, cô dựa vào vai anh mồ hôi đầm đìa, còn anh thì cắn tai cô một cách hư hỏng: \"Hết mệt chưa? Lại thêm lần nữa nhé?\"</p><p>2.</p><p>Thời cấp ba, Dung Vi Nguyệt chỉ chuyên tâm học hành, tránh xa những công tử nhà giàu như Phó Lận Chinh.</p><p>Nhưng anh lại cố tình cứ quấn lấy cô.</p><p>Cô mắng anh là đồ khốn, anh nhếch môi: \"Vậy thì xem em có cam tâm tình nguyện lọt vào tay một tên khốn như tôi không.\"</p><p>Anh sẽ bá đạo quấn lấy cô để đòi hôn, cũng sẽ dịu dàng dỗ dành cô uống thuốc, chở cô đi khắp nơi, lên đỉnh núi ngắm sao trời.</p><p>Rầm rộ, mãnh liệt, nhưng cuối cùng cũng chỉ như hoa quỳnh nở chốc lát.</p><p>Cô dứt khoát bỏ anh mà đi, không hề quay đầu lại.</p><p>Nhiều năm sau tại buổi họp mặt cựu học sinh, nhiều người thầm bàn tán liệu hai người có thể nối lại duyên xưa. Nhưng họ chỉ thấy vị thái tử gia đang ở đỉnh cao danh vọng vẫn lạnh lùng, cao không thể chạm tới, ánh mắt thỉnh thoảng liếc nhìn cô cũng hờ hững không chút gợn sóng.</p><p>Mọi người đều nói:</p><p>Phó Lận Chinh kiêu ngạo như vậy, làm sao có thể quay đầu lại chứ.</p><p>Không hề ai hay biết, đêm đó anh đã say mèm.</p><p>Trong bãi đậu xe, Dung Vi Nguyệt bị anh ép vào chiếc Pagani màu đen bạc. Đôi mắt người đàn ông đỏ ngầu, khản giọng: \"Dung Vi Nguyệt, ở chỗ em, lão tử chính là một con chó. Em còn muốn đùa giỡn tôi bao nhiêu lần nữa?\"</p><p>Phó Lận Chinh không có điểm yếu. Nếu có, thì đó chính là người tên Dung Vi Nguyệt. Tình yêu không thể giấu được, chỉ cần cô liếc nhìn một cái, ngọn lửa bị kìm nén kia sẽ bùng cháy dữ dội, im lặng nhưng bỏng cháy.</p><p>3.</p><p>Sau này vào một dịp Tết Trung thu, Dung Vi Nguyệt tăng ca tại studio. Phó Lận Chinh vừa kết thúc cuộc đua ở nước ngoài, đã xuất hiện trong màn đêm.</p><p>\"Đến Trung thu rồi, không phải nên về nhà ngắm trăng sao?\"</p><p>\"Nhưng mà trăng ở nước ngoài cũng có thể ngắm được mà.\"</p><p>Phó Lận Chinh cong môi, ôm lấy cô và đặt một nụ hôn:</p><p>\"Đây là trăng của tôi.\"</p><p>Cặp đôi: Thái tử gia bất cần, ngông cuồng x Mỹ nhân cổ điển dịu dàng, thanh lãnh.</p><p>Nghề nghiệp: Tay đua xe x Người thừa kế di sản phi vật thể.</p><p>【Tiểu kịch trường】</p><p>Phó Lận Chinh tuổi đời còn trẻ đã đăng quang vô địch thế giới, khiến hàng ngàn cô gái say mê, nhưng tiếc là tin kết hôn sớm đã được tung ra. Cả mạng xã hội đều đoán Phó phu nhân là ai. Sau đó, Phó Lận Chinh tổ chức một hôn lễ thế kỷ. Có người đăng ảnh: Trên đảo Santorini ở Hy Lạp, người đàn ông cúi người ôm hôn cô dâu, pháo hoa rực rỡ nở trên nền mây màu cam đỏ, lãng mạn và hoành tráng.</p><p>Cả mạng xã hội rung động.</p><p>Ngày hôm đó, Phó Lận Chinh cập nhật một dòng trạng thái ghim: 【Giành được chức vô địch không phải vinh dự cao nhất đời tôi, cưới được em mới là @Dung Vi Nguyệt.】</p><p>Từ mười tám tuổi đến giờ, cô là mối tình đầu, cũng là tình yêu duy nhất cả đời này.</p>', '2026-03-24 20:28:02', 'tháng 1.26 (51).jpg'),
(47, 'Diêu Viễn Chẳng Xa Xôi', 'Lục Hữu Gian', 'Ngôn Tình, Đô Thị, Khác', 104, 'Hoàn thành', '<strong>Tên truyện:</strong> Diêu Viễn chẳng xa xôi.</p><p class=\"wp-block-paragraph\"><strong>Tác giả:</strong> Lục Hữu Gian.</p><p class=\"wp-block-paragraph\"><strong>Thể loại:</strong> Ngôn tình, hiện đại, công sở, tinh anh trong nghề.</p><p class=\"wp-block-paragraph\"><strong>Độ dài:</strong> 104 chương + 06 ngoại truyện.</p><p class=\"wp-block-paragraph\"><strong>Xếp chữ:</strong> Trầu.</p><p><span id=\"more-737\"></span></p><p class=\"wp-block-paragraph\"><strong>Giới thiệu:</strong></p><p class=\"wp-block-paragraph\">Diêu Viễn dùng thành quả nghiên cứu thời làm Tiến sĩ để góp vốn mảng kỹ thuật, thành lập công ty công nghệ lõi Ba Quang, chuyên về các ngành công nghiệp mũi nhọn.</p><p class=\"wp-block-paragraph\">Thương Kha là một nhà đầu tư theo trường phái giá trị, để mắt đến Ba Quang và có ý định rót vốn, nhưng phía Ba Quang khéo léo từ chối vì họ không thiếu tiền. Một lần nọ, tình cờ thấy Diêu Viễn đang thuyết trình tại hội nghị thượng đỉnh, anh nghĩ bụng trong túi vẫn còn danh thiếp, chi bằng làm quen một chút. Nào ngờ bài diễn thuyết vừa dứt, anh chỉ kịp nhìn thấy một bóng lưng vội vã rời đi.</p><p class=\"wp-block-paragraph\">Trên chuyến bay từ Thượng Hải đi Athens, hai người ngẫu nhiên ngồi cạnh nhau. Anh hỏi Diêu Viễn có phải đi Santorini nghỉ mát không, cô trả lời không phải, đi buôn hàng xách tay. Anh ngỏ ý xin WeChat để tiện mua hàng, cô lại bảo điện thoại hết pin.</p><p class=\"wp-block-paragraph\">Tại Santorini, Diêu Viễn được bạn rủ chơi Poker và lại đụng độ Thương Kha đến muộn. Anh đưa cô về khách sạn, trên đường đi cô nhận một cuộc điện thoại, biết tâm trạng cô không tốt, anh chủ động đưa cô đi hóng gió.</p><p class=\"wp-block-paragraph\">Đêm khuya, đường phố, đua xe, nam nữ độc thân, đất khách quê người, nhịp tim dồn dập… tất cả những yếu tố tạo nên sự mập mờ đều đã hội tụ đủ. Hormone phái nữ mạnh mẽ thôi thúc cô vươn xúc tu thăm dò, giữ chặt lấy cổ tay anh, nhẹ nhàng vuốt ve những đường nét cơ bắp đều đặn, rắn rỏi trên cánh tay ấy và thốt lên: “Anh thơm quá, ngay từ lần đầu gặp mặt tôi đã muốn chạm vào anh.”</p><p class=\"wp-block-paragraph\">Anh đáp: “Lần đầu gặp em, tôi đã muốn đưa tiền cho em.”</p><p class=\"wp-block-paragraph\">Sau khi về nước, cô đồng ý hẹn hò, cô nói: “Tôi đã lùi một bước rồi, có phải anh cũng nên lùi một bước, thỏa mãn đôi chút dục vọng của tôi không?”</p><p class=\"wp-block-paragraph\">Anh hỏi: “Em muốn tôi thỏa mãn em thế nào?”</p><p class=\"wp-block-paragraph\">Cô đáp: “Lái xe đến chỗ không có người đi.”</p><p class=\"wp-block-paragraph\"><strong>(*) Chú thích tên truyện:</strong></p><p class=\"wp-block-paragraph\">Tên gốc “Dao Viễn Bất Viễn” (遥远不远) là một cách chơi chữ đồng âm của tác giả.</p><p class=\"wp-block-paragraph\">Từ “Dao viễn” (遥远) có nghĩa là xa xôi, phát âm giống với tên nữ chính “Diêu Viễn” (姚远).</p><p class=\"wp-block-paragraph\">Tựa đề mang hai tầng nghĩa: Vừa ám chỉ khoảng cách địa lý tuy xa mà gần, vừa ẩn ý rằng Diêu Viễn thực ra không hề xa cách đến thế, hoặc đơn giản là chẳng hề xa xôi.</p>', '2026-03-24 20:30:24', '629232404_1327466376091329_5774085349545472106_n.jpg'),
(48, 'Bến Bờ', 'Duy Tửu', 'Ngôn Tình, Đô Thị, Khác', 95, 'Hoàn thành', '<p><strong>Số chương:</strong> 95 chính văn</p><p><strong>Tag:</strong> Cường – cường, đô thị, tình cảm, hiện thực</p><p><strong>Văn án: </strong></p><p>“Anh ta tối nay không về đâu.”</p><p>“Sao anh biết?”</p><p>“Em nói xem?”</p><p>Tưởng Viên nhìn cô, rõ ràng biết rõ mà còn hỏi, rồi đương nhiên nói: “Tối nay tôi đến tìm em.”</p><p>Tất cả sai lầm đều bắt đầu từ đêm đó. Cô đi đón người chồng say rượu của mình, nhưng lại tình cờ chạm mặt cấp trên của chồng trước.</p><p>Lục Nghê cảm thấy hoàn toàn bất lực. Cô chỉ là một người phụ nữ tay trắng, chẳng có gì để bấu víu, chỉ có thể để mặc cuộc đời đẩy đưa.</p><p><strong>P.S:</strong> Nhân vật chính không ngoại tình trong thời gian hôn nhân.</p><p><strong>Nhân vật chính: </strong>Lục Nghê, Tưởng Viên.</p><p><strong>Một câu tóm tắt:</strong> Sau khi con thuyền đã chìm từ rất lâu.</p><p><strong>Chủ đề:</strong> Cuộc đời không phải là một câu hỏi trắc nghiệm chỉ có một đáp án.</p>', '2026-03-24 20:31:46', '615177425_1303474411823859_2209363629544512266_n.jpg'),
(49, 'Hời Hợt', 'Vu Triết', 'Đô Thị, Đam Mỹ, Ngược, Sủng', 109, 'Hoàn thành', '<p><strong>Thể loại: </strong>Nguyên sang, Đam mỹ, Hiện đại , HE , Tình cảm , Hỗ công , Song thị giác</p><p><em>Phàn Quân x Trâu Dương</em></p><p><em>Này, đá quán.</em></p><p><em>Đời người có tình yêu thì mọi nẻo đường đều bằng phẳng.</em></p><p><strong>Giới thiệu </strong></p><p>Một nam sinh đại học thuộc phái diễn xuất với phong cách cổ trang và bạn trai người máy bị điếc một bên tai do hắn đá quán mà có được.</p><p>✩Hỗ công</p><p>✩HE</p><p><strong>Từ khoá tìm kiếm:</strong> Nhân vật chính: Phàn Quân, Trâu Dương | Nhân vật phụ: | Khác:</p><p><strong>Tóm tắt một câu:</strong> Này, đá quán.</p><p><strong>Chủ đề:</strong> Đời người có tình yêu thì mọi nẻo đường đều bằng phẳng.</p>', '2026-03-24 20:33:58', 'tháng 2.26 (19).jpg'),
(50, 'Đoá Tường Vi Rung Động', 'Hỉ Phúc', 'Ngôn Tình, Đô Thị, Ngược, Sủng', 109, 'Hoàn thành', '<p><em>Giới thiệu</em></p><p>Năm mười tám tuổi, Hứa Niệm Sênh trót đem lòng yêu bạn của cậu mình, một người đàn ông lớn hơn cô vài tuổi. Ngày nhận được kết quả thi đại học, cô gom hết can đảm thổ lộ lòng mình với anh nhưng lại bị anh phũ phàng từ chối. </p><p>Bẵng đi ba năm, hai người tình cờ gặp lại nhau. Người đàn ông cô từng đem lòng thương mến, là ánh trăng sáng trong lòng cô nay đã trở thành một vết đen trong quá khứ mà cô muốn quên đi. Cô cảm thấy xấu hổ, muốn chứng tỏ mình không còn tơ vương gì đến anh nữa, chủ động lên tiếng: “Chú Tống.”</p><p>Người đàn ông khựng lại, sau đó lặp lại lời cô: “Chú Tống?”</p><p>Hứa Niệm Sênh tỏ ra lễ phép: “Chú bằng vai phải lứa với cậu của cháu mà.”</p><p>Người đàn ông cười khẩy: “Được thôi.”</p><p>Nhưng sau đó, vận xui của Hứa Niệm Sênh tới rồi. Người hướng dẫn sắp xếp cho cô đi thực tập, không ngờ vừa vào công ty mới phát hiện ra ông chủ lại là quá khứ không muốn nhắc đến của cô. </p><p>“…”</p><p>Kỳ thực tập này cũng không nhất thiết phải làm nữa.</p><p>—</p><p>Hứa Cẩm Ngôn hay tin cháu gái mình tới công ty của người anh em tốt của anh ấy thực tập liền gửi gắm nhờ đối phương chăm sóc. Đối phương đồng ý, còn nói lời giữ lời. Không chỉ giúp cô gái nhỏ thuê nhà, ngay cả khi cô ốm anh cũng tranh thủ thời gian tới chăm sóc, trong công việc lại còn cho không ít cơ hội rèn luyện năng lực. Hứa Cẩm Ngôn cảm thấy mình quả là có mắt nhìn người, người anh em tốt của anh ấy quả thực rất đáng. </p><p>Sau đó, người anh em tốt của anh ấy gặp phải một chuyện khó xử. Đối phương đang theo đuổi một cô gái. Hứa Cẩm Ngôn, với tư cách là người đàn ông đã có gia đình, liền nhiệt tình chia sẻ kinh nghiệm theo đuổi vợ cho người ta. </p><p>Sau một chuyến công tác trở về, Hứa Cẩm Ngôn ghé qua thăm cháu gái, bấm chuông cửa một lúc, cửa vừa mở đã nhìn thấy người anh em chí cốt của mình ăn vận chỉnh tề đứng ngay ở cửa lúc nửa đêm. </p><p>Hứa Cẩm Ngôn: “…”</p><p>Ngốc quá đi mất, mình coi người ta như anh em thân thiết, nhưng nào biết đối phương lại muốn gọi mình là cậu.</p>', '2026-03-24 20:35:11', 'tháng 1.26 (48).jpg'),
(51, 'Chạy Như Bay Về Phía Người', 'Kiến Kình Lạc', 'Đô Thị, Bách Hợp, Sủng', 81, 'Hoàn thành', '<p>Cả bệnh viện từ trên xuống dưới đều biết, bác sĩ Lục Gia Hòa không chỉ y thuật tinh thông, ngoại hình xuất chúng, mà còn đối xử với bệnh nhân vô cùng ôn nhu kiên nhẫn. Nhưng gần đây, cô lại vì một bệnh nhân nghịch ngợm mà thực sự lên cơn đau đầu.</p><p>Bệnh nhân này chẳng chịu nghe lời dặn của bác sĩ, không chịu nghỉ ngơi như lời dặn, còn mấy lần trốn khỏi phòng bệnh. Quá đáng nhất là lần nào cũng bị cô bắt được!</p><p>\"Kỷ Nhân, không được uống rượu ở quán bar, theo tôi về ngay!\"</p><p>\"Kỷ Nhân, chân cẳng còn bó bột thế này mà nhảy nhót cái gì ở quảng trường, theo tôi về ngay!\"</p><p>\"Kỷ Nhân, theo tôi về bệnh viện!\"</p><p>\"Kỷ Nhân!\"</p><p>Kỷ Nhân gần đây thực sự xui xẻo mà. Đầu tiên là bị người ta trả thù phải vào bệnh viện, rồi lại bị bác sĩ Lục \"quan tâm\" đặc biệt, lần nào trốn đi quán bar tán gẫu cũng bị cô \"ân cần\" dẫn về bệnh viện.</p><p>Nàng đi hẹn gặp khách hàng, đang tận dụng mối quan hệ với mẹ khách hàng thì đột nhiên bị bác sĩ Lục \"ân cần\" dẫn về bệnh viện.</p><p>Nàng đi ăn cơm bên ngoài thôi mà cũng đột nhiên bị bác sĩ Lục \"ân cần\" dẫn về bệnh viện.</p><p>Kỷ Nhân: ??? Tà đạo thật sự!</p><p>Cho đến một ngày, Lục Gia Hòa nói với nàng: \"Kỷ Nhân, em cứ như vậy thì tôi không quan tâm đến em nữa đâu.\"</p><p>Kỷ Nhân như sét đánh, quay đầu lại mới phát hiện ra, không biết từ lúc nào, trong tim mình đã nở một đóa hoa mang tên Lục Gia Hòa.</p><p>\"Bác sĩ Lục, chị làm ơn tiếp tục quan tâm em đi mà.\"</p><p>Các đồng nghiệp thường xuyên nhắc đến với Lục Gia Hòa về vị bệnh nhân nghịch ngợm này. Có người nói tối hôm qua thấy Kỷ Nhân ở bồn hoa phía sau đang hôn ai đó, hỏi cô có biết là ai không.</p><p>Lục Gia Hòa: \"...Là tôi.\"</p><p>------</p><p><strong>Tổ hợp định mệnh:</strong> Búp bê vải ôn nhu xinh đẹp trong bình mật X Mèo hoang sinh trưởng tự do bôn ba khắp nơi</p><p><strong>Tóm tắt một câu:</strong><br />Chị là tháng tư nhân gian,<br />Em là Đông Bắc địa tam tiên.</p><p><strong>Chủ đề:</strong> Tích cực lạc quan, khỏe mạnh hướng về phía trước</p>', '2026-03-24 20:36:36', 'tháng 2.26 (14).jpg'),
(52, 'Vòng Lặp Mối Tình Đầu', 'Dung Vô Tiên', 'Ngôn Tình, Đô Thị, Sủng', 69, 'Hoàn thành', '<p>Thể loại: Ngôn tình, Hiện đại, Nhẹ nhàng, Tình hữu độc chung, Hào môn thế gia, Yêu thầm, HE</p><p>Văn án:</p><p>Vào kỳ nghỉ hè, Ôn Chước Hoa đi làm thêm ở một tiệm trà sữa, nằm ngay cạnh một tòa cao ốc văn phòng cao cấp. Công việc này chỗ nào cũng tốt, ngoại trừ một điều…</p><p>Chủ nhân của tòa cao ốc ấy, Lộ Kinh Đường, chính là “ánh trăng sáng” mà cô từng thầm thích hồi cấp ba.</p><p>Thời thiếu nữ chưa hiểu chuyện, cũng chạy theo trào lưu “thầm thương trộm nhớ”. Dù đã sớm hết thích, nhưng ít nhiều vẫn thấy ngượng ngùng.</p><p>Ngượng ngùng hơn nữa là cô bạn thân còn cố tình trêu chọc, viết hẳn một fic đồng nhân ngớ ngẩn.</p><p>Mà điều xấu hổ nhất chính là file đó bị rò rỉ ngoài ý muốn, và một tài khoản marketing hạng ba… đã tin sái cổ.</p><p>Ngày hôm sau, bắt đầu rộ lên tin đồn tổng giám đốc Lộ và Ôn Chước Hoa từng là bạn học.</p><p>Rồi hôm sau nữa, tin đồn biến thành tổng giám đốc Lộ đang theo đuổi Ôn Chước Hoa.</p><p>Rồi rồi hôm sau nữa…</p><p>Nhiều năm không gặp, khi tái ngộ, Lộ Kinh Đường cứ có cảm giác cô bạn học tên Ôn Chước Hoa này đặc biệt ghét mình.</p><p>Anh đã tự kiểm điểm không biết bao lần, nhưng vẫn không hiểu nổi rốt cuộc mình đã chọc gì cô ấy giận.</p><p>Chỉ là càng kiểm điểm, anh lại càng cảm thấy hứng thú với Ôn Chước Hoa.</p><p>Phòng PR của công ty như thường lệ báo cáo, đính kèm ảnh chụp bài viết từ tài khoản marketing hạng ba, tiêu đề: [Người thừa kế hào môn số một ráo riết theo đuổi mỹ nữ Đại học Nam, hai người là bạn học cấp ba, xa cách lâu ngày lại bùng cháy tình cảm!]</p><p>Rồi xin chỉ thị: “Chúng tôi đã xóa một số tin đồn thất thiệt như thường lệ…”</p><p>Lộ Kinh Đường vừa chọn xong bó hoa muốn gửi hôm nay, nghe vậy liền uể oải ngắt lời: “Công ty chúng ta, giờ đến cả tin thật cũng phải xóa à?”</p><p>Mọi người đều cảm thán Lộ Kinh Đường theo đuổi người ta một cách hoành tráng. Đến chính Lộ Kinh Đường lúc say cũng thẳng thắn thừa nhận, Ôn Chước Hoa trước kia ghét anh như vậy, đương nhiên là anh đã phải động lòng trước.</p><p>Chỉ là một ngày nọ, anh lục lại được một khoản chuyển khoản, thời gian đúng vào năm hai người gặp lại.</p><p>Trên giấy chuyển khoản còn có lời nhắn của Ôn Chước Hoa khi đó không còn một xu dính túi: “Trả hết nợ cho anh rồi, hình như…ngay cả lý do để lưu luyến cũng chẳng còn.”</p><p>“Vòng lặp mối tình đầu” có nghĩa là con người quả thật sẽ yêu đi yêu lại cùng một người ở những thời điểm khác nhau.</p><p>Nhưng không sao, anh sẽ vượt qua thời gian, để cảm nhận được em.</p><p>Lâu ngày gặp lại, cô gái từng thầm yêu chàng trai, sau khi tái ngộ là chàng trai theo đuổi cô gái.</p>', '2026-03-24 20:38:25', 'tháng 2.26 (11).jpg'),
(53, 'Thực Vị', 'Thất Nguyệt Thất Nhạc', 'Ngôn Tình, Đô Thị, Khác', 61, 'Hoàn thành', '<p>Thực Vị<br />Tác giả: Thất Nguyệt Thất Nhạc<br />Thể loại: hiện đại, 419, tình yêu của nam nữ trưởng thành, thực tế, cứu rỗi, ẩm thực, HE.</p><p>Độ dài: 52 chương + 9 ngoại truyện</p><p>Edit: Lynn (Ngoài ra còn có sự hỗ trợ từ QT, Google, Baidu)</p><p>Tôi chỉ muốn chú ý đến “cái mã ngoài”, nhưng anh lại khiến tôi hiểu thế nào là “thực tủy biết vị”.</p><p>Giới thiệu<br />Trần Túy không ngờ rằng đối tượng one night stand (tình một đêm) ở quán bar hôm đó lại chính là quản lý nhà hàng sắp làm việc chung với mình, Tần Phong.<br />May mắn thay, Tần Phong và Trần Túy đều là người công tư phân minh, nên chuyện đêm đó đã trở thành bí mật.<br />Sau này, họ phối hợp ăn ý, trước mặt người khác thì hòa thuận, nhưng sau lưng lại có thêm nhiều bí mật.<br />Rồi sau đó, mới phát hiện mọi thứ yên bình đều là cái bẫy do hồ ly giăng ra.<br />Tần Phong đã quên thỏa thuận dưới giường giữa cả hai, trong lúc thỏa mãn vẫn không quên nhắc nhở Trần Túy.<br />“Chef, món đó chỉ được làm cho một mình tôi ăn thôi…”<br />Nhân vật chính:</p><p>Nữ chính Trần Túy tự do, ngại giao tiếp, ngại chốn đông người, thiếu thốn tình cảm, mạnh mẽ kiên cường.<br />Nam chính Tần Phong tỉ mỉ, sành sỏi, cố chấp trong chuyện tình cảm, đã cáo còn điên.<br />Lời tác giả: Ai sẽ yêu một kẻ điên có vẻ ngoài đứng đắn.<br />Giải nghĩa:</p><p>Tên truyện 食味 xuất phát từ thành ngữ “thực tủy biết vị/食髓知味”: nghĩa đen là nếm đến tủy rồi thấy vị ngon nên lại muốn ăn nữa. Nghĩa bóng ý chỉ sau khi đã làm việc gì đó và thấy được “mùi ngon” thì trở nên tham lam, làm được một lần rồi lại muốn làm tiếp.</p>', '2026-03-24 20:41:07', '603800468_1291877896316844_3528449045488729555_n.jpg'),
(54, 'Ngọ Hải Tụng Lễ', 'Phù Cẩn', 'Ngôn Tình, Đô Thị, Khác', 31, 'Hoàn thành', '<h3 class=\"wp-block-heading\"><strong>Giới thiệu</strong></h3><p class=\"wp-block-paragraph\"><em>Giải thích tên truyện: Ngọ là tên gọi ở nhà của nữ chính. Hải là biển, cũng chỉ nam chính. Chữ Tụng (颂) mang nghĩa là: ca tụng, khúc ca, tán dương, tôn vinh. Lễ là tên của nam chính.</em></p><p class=\"wp-block-paragraph\">Nhân vật chính: Thời Tiên x Tống Hoài Lễ</p><p class=\"wp-block-paragraph\">Thể loại: Hiện đại, một lòng một dạ, vườn trường, chính kịch, cữu rỗi, bản tình ca bên lề, không nguyên mẫu, BE.</p><p class=\"wp-block-paragraph\">Độ dài: 31 chương</p><p class=\"wp-block-paragraph\">Tình trạng: Chuyển ngữ full</p><p class=\"wp-block-paragraph\">Ảnh bìa: kehao</p><h3 class=\"wp-block-heading\"><strong>Văn án</strong></h3><p class=\"wp-block-paragraph\"><em>“Anh là khoảng biển giữa đêm khuya ẩm ướt, cũng là bí mật duy nhất của riêng tôi.”</em></p><p class=\"wp-block-paragraph\">—</p><p class=\"wp-block-paragraph\">Đêm trước kỳ thi đại học, Thời Tiên suy sụp tinh thần. Tối đó cô vùi mình trong chăn khóc thầm, không kìm được mà gọi điện đến trung tâm hỗ trợ tâm lý khẩn cấp: “Xin anh… anh có thể mô phỏng giọng của người nhà tôi, nói với tôi một câu được không?”</p><p class=\"wp-block-paragraph\">Đến ngày hôm sau cô mới phát hiện mình đã gọi nhầm số, nhưng vào khoảnh khắc ấy, đầu dây bên kia quả thật có người đáp lại: “Bé con, chúc em ngày quốc tế thiếu nhi vui vẻ.”</p><p class=\"wp-block-paragraph\">Vài tháng sau, cô thi đỗ vào ngôi trường mơ ước. Nghĩ đi nghĩ lại, cô vẫn ôm tâm thế như đá chìm xuống biển mà gửi cho số điện thoại xa lạ ấy một tin nhắn: <em>Em đỗ đại học rồi!</em></p><p class=\"wp-block-paragraph\">Không ngờ một ngày sau, đối phương lại hồi âm: <em>Chúc mừng bé đã toại nguyện.</em></p><p class=\"wp-block-paragraph\">Về sau, cô có người mình thích, cô tốt nghiệp đại học, cô tìm được công việc đầu tiên, cô đến thành phố phồn hoa lập nghiệp. Mỗi một cột mốc như vậy, cô đều kể cho anh nghe, mà anh luôn luôn đáp lại.</p><p class=\"wp-block-paragraph\">Cho đến một ngày, anh đột ngột bặt vô âm tín.</p><p class=\"wp-block-paragraph\">Hôm đó Thời Tiên vội vã chạy tới bệnh viện. Dưới ánh đèn trần trắng bệch, đó là lần đầu tiên cô nhìn thấy dáng vẻ của anh, cũng là lần đầu tiên biết được tên anh.</p><p class=\"wp-block-paragraph\">Tống Hoài Lễ nhìn cô, anh dịu dàng cất lời: “Đừng lo, bé con, anh sẽ không sao đâu.”</p><p class=\"wp-block-paragraph\">Năm đầu tiên Thời Tiên liên lạc với Tống Hoài Lễ, cô mười chín tuổi, còn anh ba mươi hai.</p><p class=\"wp-block-paragraph\">Và rồi cô trưởng thành.</p><p class=\"wp-block-paragraph\">—</p><pre class=\"wp-block-verse\">Có một người từng khiến tôi hiểu ra rằng, <br />sống ký sinh giữa dòng đời này hóa ra lại tốt đẹp đến thế.<br />Vòng tay anh khiến tôi chẳng còn phiền não, <br />là anh khiến tôi tự hào.<em> — Tựa Gió · Vương Phi</em>', '2026-03-24 20:45:19', '624538539_1319651930206107_7083128364085005243_n.jpg'),
(55, 'Cẩm Niên', 'Tố Quang Đồng', 'Ngôn Tình, Đô Thị, Nữ Cường, Ngược, Sủng', 88, 'Hoàn thành', '<p><strong>Thể loại:</strong> Hiện đại, đô thị tình duyên, nam cường, nữ cường, trước nữ truy sau nam truy, nghiệp giới tinh anh, ngành tài chính, có ngọt có ngược, sủng, HE <br /><strong>Số chương</strong>: 88 chương + 3 NT<br /><strong>Editor:</strong> Peachy | Peach A Chu<br /><strong>Cover</strong>: Tel fr. Cooking Team; Yến Ngọc<br /><br /><strong>Văn án:</strong><br /><br />Hai người quyết định cá cược với nhau, mà thứ đặt cược, chính là Khương Cẩm Niên cô.<br /><br />Cuối cùng, cô thua, thua thê thảm.<br /><br />Phó Thừa Lâm đưa tay tháo cà vạt, nhìn cô đòi nợ: \"Có chơi, có chịu. Em mau trả nợ đi thôi.\"<br /><br />Giám đốc đầu tư chứng khoán x Thương nhân tài chính cao cấp<br /><br /><strong>Nhân vật chính:</strong> Khương Cẩm Niên, Phó Thừa Lâm<br /><br /><strong>Nhân vật phụ:</strong> Kỷ Chu Hành, Diêu Thiên, Thẩm Đạt Quang, Lương Tung, La Hạm</p>', '2026-03-24 20:50:00', 'cam-nien.jpg'),
(56, 'Kính Vị Tình Thương', 'Thỉnh Quân Mạc Tiếu', 'Bách Hợp, Cổ Đại, Ngược', 307, 'Hoàn thành', 'Văn án: <br /><br />Hào trời trên dòng Lạc thủy phân đại địa Thần Châu ra làm hai, phương bắc là Kính Quốc, hướng nam là Vị Quốc.<br /><br />Một vị là vương tử vô ưu vô lự trên thảo nguyên, một vị là đích công chúa độc chiếm thịnh sủng.<br /><br />Một hồi chiến loạn đã khiến thảo nguyên vương tử trở thành cô nhi. Sau mười năm ẩn nhẫn, nàng vốn định trở thành một đời nịnh thần, đảo loạn giang sơn của địch quốc, nhưng trớ trêu lại bị chọn làm phò mã tại Quỳnh Lâm yến.', '2026-03-24 20:55:31', 'kinh-vi-tinh-thuong.jpg'),
(57, 'Theo Bắc', 'Mạnh Thư', 'Ngôn Tình, Khác', 70, 'Hoàn thành', '<p class=\"has-text-align-center has-black-color has-text-color has-link-color wp-elements-823a81d2bb2680a1bf670499583f6373 wp-block-paragraph\"><strong>THEO BẮC</strong></p><p class=\"has-text-align-center has-black-color has-text-color has-link-color wp-elements-0e89578ae3fac37a1dc3897d81fda757 wp-block-paragraph\"><strong><em>MẠNH THƯ</em></strong></p><p class=\"has-black-color has-text-color has-link-color wp-elements-a428f878cf4ee314a45d9a4301043f9f wp-block-paragraph\"><strong>GIỚI THIỆU</strong></p><p class=\"has-black-color has-text-color has-link-color wp-elements-0403a8cc92beb3d4fc41b30ce611dae5 wp-block-paragraph\">Lần đầu tiên Giang Oanh gặp Lý Bắc là khi cô mười bảy tuổi, vào một ngày đầu thu. Cậu thiếu niên không lớn tuổi lắm nhưng người rất cao, lưng hơi gù, tóc mái dài che gần kín đôi mắt, đường nét gương mặt sắc sảo với chiếc cằm hơi nhọn, đôi môi mỏng luôn mím chặt. Chiếc áo hoodie đen có khóa kéo bị xô lệch do bị kéo giật, để lộ ra một đoạn xương quai xanh sâu hoắm dưới lớp áo phông trắng. Ấn tượng đầu tiên của Giang Oanh là cậu gầy quá, như một cây sào trúc có gương mặt vậy.</p><p class=\"has-black-color has-text-color has-link-color wp-elements-b9d2d6f6f8d7bebe12d8722e73c87a2c wp-block-paragraph\">Cậu bước về phía cô. Bước chân không rộng, đi lững thững uể oải, đầu luôn cúi xuống, cột sống hơi cong. Quãng đường chỉ mất nửa phút đi bộ mà cậu bước đi rất chậm. Một chiếc xe tải trắng chạy từ góc đường tới, ở một góc khuất tầm nhìn của tài xế, cậu thiếu niên đột nhiên dừng bước, đứng yên bất động, vai hơi chùng xuống.</p><p class=\"has-black-color has-text-color has-link-color wp-elements-e0b544d3072b880eea1d4e78e1f1c888 wp-block-paragraph\">Cậu ấy định tự tử sao? Giang Oanh không biết lấy đâu ra can đảm mà chạy về phía trước, chạy đến trước mặt cậu, đưa tay kéo cánh tay cậu.</p><p class=\"has-black-color has-text-color has-link-color wp-elements-899461164f3cdd2841bbebb3124f82f2 wp-block-paragraph\">Ngày hôm đó, Lý Bắc nói: “Nhiều chuyện.” </p><p class=\"has-black-color has-text-color has-link-color wp-elements-3137f29f02fd0643a7b221f4d5383cc3 wp-block-paragraph\">Sau này, cậu lại nói: “Giang Oanh, không phải cậu muốn cứu tôi sao?”</p><p class=\"has-black-color has-text-color has-link-color wp-elements-5966fc919ea6433f75e169ac1ba92684 wp-block-paragraph\">“Chuyến tàu trong cơ thể tôi chưa bao giờ trật đường ray, nên tôi cứ để mặc tuyết rơi, bão tố, lũ lụt và phi lý.” – Dư Tú Hoa</p><p class=\"has-black-color has-text-color has-link-color wp-elements-b5679670a76fcca229321f7e8cc854b9 wp-block-paragraph\">[Hướng dẫn đọc]</p><p class=\"has-black-color has-text-color has-link-color wp-elements-8ef3a0eb66105e3954cb9e400d585ebc wp-block-paragraph\">*Cứu rỗi</p><p class=\"has-black-color has-text-color has-link-color wp-elements-077a57e0b2bd022db66ad51176719c6e wp-block-paragraph\">*Cô đơn nhẫn nhịn x Lạnh lùng chán đời</p><p class=\"has-black-color has-text-color has-link-color wp-elements-b8c5bda113fcb10c9ebfde6b8deba8ac wp-block-paragraph\">Thể loại: Học đường, HE , Cứu rỗi</p><p class=\"has-black-color has-text-color has-link-color wp-elements-3458b09255e1bc4ffff4d6eed98e38aa wp-block-paragraph\">Nhân vật chính: Giang Oanh, Lý Bắc</p><p class=\"has-black-color has-text-color has-link-color wp-elements-23f2f59d6e64ca30db9dc2a2bac28a94 wp-block-paragraph\">Giới thiệu ngắn gọn: Anh tên Lý Bắc </p><p class=\"has-black-color has-text-color has-link-color wp-elements-4070bffaad865483cb6cc6bc29bda4c7 wp-block-paragraph\">Ý nghĩa: Phải đứng trong ánh sáng, tiến về phía trước.</p>', '2026-03-24 20:57:42', '625865519_1319647750206525_6470433545172787717_n.jpg');
INSERT INTO `truyen` (`Id_truyen`, `Ten`, `TacGia`, `TheLoai`, `TongSoChuong`, `TrangThai`, `GioiThieu`, `NgayTao`, `AnhBia`) VALUES
(58, 'Bạn Học Số 7', 'Nam Tri Bắc', 'Ngôn Tình, Đô Thị, Ngược, Sủng', 95, 'Hoàn thành', '<p>Ngày hôm đó tại trại hè, giáo viên phát cho mỗi người một thẻ số và yêu cầu mọi người ghép đôi. Khi cầm thể số 7, Tất Hạ lần đầu tiên có cơ hội tiếp xúc với Trần Tây Phồn.</p><p>Cậu đội mũ lưỡi trai đen, giọng nói nhẹ nhàng, cong môi cười nhạt: \"Tìm được cậu rồi, bạn học số 7.\"</p><p>\"Có thể làm đồng đội của cậu không?\" </p><p>Lúc đó, cậu là chúng tinh phủng nguyệt, thiên chi kiêu tử, là mong muốn không thể với tới. Còn Tất Hạ chỉ là một trong số vô vàn nữ sinh thích cậu, là người không mấy nổi bật.</p><p>Mối tình đơn phương này đã định trước là sẽ không có kết quả.</p><p>Nhiều năm sau, Tất Hạ gặp lại Trần Tây Phồn. Hôm đó trời mưa to tầm tã, cô bị mắc kẹt trong một thành phố xa lạ.</p><p>Anh khẽ cười, giọng điệu kiên định: \"Yên tâm, tôi nhất định sẽ đưa cậu về nhà an toàn.\"</p><p>Sau đó, họ cùng tham gia một buổi họp lớp. Một người trêu đùa yêu cầu Trần Tây Phồn một hai kể về chuyện yêu đương của mình.</p><p>Trần Tây Phồn bất lực nói: \"Thực sự là chưa từng yêu đương, nhưng xác thực từng thích một người.\"</p><p>Mọi người khiếp sợ, hỏi người anh thích là ai.</p><p>Trần Tây Phồn nhìn về phía Tất Hạ, ánh mắt họ giao nhau, hốc mắt cô dần đỏ, trái tim đập lệch nhịp.</p><p>Trần Tây Phồn khóe môi mang ý cười, chậm rãi nói: \"Bạn học số 7 trong lớp chúng ta.\"</p><p>Không ai biết, vào đêm đó trong hành lang tối tăm, Tất Hạ bị anh áp vào tường, tránh cũng không thể tránh.</p><p>Hơi thở nóng bỏng của Trần Tây Phồn bao phủ lấy cô, gần như là khẩn cầu: \"Lại yêu anh đi, Bạn học số 7.\"</p><p>\"Yêu thầm một người, con đường đó dài vô tận, cánh cửa ấy lại hẹp, mà mình đã đi trên con đường này thật lâu, mới phát hiện rằng cánh cửa ấy chưa bao giờ mở ra cho mình.</p><p>\"Trần Tây Phồn, cuối cùng mình quyết định từ bỏ việc thích cậu. Chúc cậu tiền đồ như gấm, cả đời thuận buồm xuôi gió.\"</p><p>Ký tên: Bạn học số 7.</p><p>Sau khi tốt nghiệp, Tất Hạ đã viết một lá thư như vậy cho Trần Tây Phồn, bỏ vào một cái bao con nhộng.</p><p>Nhiều năm sau, cái bao con nhộng ngoài ý muốn bị phát hiện, lá thư được chuyển đến trong tay Trần Tây Phồn.</p><p>Từ đây, ở cuối lá thư, có thêm một dòng chữ:</p><p>\"Em từ bỏ giữa chừng, anh sẽ là người kiên trì đến cùng.\"</p><p>Ký tên: Trần Tây Phồn.</p><p>Năm tháng trôi qua, mối tình đơn phương của cô cuối cùng cũng nghe thấy được một lời hồi đáp.</p><p>Một câu tóm tắt: Yêu thầm trở thành hiện thực, cầu mong sẽ có được.</p><p>Lập ý: Trong khi theo đuổi ánh trăng, hãy trở thành một phiên bản tốt hơn của chính mình.</p><p>Vai chính: Tất Hạ, Trần Tây Phồn</p><p>Song mối tình đầu, HE, nữ chính yêu thầm trở thành sự thật, giai đoạn trước vườn trường đoạn sau đô thị.</p>', '2026-03-24 21:00:27', 'tháng 1.26 (29).jpg'),
(59, 'Chấp Kiếm Ôm Đi Sư Tỷ', 'Hà Mộc', 'Bách Hợp, Khác', 347, 'Hoàn thành', '<p>Văn án<br />Ngươi là người ta dù cầm kiếm cũng muốn ôm lấy</p><p>Phục Nhan xuyên vào một quyển truyện tu tiên thể loại hậu cung. Trong truyện, nam chính vừa tu luyện thành thần, vừa thu nạp vô số mỹ nhân vào hậu cung, chuyện xưa rối rắm trùng trùng.</p><p>Dù nội dung truyện khiến người ta chán ghét vì vô lý và lố bịch, nhưng cũng may, Phục Nhan không xuyên thành một trong những nữ nhân trong hậu cung của nam chính, cũng chẳng phải vai phản diện độc ác hay kẻ tự tìm đường chết. Nàng chỉ là một người qua đường, không quan trọng, không dính dáng gì đến cốt truyện chính.</p><p>Ấy vậy mà nàng lại gặp được Bạch Nguyệt Ly, đại sư tỷ trong tông môn.</p><p>Bạch Nguyệt Ly sở hữu thể chất thuần âm hiếm có, là người được tông môn dốc lòng nuôi dưỡng để trở thành lô đỉnh – người chuyên hỗ trợ song tu cho những kẻ có thiên phú tu luyện. Vì thể chất đặc biệt, ai ai cũng muốn chiếm lấy nguyên âm trong cơ thể nàng. Là một trong các nữ nhân của nam chính trong truyện, nguyên âm của Bạch Nguyệt Ly cuối cùng bị nam chính đoạt lấy, nàng cũng bị ép vào hậu cung.</p><p>Phục Nhan chỉ lặng lẽ thở dài: \"...\"</p><p>Nàng có thể ngăn cản Bạch Nguyệt Ly gặp nam chính, nhưng không thể ngăn nổi ánh mắt tham lam của tông môn – kẻ luôn nhìn chằm chằm vào sư tỷ, coi nàng như một vật quý để giành giật.</p><p>Không ai có thể quên được ngày hôm ấy – ngày mà Phục Nhan, thiên tài mới nổi của tông môn, tay cầm trường kiếm, đứng chắn trước cửa đại điện, thân áo tung bay trong gió. Nàng quay đầu lại, nhìn Bạch Nguyệt Ly đang e ngại phía sau mình, ánh mắt kiên định.</p><p>Nàng khẽ nói:<br />\"Sư tỷ đừng sợ, ta sẽ đưa người rời khỏi nơi này.\"</p><p>【Hướng dẫn đọc truyện】</p><p>Truyện tu tiên chính tông, dài hơi, lấy tu luyện và trưởng thành làm cốt lõi. Thiết lập bối cảnh kỹ lưỡng, văn phong dễ đọc. Cả hai nữ chính đều từ từ trưởng thành, từng bước tiến lên, mỗi bước đều để lại dấu ấn rõ ràng. Truyện chỉ có một cặp đôi duy nhất, yêu nhau trọn vẹn cả thân xác lẫn tâm hồn, không có chuyện chen ngang hay người thứ ba. Truyện hay trên Tấn Giang thì vô số kể, nếu không hợp khẩu vị, xin đừng gượng ép bản thân đọc tiếp.</p>', '2026-03-24 21:02:11', '394515272-256-k347280.jpg'),
(60, 'Ta Sắp Phải Nhảy Tru Tiên Đài', 'Thu Lăng', 'Tiên Hiệp, Ngôn Tình, Huyền Huyễn, Cổ Đại', 27, 'Hoàn thành', '<p>Thân là một con Cửu Vĩ Huyền Miêu, Diệu Diệu vốn rất hài lòng với cuộc sống của mình.</p><p>Trăm triệu lần cũng không ngờ tới, tương lai nàng sắp phải nhảy Tru Tiên Đài, phải đoạn đuôi, phải bị móc tim đào thận...</p><p>Mất trí nhớ, chín kiếp luân hồi, truy thê hỏa táng tràng!</p><p>Trời ạ, cuộc sống này quá khó khăn rồi, \"truy thê hỏa táng tràng\" bây giờ cũng cạnh tranh khốc liệt đến mức này sao? Lại còn nhiều kiếp như vậy nữa?</p><p>Này, đừng kéo đuôi của ta! Hôm nay ta không bái sư, không cùng sư phụ ngược luyến tình thâm gì hết, ta muốn bế quan.</p><p>Đến khi nàng xuất quan, cuối cùng nàng cũng trở thành Thượng Thần.</p><p>Một vị Tiên Tôn biết được nhân duyên của mình sắp tới, rốt cuộc ông trời cũng cho hắn thoát khỏi kiếp độc thân mấy chục vạn năm qua.</p><p>Nghe nói nương tử tương lai của hắn sẽ là đệ nhất đại mỹ nhân Lục giới, siêu cấp tốt luôn.</p><p>Thế nhưng, hắn đợi và đợi, nương tử sao mãi vẫn chưa tới? Khó khăn lắm mới đợi được nương tử, sao nàng lại muốn bế quan rồi?</p><p>Là do hắn không đủ soái khí? Hay là hắn không đủ sủng nàng?</p><p>Các đồ đệ: Hôm nay sư tôn vẫn siêu cấp đáng sợ như mọi khi.</p>', '2026-03-24 21:03:33', '1036.jpg'),
(61, 'Mây Hồ', 'Tuế Nguyên', 'Đô Thị, Đam Mỹ, Khác, Sủng', 58, 'Hoàn thành', '<p>Khương Linh Duật từng muốn kết liễu cuộc đời mình, nhưng khó khăn làm sao khi trên đường tự sát, cậu lại gặp phải Thố Sơ. Mới gặp, cậu đã nợ Thố Sơ một khoản tiền.</p><p>Lúc đầu, Khương Linh Duật cảm thấy Thố Sơ là một vị “Bồ Tát sống” với khuôn mặt lạnh lùng và trái tim ấp áp, luôn tốt bụng với tất cả mọi người. Cậu không nghĩ bản thân có gì đặc biệt, chỉ muốn chăm chỉ làm việc để trả hết nợ.</p><p>Tuy nhiên, thời gian dần trôi qua, cậu nhận ra Thố Sơ rất quan tâm và chiều chuộng mình, không chỉ cho cậu chỗ ở, mà còn khóc vì cậu. Đây là điều mà ít ai có được, nên cậu đã tưởng trong tim của Thố Sơ, mình cũng có một chút gì đó đặc biệt.</p><p>Sau đó, cậu lấy hết can đảm để thổ lộ tình yêu của mình với Thố Sơ, nhưng nào ngờ Thố sơ luôn giấu kín một người giống cậu trong lòng.</p><p>Thố Sơ rất ngạc nhiên trước lời tỏ tình của cậu, nhưng vẫn bình tĩnh nói: “Bây giờ chắc cậu cũng không phân biệt được giữa thích và cảm động, nên có lẽ tôi không phải là người cậu cần.”</p><p>Khương Linh Duật tự biết mình đa tình, muộn màng hiểu ra việc bắt lấy một khúc gỗ khi đang trôi dạt là một sai lầm. Cậu để lại tiền và lặng lẽ biến mất khỏi cuộc đời Thố Sơ.</p><p>Nhìn khoảng sân trống trải, khuôn mặt luôn bình tĩnh của Thố Sơ cuối cùng cũng sụp đổ…</p><p>Đám mây có tên “Khương Linh Duật” trôi vào hồ có tên “Thố Sơ”.</p><p> Trong tiếng Tây Tạng, “Thố” có nghĩa là “hồ”.</p><p><strong><em>Em là một linh hồn lạc lối, và anh là bến đỗ cuối cùng.</em></strong></p><p><strong><em>CP: Phúc hắc chủ tiệm cà phê công x U ám nhạy cảm nhiếp ảnh gia thụ</em></strong></p>', '2026-03-24 21:05:26', '67.jpg'),
(62, 'Thiên Kim Danh Y', 'Nha Đầu Tinh Quái', 'Ngôn Tình, Đô Thị, Xuyên Không, Nữ Cường, Hài Hước, Khác, Sủng', 496, 'Hoàn thành', '<p>🔍 Giới thiệu truyện:</p><p>“Ta, Tô Liên Y, thề với trời, từ nay về sau sẽ không bao giờ hành y cứu người nữa!”</p><p>—----</p><p>Tô Liên Y chưa bao giờ nghĩ rằng chuyện xuyên không – trào lưu thời thượng bây giờ – lại rơi vào người nàng, một bác sĩ nghiêm nghị, độc thân lâu năm như nàng.</p><p>Nhưng đúng là chuyện đó đã xảy ra. Nàng không còn là bác sĩ thần kinh nổi tiếng trong ngoài nước, mà trở thành một nữ lưu manh có tiếng ở mấy làng quanh vùng.</p><p>Trước kia nàng bận đến mức không có thời gian yêu đương, kết hôn. Bây giờ lại có một phu quân to khỏe nhưng xấu xí.</p><p>Trước kia bị người ta chê cười là gái già chưa chồng, bây giờ thì mang danh si mê nhị thiếu gia đẹp trai nhà đại phú, thành kẻ si tình nổi tiếng.</p><p>Trước kia nàng cứu người như lẽ sống, giờ lại mang tiếng đầy tội lỗi, ai ai cũng e dè.</p><p>Chẳng lẽ đây chính là kiểu \"hài đen\" mà người ta hay nói sao?</p><p>Phu quân nàng tuy xấu xí nhưng vóc dáng vạm vỡ, nhìn từ phía sau cũng đủ hút mắt. Dù không có tình cảm yêu đương, cũng không đến mức mặn nồng gắn bó, nhưng chung sống lại khá hòa thuận.</p><p>Cha và đệ đệ là lưu manh côn đồ, nàng phải tìm cách uốn nắn, quản lý họ. Dù không thể nói là vì dân trừ hại, nhưng ít ra cũng mang lại chút yên bình cho xung quanh.</p><p>Nàng chăm chỉ kiếm tiền, chỉ mong một ngày nào đó có thể rời đi, không còn phải sống dưới thân phận người khác nữa.</p><p>Từng thề sẽ không bao giờ hành y trở lại, vậy mà hết lần này đến lần khác lại bị buộc phải ra tay cứu người trong lúc nguy cấp.</p><p>Dù là kiếp trước hay kiếp này, nàng vẫn là nàng - Tô Liên Y, chính trực đàng hoàng, đường đường chính chính là Tô Liên Y.</p><p>Nào ngờ đâu, phu quân xấu xí ấy… lại có thân phận không hề đơn giản, đầy bí ẩn…</p><p>Ps: Mị đọc truyện này hay hay, đúng gu nữ cường mị thích nên mị đọc nên dịch luôn cho các mem đọc. Truyện share Free nhưng bạn muốn đăng chỗ khác thì nhắn mình 1 tiếng nhé!</p><p>Đọc truyện vui vẻ không quạo, không nhận gạch đá (mặc dù mị chưa có gạch xây nhà hihi 😀) có sai chính tả hay cách hành văn chưa được thì cmt cho mị biết nhé. </p><p>Dự kiến là mị sẽ dịch trường kỳ cùng nhiều bộ khác! Mị sẽ ra chậm nên các bạn khỏi thắc mắc sao lâu rồi chưa có chương mới nhé!</p><p>Thân!</p><p>Chúc các bạn đọc truyện vui vẻ. <3</p>', '2026-03-24 21:06:39', 'Thiên kim danh y.jpg'),
(63, 'Tấc Lòng', 'Lạc Nhật Tường Vi', 'Tiên Hiệp, Ngôn Tình, Cổ Đại', 170, 'Hoàn thành', '<p>Thể loại: Ngôn tình, cổ đại, tu tiên, kiếp trước kiếp này</p><p data-start=\"171\" data-end=\"425\"><strong data-start=\"257\" data-end=\"273\">[Chú thích]:</strong> Bối cảnh tu tiên thời mạt pháp (linh khí sắp cạn kiệt), nữ chính sức chiến đấu cao, CP thuần hận thù, không theo thiết lập tu tiên truyền thống, yếu tố tình cảm không nhiều.</p><p data-start=\"171\" data-end=\"425\">Giới thiệu:</p><p data-start=\"427\" data-end=\"1084\">Nhiều năm trước, khi Phương Thốn Tâm còn là Thiếu chủ của Ma Môn Thiên Di, nàng từng cứu một tán tu nhỏ bé.</p><p data-start=\"427\" data-end=\"1084\">Trải qua mấy chục năm cùng vào sinh ra tử, hai người tình ý song phương, kết thành đạo lữ.</p><p data-start=\"427\" data-end=\"1084\">Thiếu chủ thành thân, Ma Môn mở tiệc mừng rộn rã. Nào ngờ đêm tân hôn, vạn ngàn chính đạo đồng loạt tập kích Thiên Di.</p><p data-start=\"427\" data-end=\"1084\">Chỉ sau một đêm, Thiên Di diệt vong.</p><p data-start=\"427\" data-end=\"1084\">Tán tu kia bỗng hóa thành ánh sáng chính đạo, “lấy thân hầu ma”.</p><p data-start=\"427\" data-end=\"1084\">Mà nàng đêm ấy mới biết hắn chính là Bùi Quân Nhạc thiên tư trác tuyệt, danh chấn ngang nàng, của Vân Hải Nhất Mộng.</p><p data-start=\"427\" data-end=\"1084\">Tiên ma hai thế đối lập, hai người bọn họ định sẵn phải trở thành tử địch.</p><p data-start=\"1086\" data-end=\"1593\">Về sau…</p><p data-start=\"1086\" data-end=\"1593\">Phương Thốn Tâm trọng thương, tỉnh lại quên hết quá khứ, bị hắn lừa thành sư muội đồng môn, từ ma nhập tiên.</p><p data-start=\"1086\" data-end=\"1593\">Trăm năm vội vã, Bùi Quân Nhạc yêu nàng khắc cốt ghi tâm, bất chấp tất cả để kết đạo lữ cùng nàng.</p><p data-start=\"1086\" data-end=\"1593\">Ngày đại hôn, Ma tu âm thầm kéo đến, tấn công Tiên môn.</p><p data-start=\"1086\" data-end=\"1593\">Còn Phương Thốn Tâm thì chưa từng mất trí nhớ…</p><p data-start=\"1086\" data-end=\"1593\">Chính tà đại chiến bảy ngày bảy đêm, hai người đồng quy vu tận.</p><p data-start=\"1086\" data-end=\"1593\">Bùi Quân Nhạc bị nàng một kiếm xuyên tim, đóng chặt vào cây Ngô Hoàng; Thốn Tâm bị hắn trói trên Lửa Thanh Hư.</p><p data-start=\"1595\" data-end=\"1888\">Lại về sau…</p><p data-start=\"1595\" data-end=\"1888\">Năm tháng thoi đưa, nước chảy chẳng hay.</p><p data-start=\"1595\" data-end=\"1888\">Có người nhổ Lôi Cốt Kiếm của Bùi Quân Nhạc, tháo Long Hồn Tiên của Phương Thốn Tâm.</p><p data-start=\"1595\" data-end=\"1888\">Hai người sống lại.</p><p data-start=\"1595\" data-end=\"1888\">Thiên Di Môn không còn, Vân Hải Nhất Mộng cũng biến mất.</p><p data-start=\"1595\" data-end=\"1888\">Một giấc vạn vạn năm, yêu hận đều xa, còn thời mạt pháp của tu tiên đã đến.</p><p data-start=\"1890\" data-end=\"1906\"><strong data-start=\"1890\" data-end=\"1904\">Lưu ý đọc:</strong></p><ol data-start=\"1907\" data-end=\"2144\"><li data-start=\"1907\" data-end=\"1979\"><p data-start=\"1910\" data-end=\"1979\">Không phải bối cảnh tu tiên truyền thống, hệ thống cấp bậc được giản lược.</p></li><li data-start=\"1980\" data-end=\"2029\"><p data-start=\"1983\" data-end=\"2029\">Trọng tâm là cốt truyện, yếu tố tình cảm ít.</p></li><li data-start=\"2030\" data-end=\"2117\"><p data-start=\"2033\" data-end=\"2117\">Tác giả chưa từng tu tiên, thế giới tu tiên trong truyện hoàn toàn là tưởng tượng.</p></li></ol><p data-start=\"2227\" data-end=\"2343\"><strong data-start=\"2227\" data-end=\"2244\">Tag:</strong> Cường – cường, Tiên hiệp tu chân, thăng cấp, Nhẹ nhàng, Não động, Nhiều tuyến nhân vật.</p><p data-start=\"2345\" data-end=\"2447\"><strong data-start=\"2345\" data-end=\"2364\">Nhân vật chính:</strong> Phương Thốn Tâm, Diệp Huyền Tuyết/Bùi Quân Nhạc<br data-start=\"2414\" data-end=\"2417\" /><strong data-start=\"2417\" data-end=\"2434\">Nhân vật phụ:</strong> Rất nhiều.</p><p data-start=\"2449\" data-end=\"2506\"><strong data-start=\"2449\" data-end=\"2458\">Khác:</strong> Nữ chính sức chiến đấu cao, CP thuần hận thù.</p><p data-start=\"2508\" data-end=\"2598\"><strong data-start=\"2508\" data-end=\"2528\">Một câu tóm tắt:</strong> Sau khi đồng quy vu tận cùng nam chính, sống lại vào thời mạt pháp.</p><p data-start=\"2600\" data-end=\"2631\"><strong data-start=\"2600\" data-end=\"2611\">Chủ đề:</strong> Nỗ lực sống tiếp. Thốn Tâm – Tấc lòng</p>', '2026-03-24 21:07:51', 'tháng 1.26 (38).jpg'),
(64, 'Thính Thần', 'Cá Muối Không Ăn Rau', 'Đô Thị, Bách Hợp, Trinh Thám, Khác', 128, 'Hoàn thành', '<p>Tên tác phẩm: Thính Thần<br /><br />Tác giả: Cá Muối Không Ăn Rau<br /><br />Thể loại: Bách hợp, Hiện đại, Vô hạn lưu, Vô hạn tuần hoàn, Huyền nghi, Suy luận kịch tính, HE,...<br /><br />Nhân vật chính:  Hai bé Lâm Thương Từ và Cố Trọng (Biên kịch gàn dở X Diễn viên tầm trung)<br /><br />Số chương: 127 chương <br /><br />Editor: Lăng<br /><br />Văn án<br /><br />Một người là diễn viên tầm trung trong giới giải trí, bất ngờ trở nên nổi tiếng nhờ một bộ phim cổ trang võ hiệp.<br /><br />Một người là nhà biên kịch quái gở hướng nội, chỉ thích trốn trong nhà sáng tác.<br /><br />Một bên rực rỡ như sao trời. Một bên tĩnh lặng như hồ sâu.<br /><br />Câu chuyện bắt đầu từ một buổi tiệc mừng công. Cứ nghĩ quan hệ giữa hai người chỉ như bèo nước gặp nhau, uống một ly rượu hàn huyên vài câu là xong, chẳng ngờ lại bị sợi dây vận mệnh trói buộc thành đôi.<br /><br />Kim giây tích tắc vơi đi từng giây, rồi lại quay về nơi bắt đầu, hệt như cách thời gian đùa bỡn với nhân loại đáng thương.<br /><br />Chào mừng đến với Thính Thần.<br /><br />Nghệ sĩ hạng ba Cố Trọng X Biên kịch quái gở Lâm Thương Từ<br /><br />Lập ý: Dù quay lại bao nhiêu lần đi nữa, người vẫn luôn ngự trị trong trái tim tôi. Tôi yêu người.<br /><br />- ---<br /><br />Huyền nghi: Là các tác phẩm có nội dung kết hợp các yếu tố hồi hộp bí ẩn, trinh thám, phá án, đan xen những yếu tố ly kỳ.<br /><br />Vô hạn lưu là một thể loại văn học Trung Quốc bắt nguồn từ tác phẩm Vô Hạn Khủng Bố (2008). Từ Vô hạn lưu có thể tạm hiểu là \"Không giới hạn trong mọi thứ\", bao gồm tất cả mọi yếu tố như Khoa học Kỹ thuật, Tôn giáo, Thời gian, Không gian,...<br /><br />Từ trong thể loại vô hạn này được chia ra làm nhiều nhánh khác nhau: Vô hạn khủng bố, vô hạn tuần hoàn (vòng lặp), vô hạn kinh dị, xuyên map, xuyên game,... Đặc điểm chung của thể loại vô hạn là nhân vật chính bị rơi vào một hoàn cảnh đặc biệt (không giới hạn về thời/ không gian, có nhiều yếu tố giả lập không thể chứng minh được bằng lý luận khoa học thực tế trong thế giới thật) liên tục phải trải qua các thử thách cực hạn khác nhau (Ví dụ: Đóng phim kinh dị, vào game nhập vai, giải mã câu đố, các không gian ảo,...), từ đó giải mã bí ẩn để tìm cách thoát ra.<br /><br />Bạn nào hay đọc truyện nam tần chắc không xa lạ gì thể loại này, một số tác phẩm vô hạn lưu khá ổn mà mình đã đọc: Series Vô hạn khủng bố, Rạp chiếu phim địa ngục, Chạy trốn khỏi phim trường, Livestream siêu kinh dị, Khủng bố sống lại, Radio khủng bố,...<br /><br />Tâm sự kiêm review:<br /><br />Chào mọi người,<br /><br />Tên truyện được tác giả lý giải \"Thính\" hay \"Nghe\" là một hành vi thụ động, \"Thần\" nghĩa như mặt chữ, chỉ một thực thể không thuộc phạm trù hiểu biết nhân loại. \"Thính thần\" ám chỉ sự hoang mang, mờ mịt khi bị động tiếp nhận một thứ gì đó, và cũng bị động đi tìm kiếm chân tướng. Bạn đọc là sẽ hiểu về ý nghĩa của tên truyện thôi.<br /><br />Chủ đề chính của tác phẩm mới lạ, độc đáo, hiếm thấy ở bách hợp. Tác giả mới ít người biết ở bên mình, nhưng viết khá chắc tay, khéo léo có đầu có đuôi, các vòng lặp được làm mới liên tục không gây nhàm chán, mỗi lần lặp lại là lại đẩy cao trào lên nấc thang mới, khá giống rắn Ouroboros. Có cài cắm khá nhiều plot twist và easter egg, tuy là nhiều tình tiết dễ đoán nhưng tất cả mọi việc xảy ra đều có lý do, được tính toán kỹ lưỡng, chỗ nào còn khúc mắc thì sau này cũng sẽ được giải đáp.<br /><br />Phần miêu tả nội tâm của nhân vật cũng khá hay, cảm xúc qua từng vòng lặp cũng có sự chuyển biến tốt, từ sợ hãi, bàng hoàng sang mệt mỏi, muốn bỏ cuộc rồi lại đến quyết tâm phá vỡ. Tuy là đôi chỗ miêu tả hơi dài dòng lan man, không mạch lạc nhưng thôi không sao. Ngoài ra tác giả đặt trọng tâm vào vòng lặp nên không còn chỗ để khai thác thêm về các nhân vật phụ mà mình thích (mà thế nên mới edit chứ còn dài hơn nữa thì chẳng bao giờ động tay vào rồi). Truyện có yếu tố showbiz nhưng không nhiều, cách khai thác cũng mới lạ. (Cũng may chứ thật ra lúc đầu thấy nói về showbiz mình không tính đọc vì chán.)<br /><br />Về hai nhân vật chính, xứng đôi vừa lứa với nhau, mấy bạn không lo bị ngược vì cả hai chung thủy một lòng sắt son, truyện cũng không có tình tiết máu chó kẻ thứ ba, phần ngược không nằm trong tuyến tình cảm của hai nhân vật chính. Hai bé yêu nhau đúng như trong câu lập ý \"Dù quay lại bao nhiêu lần đi nữa, người mãi ngự trị trong trái tim tôi\".<br /><br />Hai nhân vật cũng được xây dựng khá sát với thực tế, không được buff nhiều (\"được\" hành nhiều hơn), Lâm Thương Từ suy nghĩ lý trí đôi khi sẽ thấy ích kỷ thực dụng, nhưng lại đúng với đa số bản chất con người, thế nên mới cần có một Cố Trọng thấu tình đạt lý ở bên cạnh. Mình nghĩ trong cuộc sống ai cũng từng có suy nghĩ như Thương Từ, nhưng không phải ai cũng đủ tỉnh táo để phân rõ đúng sai như Cố Trọng, vậy nên mới tạo ra couple vừa thực tế vừa ảo ma Canada này.<br /><br />Nói đến thế thôi, nội dung như thế nào thì mọi người tự đọc và cảm nhận. Truyện mình đã edit xong nên mấy bạn không lo drop. Chúc mọi người thưởng thức tác phẩm vui vẻ.<br /><br />Vì là chuyện vòng lặp nên các bạn lưu ý các mốc thời gian giúp mình.</p>', '2026-03-24 21:10:42', '357301329-256-k987030.jpg'),
(65, 'Bức Lương Vi Phi', 'Lâm Thác', 'Bách Hợp, Cổ Đại, Khác', 85, 'Hoàn thành', '<p>Tác phẩm: Bức Lương Vi Phi<br />Tác giả: Lâm Thác<br />Thể loại: Cổ ngôn, chính kịch, nữ tần, quân thần chi luyến, niên hạ, chuyên nhất, HE<br />Trạng thái: Kim bài tác phẩm tiêu biểu Tấn Giang Văn Học Thành<br />Nhân vật: Nguyên Gia x Cố Uyên<br />Độ dài: Trường thiên<br />Editor: KimDan-ssi</p><p>VĂN ÁN & GIỚI THIỆU</p><p>Quân thượng trên ngôi cửu ngũ, nhất ngôn cửu đỉnh. Tuy là nữ Đế, cũng vẫn quân vô hí ngôn[1].</p><p>[1] Vua không bao giờ nói chơi.</p><p>Quân thượng không vừa mắt với văn chương của Cố Uyên, nàng chỉ còn cách lưu lạc đầu đường.</p><p>Quân thượng muốn Cố Uyên nhập cung hầu hạ, nàng chỉ còn cách pha trà rót nước.</p><p>Quân thượng muốn Cố Uyên dọn giường, trải chăn, chung loan trướng - Nàng đấu tranh mãi, cuối cùng, đành chấp nhận.</p><p>———</p><p>Lời Editor:<br />\"Bức Lương Vi Phi\" - bức lương thần thành phi tần, có thể hiểu đã là phi tần thì không bao giờ lương thiện.</p><p>Đây là tác phẩm không mới, đã 10 năm rồi. \"Bức Lương Vi Phi\" có nhân vật liên quan đến tiểu thuyết \"Tung Hoành\" của cùng tác giả Lâm Thác - đại thần tiểu thuyết bách hợp thời kỳ đầu (10-15 năm trước). \"Tung Hoành\" là tựa truyện trường thiên nữ tần, bách hợp quyền mưu bối cảnh lớn tiểu biểu trong thời kỳ đầu của văn học mạng, thời đó thường được ví như \"Lang Nha Bảng\" của giới bách hợp. \"Tung Hoành\" quá đồ sộ và tác giả chưa thật sự kết thúc phần sau của nó, nên nhà đài thầu \"Bức Lương Vi Phi\" - cùng tác giả, cùng phong cách, nhưng ngắn hơn, nhẹ nhàng dễ xem hơn nhưng cũng đã nhận được Kim bài Tác phẩm tiêu biểu Tấn Giang Văn Học Thành. Hi vọng các bạn yêu thích.</p>', '2026-03-24 21:12:57', '398884060-256-k32249.jpg'),
(66, 'Hội Ngộ Ngày Xuân Khởi ', 'Trừng Tịch', 'Ngôn Tình, Đô Thị, Ngược, Sủng', 69, 'Hoàn thành', '<em>Giới thiệu</em></h3><p>Nhân vật chính: Bạch Hành Việt x Châu Toàn</p><p>Kiến trúc sư x Nhà khảo cổ học</p><p>Thể loại: Đô thị, tình yêu duy nhất, đập chậu cướp hoa, nam nữ trưởng thành, HE.</p><h3 class=\"wp-block-heading\"><em>Văn án</em></h3><p>Trong vài tháng làm việc ở thị trấn nhỏ để tham gia khảo cổ, Châu Toàn có một quãng thời gian ngắn bên cạnh Bạch Hành Việt. Anh là bạn thuở nhỏ của bạn trai cô, anh mới về nước không lâu, đến đây du ngoạn, coi như là để thư giãn.</p><p>Lần gặp đầu tiên là tại phòng khách sạn của bạn trai cô. Cô vừa tắm xong, sắc mặt hồng hào, những giọt nước từ đuôi tóc rơi xuống sàn. Bạch Hành Việt đứng tựa ở cửa sổ hút thuốc, mỉm cười một cách mơ hồ, ánh mắt dò xét công khai không hề che dấu.</p><p>Châu Toàn cảm thấy anh là kiểu người lả lơi, không có nguyên tắc, không muốn bị cuốn vào quá sâu, nhưng anh lại lặng lẽ chen vào công việc và cuộc sống của cô, lúc tiến lúc lùi, như ếch được luộc trong nước đun sôi từ từ.</p><p>Vào ngày phát hiện bạn trai ngoại tình, Châu Toàn được dẫn đến lại cái khách sạn ngày đó. Bạch Hành Việt nhẹ nhàng vuốt ve môi cô hỏi: “Em có muốn trả thù không?”</p><p>Anh quá tự tin, rõ ràng là đã nắm chắc phần thắng trong tay.</p><p>Châu Toàn mặt không đổi sắc, cố tình cắn vào ngón tay anh, không hề nương tình.</p><p>Châu Toàn lần đầu tiên thẳng thắn hỏi: “Anh có phải là có chút hứng thú với tôi không?”</p><p>Bạch Hành Việt thừa nhận: “Không chỉ một chút.”</p><p>—</p><p>Ấn tượng đầu tiên của Bạch Hành Việt về Châu Toàn đã dừng lại ở cách đây bốn, năm năm trước. Anh từng đến một quán bar yên tĩnh trước khi ra nước ngoài và bị cô phục vụ nữ làm đổ rượu lên người.</p><p>Cô gái trẻ lúc ấy giống như đối mặt với kẻ thù, môi mím chặt, sắc mặt như sắp khóc. Lần đầu tiên, anh vốn ít khi cảm thấy mủi lòng nhưng lần này không nỡ bỏ mặc liền giúp cô thoát khỏi tình huống bối rối.</p><p>Ban đầu, mọi chuyện chỉ dừng lại ở đó, cho đến khi xem được video từ bạn thuở nhỏ của mình. Cô thay đổi quá nhiều, trang điểm tinh tế, cử chỉ hành động tự nhiên, biết cách nở nụ cười dịu dàng với những người đàn ông khác.</p><p>Khoảnh khắc ấy, đồng cỏ mùa xuân xanh tươi trở lại, anh đột nhiên muốn cắt đứt sợi dây tơ hồng của cô với người khác để nối lại một mối duyên thầm mà cô đã lãng quên từ thuở nào.</p>', '2026-03-24 21:16:52', 'tháng 1.26.png'),
(67, 'Sương Đêm Và Tuyết Tùng', 'Nhất Thốn Chu', 'Ngôn Tình, Đô Thị, Hài Hước, Sủng', 157, 'Hoàn thành', '<p>Tên khác: Gốc Tuyết Tùng Trong Màn Sương Đêm </p><p>Công Tử Miệng Độc Xuyên Tạc X Người Đặc Trị Lời Ong Tiếng Ve Giả Vờ Thanh Thuần</p><p>Nhiều năm không từ mà biệt, Trình Giang Tuyết gặp lại Chu Phục ở một thị trấn nhỏ phía Tây Nam.</p><p>Cô giáo Trình đến đây để dạy học tình nguyện, vali hành lý lỉnh kỉnh, dính đầy bụi đường.</p><p>Trong buổi tiệc chào đón, mọi người đều bày tỏ sự hoan nghênh với cô giáo Trình, chỉ có Chu Phục là giữ vẻ mặt lạnh tanh.</p><p>Thế nhưng, vào một đêm nọ, có người đứng ngoài cửa ký túc xá thấy cô giáo Trình - người thậm chí còn không dám nói lớn tiếng - đã dùng lực tát Chu Phục một bạt tai và nói: \"Phiền anh làm rõ ràng, chúng ta đã chia tay rồi.\"</p><p>\"Tát mạnh thêm chút nữa đi, thoải mái hơn đấy.\" Chu Phục dựa tay vào mặt với vẻ mặt cà lơ phất phơ, từ từ nở nụ cười.</p><p>Về người đàn ông mà cô yêu, ngay cả trong cuốn nhật ký viết thời sinh viên, Trình Giang Tuyết cũng chỉ dành cho anh một câu: “Tôi quá mức khuôn mẫu và bình thường đến mức anh ấy sẽ chẳng bao giờ chú ý đến tôi, càng không thể biết được tôi bắt đầu yêu anh ấy từ lúc nào, và đã từ bỏ hy vọng vào ngày nào.”</p><p>Hướng Dẫn Khi Đọc:</p><p>SC, HE.<br />Chênh lệch tuổi tác: Nam lớn hơn nữ 4 tuổi.<br />Cốt truyện: Mở đầu là gặp lại, giữa truyện sẽ có một đoạn hồi ức về thời học sinh.<br />Địa danh trong truyện là hư cấu.</p><p>Tóm tắt một câu: Tạm biệt tuổi thanh xuân.</p><p>Chủ đề: Kiên trì chính là chiến thắng.</p>', '2026-03-24 21:25:20', 'tháng 3.26 (6).jpg'),
(68, 'Cung Phá Cửu Tiêu', 'Mộng Cảnh', 'Tiên Hiệp, Kiếm Hiệp, Đô Thị, Dị Giới, Huyền Huyễn, Đông Phương, Hài Hước, Cổ Đại, Khác', 483, 'Hoàn thành', '<p>Thể loại: Cổ Đại, Dị Thế Đại Lục, Góc Nhìn Nam, Hài Hước, Huyền Huyễn, Huyền Huyễn Phương Đông, Phương Đông</p><p>Giới thiệu:</p><p>Từ đáy bùn của Thành Triều Dương, nơi một tiểu ăn xin run rẩy trong gió lạnh, vận mệnh lại mở ra một khe sáng. Cuộc gặp gỡ với người mẹ nuôi thần bí đến từ Thượng giới đã khiến số phận Loan Bồi Thạch đổi dời — đưa hắn bước vào con đường mà chỉ những kẻ mang chí hướng phá thiên xé đạo mới dám đặt chân.</p><p>Võ đạo vừa là cứu rỗi, vừa là lưỡi dao thử thách.<br />Ân oán, huyết thù, mưu đồ, diệt tộc — tất cả lần lượt cuộn lại, đẩy hắn từ một phàm tục vô danh thành kẻ đủ sức đối kháng cả trời đất.</p><p>Từ Hạ giới nhiễu loạn bởi Ma nhân triều, đến Thượng giới mênh mông tràn đầy âm mưu và tộc chiến ngàn năm, Loan Bồi Thạch từng bước nghịch thiên:</p><p>• Thể phách cường hãn – tâm cảnh Tuyệt Dục – lĩnh ngộ pháp tắc vạn đạo.<br />• Cung thuật tuyệt thế – Tiễn Vực khai mở – pháp bảo Tinh Hãn Chi Nhãn trấn áp thần hồn.<br />• Đối chiến cường giả vượt cấp – quét sạch tà ma – trấn động chư thiên.</p><p>Bên cạnh hắn là những nữ tử tài mạo song toàn: người vì hắn mà hy sinh, người vì hắn mà lột xác, người đi cùng hắn suốt vạn dặm tang thương. Họ là thê tử, là đồng đội, là phần mềm mại duy nhất trong một hành trình ngập tràn máu và lửa.</p><p>Kẻ thù của hắn — từ những cường hào ở Thành Triều Dương, đến các gia tộc cổ xưa của Thượng giới, đến cả Tà Linh tai họa muôn đời — mỗi một kẻ đều là bậc tồn tại khiến thiên địa run rẩy. Nhưng tất cả đều phải cúi đầu trước ý chí của hắn.</p><p>Vì gia tộc.<br />Vì người thân.<br />Vì đạo tâm bất diệt.<br />Vì một thế giới nhân tộc không còn bị vùi trong bóng tối.</p><p>Từ Võ Tôn đến Nhân Quân, từ Thánh Quân đến bước đầu chạm vào Vĩnh Hằng Ngũ Cảnh, hắn dùng chính máu, nước mắt và quyết tâm khắc lên thiên đạo một câu:</p><p>“Phàm nhân cũng có thể bước lên Vĩnh Hằng.”</p><p>Một bản trường ca tu tiên khắc họa trọn vẹn:<br />ý chí bất khuất – tình thân thâm hậu – tình yêu thủy chung – thù hận khắc cốt – và con đường nghịch thiên truy cầu đạo của một con người dám thách thức cả vũ trụ.</p>', '2026-03-24 21:26:37', 'tháng 1.26 (16).jpg'),
(69, 'Cô Ấy Vẫn Chưa Biết', 'Bản Đông', 'Ngôn Tình, Đô Thị, Hài Hước, Khác, Sủng', 59, 'Hoàn thành', '<p>Đây là năm thứ mười Bùi Kỳ thích Thẩm Phương Nguyệt.</p><p>Nhưng cô ấy vẫn chưa biết.</p><p>–</p><p>Một lần nọ, Bùi Kỳ lấy hết can đảm hỏi: “Cậu có thích tớ không, Thẩm Phương Nguyệt.”</p><p>Cô dè dặt trả lời: “Chỉ là thích một chút xíu xíu xíu xíu xíu thôi.”</p><p>Bùi Kỳ thở phào: “Ừ, thích một chút xíu xíu xíu cũng được.”</p><p>“Cậu thiếu hai chữ ‘xíu’ kìa.”</p><p>–</p><p>1. Truyện học đường, đáng yêu ngốc nghếch VS. độc mồm độc miệng.</p><p>2. Thanh mai trúc mã/ Oan gia vui vẻ, câu chuyện thường ngày, truyện ngắn đáng yêu giải trí.</p><p>3. Trước khi thành niên sẽ không yêu đương.</p><p><strong>Một câu tóm tắt: </strong>Bạn thân thuở bé</p><p><strong>Thông điệp:</strong> Sống cùng một xóm, đôi trẻ hồn nhiên</p>', '2026-03-24 21:27:31', '30.jpg'),
(70, 'Ngàn Vạn Nụ Hôn Trao Em', 'Chu Minh Đình', 'Ngôn Tình, Đô Thị, Hài Hước, Sủng', 59, 'Hoàn thành', '<p>Thể loại: 1v1, HE (Kết thúc viên mãn), Hài hước, Nhật ký “tự vả” của nam chính, Oan gia ngõ hẹp, Hợp đồng tình yêu, Cưới trước yêu sau, Phấn đấu sự nghiệp, Truyện ngọt.</p><p>Giới thiệu: </p><p>Tổng tài tập đoàn Kỷ thị – Kỷ Hoài Xuyên vốn anh tuấn, thanh cao, nhưng mãi vẫn chưa chịu lập gia đình. Gia đình giục cưới gắt gao, thế nên, anh tìm một cô gái để kết hôn trên danh nghĩa: Đôi bên cùng có lợi, một năm sau sẽ ly hôn.</p><p>Sở Thác giữ chặt tấm thẻ đen anh đẩy tới, chốt đơn ngay lặp tức: “Một lời đã định!”</p><p>Sở Thác người đẹp, miệng ngọt, ai gặp cũng mến, mọi việc đều thuận lợi, có thể gọi là “tuyển thủ toàn năng” trong làng kết hôn giả. Mọi thứ đều rất hoàn hảo, ngoại trừ việc… —— Ngoại trừ việc hình như anh bắt đầu có chút thích cô rồi.</p><p>Kỷ Hoài Xuyên bình tĩnh suy nghĩ, rồi nói với Sở Thác: “Kết thúc đi.”</p><p>Vừa đến tối đã nhận được tin nhắn: “Thẻ đã quẹt cháy máy. Tạm biệt chồng cũ nhé ~” ……</p><p>Thỏa thuận hôn nhân kết thúc bất ngờ, Sở Thác liền tìm ngay một em trai trẻ trung, vai rộng eo thon, cơ bụng tám múi, chuẩn bị sảng khoái cao chạy xa bay. Ngờ đâu đêm trước khi đi, cô lỡ uống say. Sáng hôm sau tỉnh dậy, suýt thì bị “tên đàn ông tồi” nằm bên cạnh dọa cho hết hồn.</p><p>Kỷ Hoài Xuyên nhìn cô cười như không cười, thong thả mở miệng: “Tối qua ngủ ngon không?”</p><p>Sở Thác: “Khụ khụ, không tốt lắm… Cái đó, tôi say quá, không cố ý làm gì anh đâu… Chúng ta coi như quên đi nhé.” Tuy rằng… người nào đó sức lực dồi dào, “bay đường dài” cực đỉnh, trải nghiệm người dùng cũng khá tuyệt.</p><p>Cô vừa định chuồn êm thì bị Kỷ Hoài Xuyên ôm vào lòng: “Muốn quên à? Giờ vẫn còn sớm, ôn lại bài cũ chút đã, không vội.”</p><p>“……” Tên khốn này, đã bảo là kết hôn giả thôi cơ mà!</p><p>Cặp đôi: Tổng tài ngạo kiều x Nữ chủ biên cực kỳ thực tế (vô cảm, chỉ mê tiền).</p>', '2026-03-24 21:28:25', 'tháng 12 (60).jpg'),
(71, 'Mộ Dĩ Thành Chu', 'Lục Lộ Lộc', 'Ngôn Tình, Đô Thị, Hài Hước, Sủng', 75, 'Hoàn thành', '<p><strong>Giới thiệu:</strong></p><p>Triệu Mộ Dư gần đây tham gia một chương trình thực tế về hẹn hò giả tưởng giữa người thường và nghệ sĩ.</p><p>Khi được hỏi về hình mẫu lý tưởng, cô chỉ đưa ra ba tiêu chí: “Không phải diễn viên, không nổi tiếng, và không scandal.”</p><p>Sau đó, trong buổi ghi hình đầu tiên.</p><p>Vừa đến trường quay, Triệu Mộ Dư đã được đạo diễn quay phim đi theo hào hứng dặn dò: “Cô Triệu ơi, xe cứu thương đã chuẩn bị sẵn sàng rồi, lát nữa cô có kích động quá mà ngất đi cũng không sao nhé!”</p><p>Triệu Mộ Dư: “?”</p><p>Cô đang ngơ ngác không hiểu gì thì bước vào quán cà phê, rồi nhìn thấy đối tượng hẹn hò giả tưởng ở cách đó không xa—là Giang Chu Trì, người vừa trở thành Ảnh đế Đại mãn quán* trẻ tuổi nhất lịch sử, nổi tiếng khắp toàn cầu, và có scandal bay đầy trời.</p><p><em>* “Ảnh đế Đại mãn quán” dùng để chỉ diễn viên nam giành được tất cả các giải thưởng danh giá nhất về diễn xuất trong lĩnh vực điện ảnh tại một khu vực hoặc quốc tế.</em></p><p>Sau một thoáng im lặng, Triệu Mộ Dư quay lưng định đi ngay.</p><p>Nhưng phía sau cô vang lên một giọng nói, vượt qua mọi ồn ào. Giọng điệu hơi lười biếng, lạnh nhạt, hờ hững nhắc nhở cô: “Cô Triệu, lối ra ở phía tôi.”</p><p>Khoảng cách trong từng lời nói được kiểm soát một cách hoàn hảo, khác nhau hoàn toàn so với Giang Chu Trì tối qua đã vùi mặt vào hõm cổ cô, khàn giọng gọi cô là “Mộ Mộ”.</p><p>—</p><p>Giang Chu Trì nổi tiếng từ khi còn trẻ, nốt ruồi nhỏ trên sống mũi đã khiến biết bao người say đắm, trở thành nốt chu sa trong lòng hàng triệu khán giả.</p><p>Thế nhưng, vào năm anh giành được chiếc cúp Nam diễn viên chính xuất sắc nhất thứ ba, khi sự nghiệp chạm đến đỉnh cao một lần nữa, anh lại nhận lời tham gia một show hẹn hò, dù trước giờ chưa bao giờ xuất hiện trong các show truyền hình.</p><p>Tin tức này vừa tung ra, cả mạng xã hội đều tan nát cõi lòng.</p><p>Đến khi chương trình phát sóng, cộng đồng mạng lại đồng lòng – “Không giống diễn chút nào, tiếp tục cắn đường xem sao!”</p><p>Sau ba tháng chương trình kết thúc, cả mạng xã hội đồn đoán anh và Triệu Mộ Dư phim giả tình thật, trong đó tin tức chấn động nhất là từ một người tự xưng là nhân viên của ekip chương trình tiết lộ, hai người đã đăng ký kết hôn từ lâu.</p><p>Từ khóa #Giang Chu Trì Triệu Mộ Dư kết hôn# ngay lập tức làm nổ tung top tìm kiếm.</p><p>Cùng lúc đó, có người chụp được ảnh Giang Chu Trì ở phim trường.</p><p>Vừa bước xuống xe bảo mẫu, cô gái trong vòng tay anh được trợ lý dùng chiếc ô đen lớn che chắn kín mít.</p><p>Trong lúc hỗn loạn, người ta chỉ thấy bộ quần áo hơi xộc xệch của Giang Chu Trì, và một đoạn cổ trắng lạnh, trên đó một dấu răng mờ ám hiện rõ.</p><p>Dư luận lại tiếp tục nóng lên.</p><p>Tối hôm đó, Giang Chu Trì, người chưa bao giờ đáp lại scandal, lần đầu tiên đăng một bài viết trên Weibo để đính chính—</p><p>“Là giả. Mới cầu hôn, cô ấy chưa đồng ý.”</p><p>—</p><p><em>Em đi qua mười năm xuân và thu, trở thành căn gác xép trong tim anh. Thế nên, giữa mùa hè khô hạn đã lâu không mưa, anh đành chấp nhận ‘bát nước đổ đi’. Còn em, sau khi lửa dại thiêu rụi tuyết đông, ‘Mộ’ đã thành ‘Chu’.</em></p><p>Tên truyện “Mộ Dĩ Thành Chu” là cách chơi chữ với thành ngữ “Mộc dĩ thành chu” (Ván đã đóng thuyền). Tên truyện này có nghĩa là tình cảm mến mộ đã trở thành sự thật và không thể thay đổi, “Mộ” (Mộ Dư) đã chấp nhận ở bên “Chu” (Chu Trì).</p><p>– Một nửa là gặp lại sau chia xa // Một nửa là gương vỡ lại lành // Toàn bộ là song hướng yêu thầm.</p><p>– Ảnh đế vừa điên cuồng vừa quyến rũ x Giảng viên đại học ít nói nhưng nhiều trò vui</p><p>—</p><p>Thể loại: Tình cảm đặc biệt | Con cưng của trời | Giới giải trí | Truyện ngọt | Hài hước</p><p>Khác: Ngọt, ngọt, ngọt đến chết người!</p><p>Tóm tắt một câu: Đại minh tinh vừa điên vừa quyến rũ x Đại mỹ nhân xuất khẩu thành meme</p><p>Thông điệp: Lan tỏa niềm vui, lan tỏa tình yêu</p>', '2026-03-24 21:29:22', 'tháng 12 (46).jpg'),
(72, 'Luôn Có Giáo Viên Muốn Mời Phụ Huynh', 'Cảnh Ngô', 'Đô Thị, Bách Hợp, Khác', 117, 'Hoàn thành', '<p>Tác phẩm: Luôn Có Giáo Viên Muốn Mời Phụ Huynh<br /><br />Tác giả: Cảnh Ngô<br /><br />Độ dài: 117 chương<br /><br />Nhân vật chính: Kỳ Ngôn, Lục Tri Kiều<br /><br />Thể loại: Bách hợp (Nữ x Nữ), Tình yêu chốn đô thị, Duyên phận bất ngờ, HE<br /><br />***<br /><br /><em>Tóm tắt:</em><br /><br />Tối đó Kỳ Ngôn \"hốt\" được một người phụ nữ, cùng người mây mưa một đêm, nhưng không ngờ đối phương lại là mẹ của học sinh trong lớp bản thân làm chủ giáo viên nhiệm.<br /><br />Trong cuộc họp phụ huynh, hai người bốn mắt nhìn nhau.<br /><br />\"Cô Kỳ, trùng hợp quá.\"<br /><br />\"...\"<br /><br />Một hôm nọ, Kỳ Ngôn tịch thu diện thoại của nữ sinh, sau tiết học cô gái nhỏ chạy tới văn phòng khóc lóc.<br /><br />\"Cô Kỳ, cô có thể trả điện thoại cho em không ạ?\"<br /><br />\"Gọi mẹ em tới đây.\"<br /><br />***<br /><br />Một câu tóm lược: Gọi mẹ em tới đây<br /><br />Đại ý: Độc lập tự chủ, tái sinh trong nghịch cảnh</p>', '2026-03-24 21:30:52', 'luon-co-giao-vien-muon-moi-phu-huynh.jpg'),
(73, 'Sóng Triều Dịu Dàng', 'Úc Thất Nguyệt', 'Ngôn Tình, Đô Thị, Hài Hước, Khác, Sủng', 151, 'Hoàn thành', '<p>Tác giả: Úc Thất Nguyệt </p><p>Tran / Editor: AI_Quả Tầm Xuân</p><p>Beta: AI_Mộc Lan</p><p>Thể loại: Hiện đại, Hào môn thế gia, Cưới trước yêu sau, Nghiệp giới tinh anh, Thầm mến, Sạch, Sủng Ngọt, Nhẹ nhàng, Nhất kiến chung tình, Hài hước, HE</p><p>Độ dài: 151</p><p>Giới thiệu</p><p>[Nam chính thầm yêu/ Mưu tính đã lâu, nữ chính kết hôn trước rồi mới yêu]</p><p>[Nhân vật nam dịu dàng mạnh mẽ/ ẩn nhẫn cuồng nhiệt x Mỹ nhân lạnh lùng/ Chênh lệch 4 tuổi/ Nam chính sạch]</p><p>Tóm tắt:</p><p>Năm 27 tuổi, An Chi Dư đã làm một việc điên rồ nhất trong cuộc đời mình: để trả thù bạn trai cũ ngoại tình, cô kết hôn với cấp trên của anh ta.</p><p>Cận Châu là người nắm quyền của Cận Thị, là một người đàn ông có giáo dục ăn sâu vào tận xương tủy. Anh dịu dàng, trầm tĩnh và tao nhã, nhưng cũng cực kỳ khắt khe với bản thân, không một người phụ nữ nào có thể phá vỡ ranh giới xã hội của anh.</p><p>Trước khi kết hôn, An Chi Dư đã nghe nhiều tin đồn kín đáo về anh, nhưng ai ngờ rằng ngay ngày thứ hai sau khi nhận giấy kết hôn, anh đã nắm tay cô ở cửa thang máy đông người, hôn lên trán cô, còn khoe khoang với người khác: \"Tôi đến để đưa vợ tôi đi làm.\"</p><p>\"... \" Tin đồn không đáng tin ư?</p><p>Chỉ là một cuộc hôn nhân đôi bên đều có lợi, An Chi Dư chỉ nghĩ rằng anh đang diễn vai chồng hoàn hảo, nhưng sau khi kết hôn, anh lại dịu dàng và chu đáo, đối với cô luôn rất kiên nhẫn.</p><p>Giữa đêm đông dài lạnh lẽo, anh quấn quanh người đầy hơi lạnh tìm đến thành phố nơi cô đang ở, giọng khàn khàn không giống anh thường ngày: \"Em ở ngoài một mình, anh không yên tâm.\"</p><p>Sau này cô mới biết, vé máy bay ngày hôm đó đã hết, anh lái xe chín tiếng đồng hồ chỉ vì dự báo thời tiết nói thành phố cô đang ở sẽ có mưa lớn.</p><p>*</p><p>Không ai tin được rằng, một người như Cận Châu, đứng trên đỉnh cao của kim tự tháp, lại có một mối tình thầm lặng không thể nói ra.</p><p>Quả thật, trước khi gặp An Chi Dư, anh luôn là người cực kỳ nghiêm khắc với bản thân, cho đến khi nghe tin cô sắp kết hôn, tình cảm mãnh liệt, điên cuồng và sâu sắc mà anh giấu kín bấy lâu đã không thể kiềm chế được nữa.</p><p>Thế nên, trong đám cưới của bạn trai cũ cô, anh đã bỏ qua mọi sự nhẫn nhịn và kiềm chế bấy lâu, hỏi cô: \"Em có muốn kết hôn với anh không?\"</p><p>**</p><p>Một trái tim rung động vốn dĩ chỉ là một khoảnh khắc ngắn ngủi, nhưng sự xuất hiện của cô đã làm chấn động cả thế giới của anh, với sức ảnh hưởng vượt ngoài tầm kiểm soát, khiến mỗi lần ở bên cô, sóng gió trong lòng anh đều dễ dàng nổi lên.</p>', '2026-03-24 21:31:56', '1751214129910.jpg'),
(74, 'Sự Trỗi Dậy Của Ba Tai Họa', 'Entrail_JI', 'Ngôn Tình, Dị Giới, Xuyên Không, Hài Hước, Khác, Hệ Thống', 636, 'Đang ra', '<p>[Từ Tác Giả của truyện Author\'s POV...]</p><p>Cảm xúc đối với chúng ta giống như một loại ma túy.</p><p>Càng trải nghiệm chúng, chúng ta càng trở nên nghiện ngập.</p><p>Phần khó nhất là không để chúng nuốt chửng chúng ta.</p><p>Nhưng đối với tôi, đã quá muộn rồi.</p><p>Tôi đã bị nuốt chửng hoàn toàn.</p><p>***</p><p>Tôi không hề biết gì về trò chơi này.</p><p>Tôi đáng lẽ đã phải chết.</p><p>Vậy mà, tôi lại thấy mình trong tình huống này.</p><p>Một trò chơi mà tôi chưa từng chơi. Một nhân vật mà tôi không quen thuộc, và... Một thế giới dường như muốn nuốt chửng tôi với mỗi bước tôi đi.</p><p>Chuyện quái quỷ gì đang xảy ra vậy?</p><p>...và tôi là ai?</p>', '2026-03-24 21:33:29', 'Sự Trỗi Dậy của Ba Tai Họa.jpg'),
(75, 'Du Thuyền Tận Thế', 'Lesliya', 'Hài Hước, Khác, Hệ Thống', 174, 'Hoàn thành', '<p>Tác giả: Lesliya</p><p>Tran / Editor: AI_Măng Cụt</p><p>Beta: AI_Nhất Chi Mai</p><p>Thể loại: Vô hạn lưu, Chậm nhiệt, Ấm áp, Góc nhìn nữ chính, Sinh tồn, Hệ thống, Hài hước, Viễn tưởng, HE</p><p>Độ dài: 174</p><p>Giới thiệu</p><p>Khoảnh khắc Mặt trời vừa lặn xuống, Trái đất bỗng chán ghét lũ ký sinh chỉ biết vòi vĩnh trên người mình, thế là nó quyết định tự nổ tung để được giải thoát.</p><p>Khi vô số mảnh vỡ kỳ quái lướt qua trước mắt, Mạc Tiểu Nghiêu đã thuận tay tóm được một mảnh trước khi ý thức hoàn toàn tan biến, và rồi cô xuất hiện trong một màn chơi.</p><p>Trải qua bao gian truân vất vả để đến được vạch đích, thứ xuất hiện trước mặt cô lại là một chiếc du thuyền khổng lồ.</p><p>Dưới chân cầu thang, một quý ông mặc đồng phục thuyền phó cúi người chào cô rất lịch sự: “Quý cô, lên thuyền chứ ạ?”</p><p>Mạc Tiểu Nghiêu nhìn khuôn mặt giống hệt bạch tuộc của anh ta, thản nhiên đáp: “Đương nhiên rồi.”</p><p>Đường đua trong sương mù √</p><p>Rạp xiếc của ngài A √</p><p>Thị trấn suối nước nóng quái dị √</p><p>Vở múa rối của cô Lộc √</p><p>Thực vật đại chiến thây ma √</p><p>Mùa tốt nghiệp √</p><p>Tiệc trà của Hoàng Hậu Đen √</p><p>Lễ hội hóa trang ở Vương Thành √</p>', '2026-03-24 21:34:36', '1740737803074.jpg'),
(76, 'Oanh Đào ', 'Lựu Hoa Dục Nhiên', 'Xuyên Không, Hài Hước, Cổ Đại', 11, 'Hoàn thành', '<p>Ta, một trạng nguyên thi đại học, xuyên không thành một nha hoàn thời cổ đại.</p><p>Các nha hoàn khác, ngày ngày chỉ mong trèo lên giường chủ tử; còn ta, ngày ngày chỉ mong thúc giục thiếu gia đọc sách.</p><p>Mẹ kiếp, bà đây đã \"cày\" mười tám năm, thứ không thiếu nhất chính là kinh nghiệm ôn thi!</p><p>Năm năm khoa cử, ba năm mô phỏng, thiếu gia đỗ trạng nguyên, ta công thành danh toại, rời phủ lấy chồng.</p><p>Thế nhưng, thiếu gia lại dồn ta vào góc tường, đôi mắt đỏ ngầu:</p><p>\"Hành hạ ta bao nhiêu năm, nàng còn muốn đi hành hạ người khác nữa sao?\"</p>', '2026-03-24 21:35:37', 'cats-1.jpg'),
(77, 'Liệp Hung Kí ', 'Nhạc Dũng', 'Đô Thị, Thám Hiểm, Khác', 48, 'Đang ra', 'Thể loại: Trinh thám​, Không CP, Kinh dị, OE<br><br>Dịch: Doremon98<br><br>Văn án<br><br>Trên đoàn tàu trong cơn mưa gió, một thi thể nữ giới bị để lại. Là ai, cả gan gây án giữa công chúng thế này???<br><br>Nhưng nữ thi này vốn ở thành phố A, tại sao xuất hiện ở thành phố B?<br><br>Trên đường phố vào đêm khuya, nhiều vụ án \"cắn người\" xuất hiện, nhiều người đều nói mình thấy một cái miệng rộng hoác đầy máu lao tới, sau đó bị cắn cái mũi, lỗ tai. Lẽ nào thật sự có \"cương thi ăn thịt người?<br><br>Hai lần nhìn lén bị cuốn vào ba vụ án mạng đầy bí ẩn. Bốn người ngồi xe, xuất hiện một sát thủ ưu linh.<br><br>Năm vụ án mạng, dẫn đến một âm mưu động trời. Chuyến xe lửa chạy băng băng trên đường ray trong một đêm mưa tầm tả, một thi thể nữ thần bí bị ném xuống xe, là ai đã diễn vỡ kịch giết người trước bao nhiêu đôi mắt như vậy?<br><br>Sau đó, trong khu vực thành phố liên tiếp xảy ra năm vụ án giết người, chẳng lẽ lại là \"cương thi\" âm hồn không tan?', '2026-03-24 21:37:00', 'd3c4c9b1e7da915ebccbcdb577aba390.jpg'),
(78, 'Vô Cực Ma Đạo', 'Nghịch Thương Thiên', 'Tiên Hiệp, Kiếm Hiệp, Dị Giới, Huyền Huyễn, Thám Hiểm, Đông Phương, Cổ Đại', 270, 'Đang ra', '\"Tác giả Nghịch Thương Thiên đã tạo nên một thế giới ma đạo hoàn toàn mới, nơi mà Vô Cực Ma Tông, môn phái ma đạo nhị lưu từng bị lãng quên, trở thành đối tượng quan tâm của các ma đạo khác khi Đinh Hạo gia nhập và tạo nên cơn địa chấn. <br><br>Được gọi là Vô Cực Ma Quân, Đinh Hạo được xem là người xuất sắc nhất của môn phái và tốc độ tu luyện của hắn còn nhanh hơn cả Ma đạo truyền thống. <br><br>Tuy nhiên, với tâm dục độc ác và khao khát quyền lực, Đinh Hạo đã trở thành một kẻ gian xảo vô cùng, thể hiện qua những hành động diệt môn diệt phái nhằm đạt được khát khao của mình.\"', '2026-03-24 21:38:36', 'tải xuống (5).jpg'),
(79, 'Sa Hải II', 'Sa Mãng Xà Sào', 'Linh Dị, Thám Hiểm, Đông Phương, Khác', 56, 'Đang ra', 'Tác giả: Nam Phái Tam Thúc<br><br>Thể loại: Bí ẩn, phiêu lưu mạo hiểm, kinh dị.<br><br>Editor: <em>An Nhiên</em><br><br><em>Beta:</em> Tiêu, Miêu, Phi<br><br>**************************************************<br><br>Một ngày mà, Ngô Tà trên đường trở về từ Mặc Thoát, tâm tư hắn bồng bềnh bất định, trước quá nhiều manh mối khiến tinh thần hắn mệt mỏi rã rời, là một người bố trí “mê cung”, tất cả kẻ thù và bằng hữu của hắn, đều đã nằm trong tầm kiểm soát, hắn không thể can thiệt vào bất kỳ số phận của ai, chỉ có duy nhất một chuyện mà hắn phải làm.<br><br>Một ngày mà, Bắc Kinh hoàn toàn tĩnh lặng, Tú Tú mấy người sinh tử không rõ, chấp nhận áp lực lớn nhất của bọn họ, không chỉ đối mặt với kẻ thù mà mình không biết, mà còn tự mình dựng lên một đế chế. Bọn họ cô lập bản thân, dường như đã định trước sẽ gặp phải một kết cục bi thảm.<br><br>Một ngày mà, Giải Vũ Thần biến mất liền ba ngày trong biển người mênh mông, hắn lẩn quất trong màn sương mù dày đặc, vẫn chưa đến lúc phải hoạt động, hắn dường như độc lập tách rời khỏi kế hoạch của Ngô Tà, là nhân tố bất định lớn nhất, hắn sẽ có vai trò gì trong tương lai?<br><br>Một ngày mà, Lương Loan tiếp tục mò mẫm trong trung tâm phế tích dưới lòng sa mạc, cô ấy không biết số phận nào đang chờ đợi mình, cũng chẳng hay, cô là quân cờ của Giải Vũ Thần, kết cục sẽ bị sắp đặt ở nơi nào?<br><br>Một ngày mà, Hắc Nhãn Kính quằn quại với nỗi đau trên cơ thể, Dương Hảo không rõ tung tích, Tô Vạn đối mặt với suy sụp.<br><br>Nhưng lúc này, Lê Thốc mở mắt, tất cả kế hoạch của Ngô Tà đã hằn trong não, chuyến này nhất định sẽ thành công.<br><br>Nhưng lúc này, ở sâu dưới tầng đất tối tăm, một người trẻ tuổi trầm mặc dường như cảm giác được bên ngoài sinh giới có xảy ra biến cố nghiên trời lệch đất, người trẻ tuổi ấy ít nhất cũng nhận ra một tia khác biệt…', '2026-03-24 21:43:11', 'sa-hai-ii-sa-mang-xa-sao.jpg'),
(80, 'Lệnh Truy Nã Vong Hồn', 'Cháo Trắng', 'Đô Thị, Linh Dị, Thám Hiểm, Khác', 24, 'Đang ra', 'Tác giả: Cháo Trắng<br><br>Thể loại: Đô Thị, Linh Dị, Truyện Khác, Thám Hiểm<br><br>Giới thiệu:<br><br>Một tai nạn kỳ lạ đã khiến hai anh em song sinh Tiểu Lộ và Tiểu hào phải tranh giành một bảo vật. Minh Hiểu Vũ là người được chọn làm tế vật cho anh trai là Lý Tiểu Hào đã vô tình lấy bảo vật ra khỏi tay của Lý Hào và trở thành nạn nhân cuốn theo âm mưu của hai anh em. Liệu Minh Hiểu Vũ có thể thoát ra khỏi những âm mưu này,đằng sau bảo vật ẩn chứa bí mật gì, hãy tiếp tục đọc “Lệnh truy nã vong hồn”', '2026-03-24 21:47:51', 'lenh-truy-na-vong-hon.jpg'),
(81, 'Phong Vân Hệ Thống', 'Dương Tuấn', 'Huyền Huyễn, Xuyên Không, Thám Hiểm, Khác, Hệ Thống', 63, 'Đang ra', 'Tác giả: Dương Tuấn<br><br>Thể loại: hệ thống, huyền huyễn, mạo hiểm, phiêu lưu, tình yêu, tu tiên, xuyên không...<br><br>Giới thiệu:<br><br>Truyện kể về một thanh niên tên Dương Tấn xuyên qua đại lục khác. Sống hết mười chín năm mới nhớ lại chuyện trên địa cầu. Sau đó, Tấn bắt đầu con đường trở thành cường giả, tìm lại cách trở về quê hương của mình.', '2026-03-24 21:49:21', 'phong-van-he-thong.jpg');

